window.RAFEEQ_ATTACHED_KNOWLEDGE=[{"id":"anxiety-what-is-anxiety","question":"ما هو القلق النفسي؟","alternative_questions":["يعني إيه القلق؟","إيه الفرق بين القلق والتوتر؟","أنا قلقان طول الوقت ده طبيعي؟","ليه دايماً بقلق؟","ما الفرق بين القلق الطبيعي واضطراب القلق؟"],"title":"القلق النفسي","category":"القلق","subcategory":"مفهوم القلق","keywords":["القلق","التوتر","الخوف","الاسترس","الهم","الاضطراب","انزعاج","توجس","ترقب"],"short_answer":"القلق رد فعل طبيعي للضغط، لكنه يبقى مشكلة لما يكون مستمراً ومبالغاً فيه ويعيق حياتك اليومية.","answer":"القلق النفسي حالة توتر وخوف من المستقبل بدون سبب واضح ومحدد.\n\nهو رد فعل طبيعي لجسمك أمام الخطر — يجهزك للمواجهة أو الهرب. لكن لما يبقى مستمراً ومبالغاً فيه وأنت في أمان، يبقى اضطراباً يحتاج تعاملاً.\n\nالفرق الأساسي: القلق الطبيعي مؤقت ومرتبط بموقف، أما اضطراب القلق فمستمر يأتي بدون سبب واضح ويؤثر على نومك وشغلك وعلاقاتك.","practical_steps":["تمرين التنفس 4-7-8: شهيق 4 ثوانٍ، كتم 7 ثوانٍ، زفير 8 ثوانٍ — كرره 4 مرات","اكتب مخاوفك على ورق بدل ما تدور في رأسك","حدد وقتاً يومياً (15 دقيقة) للقلق فقط، وخارجه وجّه انتباهك","قلّل الكافيين لأنه يضخّم أعراض القلق","تحرّك جسدياً 20 دقيقة مشي يفرز هرمونات مهدّئة"],"common_mistakes":["محاولة إيقاف القلق بالقوة — كلما قاومته زاد","تجنّب كل المواقف التي تقلقك — يعزّز القلق","الاعتماد على المهدّئات بدون علاج السبب","التفكير المستمر في أسوأ الاحتمالات","شرب الكافيين بكثرة ظنّاً أنه يساعد"],"when_to_seek_help":"اطلب مساعدة مختص لو القلق مستمر أكثر من 6 أسابيع، أو يُعطّل شغلك ونومك وعلاقاتك، أو يصاحبه أعراض جسدية شديدة (خفقان، اختناق)، أو لو ظهرت أفكار يأس.","related_questions":["إزاي أفرّق بين القلق الطبيعي واضطراب القلق؟","إيه أعراض نوبة القلق؟","هل القلق بيتورّث؟"],"risk_level":"low","language":"mixed","tags":["قلق","صحة نفسية","أعراض","تعامل ذاتي"]},{"id":"anxiety-physical-symptoms","question":"ما هي الأعراض الجسدية للقلق؟","alternative_questions":["القلق بيعمل إيه في الجسم؟","ليه لما بقلق بوجعني صدري؟","أعراض القلق الجسدية إيه؟","خلاصي وبتصبب عرق وقلبي بينبض بسرعة ليه؟"],"title":"الأعراض الجسدية للقلق","category":"القلق","subcategory":"الأعراض","keywords":["أعراض جسدية","خفقان","صداع","عرق","رعشة","ضيق تنفس","غثيان","توتر عضلي","جسد"],"short_answer":"القلق يظهر في الجسم عبر خفقان، تعرّق، رعشة، توتر عضلي، اضطراب هضمي وضيق تنفس — ردود فعل لجهاز العصب السمبثاوي.","answer":"لما يقلق عقلك، جسمك يدخل حالة استنفار (fight or flight) فيظهر:\n\n• قلب يخفق ويتسارع\n• تعرّق ورعشة\n• توتر في العضلات وآلام في الرقبة والكتف\n• ضيق تنفس أو إحساس بكتلة في الحلق\n• اضطراب المعدة وغثيان\n• صداع ودوار\n\nهذه الأعراض حقيقية وليست «في رأسك»، لكن سببها نفسي. لما يهدأ القلق تختفي. لو مستمرة أو شديدة، لازم تفحصها طبيبًا لاستبعاد أسباب عضوية أولًا.","practical_steps":["تعلم تمارين الاسترخاء العضلي التدريجي (شدّ ثم أرخِ كل مجموعة عضلية)","ضع يدك على بطنك وتنفّس ببطء من الحجاب الحاجز","حرّك جسمك لتفريغ طاقة الاستنفار","سجّل متى تظهر الأعراض وما يسبقها لاكتشاف المحفّزات"],"common_mistakes":["الاعتقاد أن الأعراض الجسدية تعني مرضاً عضوياً خطيراً رغم الفحوص السليمة","تجنّب النشاط خوفاً من ظهور الأعراض","إهمال الفحص الطبي لاستبعاد الأسباب العضوية"],"when_to_seek_help":"لو الأعراض الجسدية متكررة وشديدة، أو رافقها ألم صدر حاد أو ضيق تنفس مفاجئ، توجه للطوارئ أولًا. ثم اطلب مختصًا نفسيًا لو الفحوص سليمة والأعراض مستمرة.","related_questions":["إزاي أهدّي جسمي وقت القلق؟","إيه الفرق بين نوبة القلق ونوبة الهلع؟"],"risk_level":"medium","language":"mixed","tags":["أعراض جسدية","قلق","استرخاء"]},{"id":"anxiety-normal-vs-disorder","question":"كيف أفرّق بين القلق الطبيعي واضطراب القلق؟","alternative_questions":["إمتى القلق يبقى مرض؟","قلقي طبيعي ولا محتاج علاج؟","إيه الفرق بين قلق يومي واضطراب؟","أنا قلقتان على المستقبل ده مرض؟"],"title":"القلق الطبيعي مقابل اضطراب القلق","category":"القلق","subcategory":"التشخيص التفريقي","keywords":["قلق طبيعي","اضطراب قلق","تشخيص","حدود القلق","متى القلق مرض","فرق"],"short_answer":"القلق الطبيعي مرتبط بموقف وينتهي بزواله. الاضطراب مستمر ومبالغ فيه ويعيق الحياة، ويحتاج تدخلًا.","answer":"القاعدة البسيطة: اسأل نفسك ثلاثة أسئلة.\n\n1) المدة: هل القلق مستمر أكثر من أسابيع ولا يرتبط بموقف محدد؟\n2) الشدّة: هل يبالغ في حجم الخطر الفعلي؟\n3) التأثير: هل يُعطّل نومك وشغلك وعلاقاتك؟\n\nلو أجبت بـ«نعم» على الأغلب، فأنت غالبًا أمام قلق يستحق الاهتمام. التشخيص الدقيق يحدده مختص، لأن هناك أنواعًا متعددة (قلق عام، قلق اجتماعي، نوبات هلع...).","practical_steps":["سجّل في دفتر: الموقف، شدة القلق (1-10)، ومدته","لاحظ هل القلق يحدث بدون محفّز واضح","راقب تأثيره على نومك وشهيتك وأدائك","استشر مختصًا للتقييم إذا استمر أكثر من شهر"],"common_mistakes":["تصنيف نفسك بنفسك وتأكيد التشخيص دون مختص","التقليل من قلقك واعتباره «طبيعي» رغم تأثيره الواضح","الخوف من «الملصق» فتأجيل العلاج"],"when_to_seek_help":"إذا تأثر نومك أو عملك أو علاقاتك لأسابيع، أو ظهرت نوبات هلع، أو أفكار يأس، فاطلب تقييمًا متخصصًا.","related_questions":["ما هو القلق النفسي؟","أنواع اضطرابات القلق"],"risk_level":"low","language":"mixed","tags":["تشخيص","قلق","توعية"]},{"id":"anxiety-racing-thoughts","question":"كيف أوقف الأفكار المتسارعة في رأسي؟","alternative_questions":["أفكار بتجري في دماغي ومش قادر أوقفها","دماغي مش بيفصل إزاي؟","أفكار سلبية بتجي في الليل إزاي أوقفها","ليه دايماً بفكر في حاجات تقلقني"],"title":"إيقاف الأفكار المتسارعة","category":"القلق","subcategory":"الأعراض","keywords":["أفكار متسارعة","过度思考","اجترار","أفكار ليلية","دماغ مش بتفصل","قلق ليلي","توقف الفكرة"],"short_answer":"لا يمكنك إيقاف الفكرة بالقوة، لكن يمكنك تحويل الانتباه عنها وتهدئة الجهاز العصبي فتخفت تدريجيًا.","answer":"محاولة «إيقاف» فكرة تزيدها قوة (تأثير المراقبة المعاكس). الحل ليس في القمع بل في إعادة توجيه.\n\nآلية بسيطة: لاحظ الفكرة دون محاربتها («هذه فكرة قلق، ليست حقيقة») ثم وجّه انتباهك لحسّ جسدي — تنفّسك، صوت المحيط، أو حركة يدك. الفكرة تضعف لما ما تعيدها بالطاقة.\n\nمع الوقت، تمرّن دماغك على ألا يلحق كل فكرة. هذا جوهر تقنيات اليقظة الذهنية (Mindfulness).","practical_steps":["تقنية 5-4-3-2-1: سمِّ 5 أشياء تراها، 4 تسمعها، 3 تلمسها، 2 تشمّها، 1 تتذوقها","اكتب الأفكار على ورق لتفريغها من رأسك","خصص «ساعة قلق» محددة نهارًا، وخارجها أخّر التفكير","تمرّن على التنفس البطيء 6 أنفاس في الدقيقة قبل النوم","لا تحاول النوم قسرًا — قم واقرأ أو استرخِ ثم عد"],"common_mistakes":["مقاومة الفكرة وشتم النفس «تباً توقفي»","تصديق الفكرة كأنها نبوءة","تصفّح الهاتف ليلةً (الضوء الأزرق يزيد القلق)","الكافيين مساءً"],"when_to_seek_help":"لو الأفكار المتسارعة تمنع النوم لأسابيع، أو تسبب أرقًا مزمنًا، أو ترافقها نوبات هلع، استشر مختصًا.","related_questions":["إزاي أنام وأنا قلقان؟","إيه تقنية اليقظة الذهنية؟"],"risk_level":"medium","language":"mixed","tags":["أفكار","قلق ليلي","يقظة ذهنية"]},{"id":"anxiety-caffeine-and-diet","question":"هل تؤثر مرحلة القلق على النظام الغذائي؟","alternative_questions":["أكلات بتزيد القلق؟","القهوة بتزيد القلق؟","إيه اللي بيبطل آكله وأنا قلقان؟","السكر والقلق علاقة إيه؟"],"title":"الغذاء والقلق","category":"القلق","subcategory":"نمط الحياة","keywords":["غذاء","كافيين","سكر","قهوة","نظام غذائي","قلق","محفّزات","أطعمة"],"short_answer":"نعم. الكافيين والسكر المكرّر والكحول محفّزات قلق شائعة، بينما الأطعمة الغنية بأوميغا-3 والمغنيسيوم تدعم الاستقرار.","answer":"ما تأكله يؤثر في كيمياء مزاجك.\n\nيُزيد القلق: الكافيين (قهوة، مشروبات طاقة، شاي بكثرة)، السكر المكرّر (يرفع ثم يهبط سكر الدم فيجهد الأعصاب)، الكحول (ارتداد قلق بعد زوال مفعوله).\n\nيدعم الاستقرار: أوميغا-3 (سمك، جوز)، المغنيسيوم (خضروات ورقية، مكسرات)، الماء بانتظام، بروتين كافٍ لاستقرار سكر الدم.\n\nلا تظن أن الغذاء وحده يعالج القلق، لكنه جزء مهم من خطة متكاملة.","practical_steps":["قلّل الكافيين تدريجيًا لتجنّب أعراض الانسحاب","اشرب الماء أولًا صباحًا بدل القهوة الفورية","وزّع وجبات صغيرة لاستقرار سكر الدم","أضف مصدر أوميغا-3 مرتين أسبوعيًا"],"common_mistakes":["شرب قهوة أكثر لمحاربة الإرهاق الناتج أصلًا من القلق","تناول سكر سريع لتعويض الطاقة ثم انهيار أسوأ","إهمال دور الطعام في خطة العلاج"],"when_to_seek_help":"لو القلق شديد ولا يستجيب لتعديل نمط الحياة، أو ترافقه اضطرابات أكل، فاستشر مختصًا.","related_questions":["إزاي أنام وأنا قلقان؟","تمارين تنفس لتهدئة القلق"],"risk_level":"low","language":"mixed","tags":["غذاء","كافيين","نمط حياة"]},{"id":"anxiety-sleep-connection","question":"لماذا يشتد القلق ليلاً؟","alternative_questions":["ليه بالليل القلق بيزيد؟","أنا بنام قلقان وبصحى تعبان","ليه وقت النوم بتجيلي أفكار سلبية","القلق الليلي إزاي أعالجه"],"title":"القلق الليلي","category":"القلق","subcategory":"النوم","keywords":["قلق ليلي","أرق","نوم","أفكار ليلية","صعوبة النوم","استيقاظ","قلق قبل النوم"],"short_answer":"ليلاً تختفي المشتتات النهارية فتطفو الأفكار المكمّنة. كما يرتفع الكورتيزول في منتصف الليل فتزيد الاستثارة.","answer":"نهارًا عقلك مشغول بالمهام فتُؤجَّل الأفكار. ليلاً يقلّ التشتيت فتظهر كل المخاوف دفعة واحدة.\n\nعامل فيسيولوجي: الجسم يمر بدورة كورتيزول، وقد يرتفع في منتصف الليل فيوقظك مستثارًا. كما أن التعب يُضعف قدرة الدماغ على كبح الأفكار السلبية.\n\nالحل ليس في إجبار النوم، بل في إعداد جسد وعقل للراحة قبل السرير بساعة على الأقل.","practical_steps":["روتين قبل النوم: إضاءة خافتة، لا شاشات، قراءة أو ذكر","اكتب كل ما يشغلك في «دفتر التفريغ» قبل النوم","تمرين تنفس بطيء 4-7-8 لمدة 5 دقائق","إن لم تنم خلال 20 دقيقة، قم واقرأ في ضوء خافت ثم عد","ثبّت موعد نوم واستيقاظ يوميًا حتى عطلات الأسبوع"],"common_mistakes":["تصفّح الهاتف في السرير لتمرير الوقت","شرب قهوة بعد العصر","البقاء في السرير متقلبًا ساعات (يربط الدماغ السرير باليقظة)","ممارسة رياضة شديدة قرب النوم"],"when_to_seek_help":"لو الأرق مزمن (أكثر من شهر، 3 ليالٍ أسبوعيًا)، أو ترافقه أفكار يأس، فاطلب مختصًا.","related_questions":["إزاي أوقف الأفكار المتسارعة؟","أعراض القلق الجسدية"],"risk_level":"medium","language":"mixed","tags":["نوم","قلق ليلي","أرق"]},{"id":"anxiety-is-it-inherited","question":"هل القلق يُورَّث؟","alternative_questions":["القلق بيورّث؟","أبويّ قلقانين هل هكمل زيهم","هل الجينات مسؤولة عن القلق","إذا كانت أمي قلقة هل أنا كمان؟"],"title":"الوراثة والقلق","category":"القلق","subcategory":"الأسباب","keywords":["وراثة","جينات","استعداد","عوامل وراثية","تاريخ عائلي","قلق موروث"],"short_answer":"يوجد استعداد وراثي، لكن الجينات لا تُحدّد المصير. البيئة والمهارات تلعب دورًا أكبر.","answer":"القلق ليس «مرضًا وراثيًا» بالمعنى الحرفي، لكن هناك استعدادًا بيولوجيًا ينتقل.\n\nما يُورَّث فعليًا هو الحساسية العصبية، لا القلق نفسه. طفل لأبوين قلقَين قد يكتسب أيضًا أنماط التفكير بالتقليد.\n\nالأهم: الاستعداد ليس قدرًا. العلاج النفسي يعيد تشكيل استجابات الدماغ (الليونة العصبية) في أي عمر. لذا المعرفة بالتاريخ العائلي سبب للاستباق لا للاستسلام.","practical_steps":["اعرف تاريخ عائلتك لتفهم نفسك بلا ذنب","ركّز على ما يمكنك تغييره: مهاراتك وبيئتك","راقب أنماط تفكير موروثة واختبرها","استثمر في علاج مبكر قبل تفاقم الأعراض"],"common_mistakes":["القول «أنا كده من جيناتي مش هتغير»","إلقاء اللوم كله على الوراثة وإهمال التغيير","الخوف من توريث القلق للأطفال فالإفراط في الحماية"],"when_to_seek_help":"إذا كان تاريخ عائلي لاضطرابات قلق أو اكتئاب وكانت أعراضك بدأت تؤثر على حياتك، فالاستشارة المبكرة مفيدة.","related_questions":["ما هو القلق النفسي؟","إزاي أغيّر نمط تفكيري؟"],"risk_level":"low","language":"mixed","tags":["وراثة","أسباب","توعية"]},{"id":"stress-what-is-stress","question":"ما هو التوتر النفسي؟","alternative_questions":["يعني إيه استرس؟","إيه الفرق بين القلق والتوتر؟","أنا مضغوط من كل جوانب حياتي","إمتى التوتر يبقى خطر؟"],"title":"التوتر النفسي","category":"التوتر","subcategory":"مفهوم التوتر","keywords":["توتر","استرس","ضغط","إجهاد","ضغط نفسي","stress","إرهاق نفسي"],"short_answer":"التوتر رد فعل جسمك على ضغط خارجي (مهام، مواعيد، مشاكل). يصبح خطرًا إن استمر بعد زوال السبب.","answer":"التوتر استجابة طبيعية للضغط. لما تواجه موعدًا أو مشكلة، يفرز جسمك أدرينالين وكورتيزول ليرفع تركيزك.\n\nالمفيد: توتر بسيط قصير يحفّز الأداء.\n\nالضار: توتر مزمن لا يهدأ، يرفع ضغط الدم، يضعف المناعة، ويرهق المزاج.\n\nالفرق عن القلق: التوتر غالبًا له سبب خارجي واضح وينتهي بزواله، أما القلق فقد يستمر بعده أو يأتي بدون سبب محدد.","practical_steps":["صنّف ما يضغطك إلى: أتحكم فيه / لا أتحكم — ركّز على الأول","قسّم المهام الكبيرة لخطوات صغيرة","خذ استراحة 5 دقائق كل ساعة لتتنفّس وتمشِ","مارس نشاطًا بدنيًا يوميًا ولو 20 دقيقة","احمِ وقت نومك كأولوية قصوى"],"common_mistakes":["محاولة إنجاز كل شيء دفعة واحدة","إهمال النوم لإنجاز أكثر (يرفع الإجهاد)","التعبير عن التوتر بالعصبية على المقربين","الاعتماد على النيكوتين أو السكر للهدوء المؤقت"],"when_to_seek_help":"لو التوتر مزمن أكثر من شهر، يسبب أعراضًا جسدية (صداع مزمن، اضطراب هضمي، ارتفاع ضغط)، أو ينعكس على علاقاتك، فاطلب مختصًا.","related_questions":["إيه الفرق بين القلق والاكتئاب؟","إزاي أدير ضغط الشغل؟"],"risk_level":"low","language":"mixed","tags":["توتر","ضغط","إدارة"]},{"id":"stress-management-techniques","question":"ما أفضل تقنيات إدارة التوتر؟","alternative_questions":["إزاي أقلل الاسترس","تمارين للتوتر","أنا مضغوط وعايز أهدى","حاجات بتعمل ريلاكس للنفس"],"title":"تقنيات إدارة التوتر","category":"التوتر","subcategory":"التعامل","keywords":["إدارة توتر","استرخاء","تقنيات","تمارين","تهدئة","ريلاكس","تنفس"],"short_answer":"أفضل التقنيات تجمع بين الجسد (تنفس، حركة) والذهن (كتابة، إعادة تأطير) وروتين يومي ثابت.","answer":"إدارة التوتر ليست حيلة واحدة، بل منظومة:\n\n• جسدية: تنفّس بطيء من الحجاب، رياضة معتدلة، نوم كافٍ، تخفيف الكافيين.\n• ذهنية: اكتب ضغوطك لتفصلها عنك، أعِد تأطير «لا أستطيع» إلى «سأحاول خطوة»، ركّز على ما تتحكم فيه.\n• اجتماعية: تحدّث لشخص تثق به، اقبل المساعدة.\n• روحية: moments من الصمت أو الذكر أو التأمل يوميًا.\n\nالاستمرار أهم من الكمال. 10 دقائق يوميًا أفضل من ساعة أسبوعيًا.","practical_steps":["تمرين تنفس الصندوق: شهيق 4 ثوانٍ، كتم 4، زفير 4، كتم 4 — 5 دورات","استرخاء عضلي تدريجي قبل النوم","كتابة الامتنان: 3 أشياء يوميًا","مشي 20 دقيقة بدون هاتف","تحديد أولويات اليوم في 3 مهام فقط"],"common_mistakes":["تجريب تقنية مرة ثم الحكم عليها بعدم الفعالية","توقع راحة فورية (الأثر تراكمي)","استبدال النوم بممارسة الاسترخاء","ممارسة الاسترخاء أثناء قيادة تتطلب تركيزًا"],"when_to_seek_help":"لو التقنيات الذاتية لم تكفِ بعد أسابيع، أو كان التوتر شللًا لأدائك، فالعلاج النفسي (خصوصًا CBT) فعّال جدًا.","related_questions":["إيه تقنية اليقظة الذهنية؟","إزاي أنام وأنا متوتر؟"],"risk_level":"low","language":"mixed","tags":["إدارة","استرخاء","تمارين"]},{"id":"stress-work-pressure","question":"كيف أتعامل مع ضغط العمل المستمر؟","alternative_questions":["شغلي بيشفط طاقتي","أنا مكسور من الشغل","ضغط شغل بيجيبلي صداع","إزاي أوازن شغل وحياتي"],"title":"ضغط العمل","category":"التوتر","subcategory":"بيئة العمل","keywords":["ضغط عمل","إرهاق وظيفي","توتر مهني","موازنة","work-life","إجهاد وظيفي"],"short_answer":"أدر متطلباتك لا وقتك فقط: رتّب الأولويات، تعلّم قول لا، واحمِ حدودًا واضحة بين العمل والحياة.","answer":"ضغط العمل لا يُحل بالعمل أكثر، بل بحدود أوضح.\n\nابدأ بتصنيف المهام (مهم وعاجل)، ركّز على القليلة ذات الأثر، وتعلّم رفض ما لا يتسع له وقتك بذوق.\n\nافصل العمل عن البيت قدر الإمكان: لا إيميلات بعد ساعة محددة، غرفة أو ركن خاص بالعمل، طقس «إغلاق اليوم».\n\nتذكر: إنتاجية مرتفعة لسنوات تحتاج جسدًا ونفسًا تحافظ عليهما، لا استنزافًا متواصلًا.","practical_steps":["قاعدة 80/20: 20% من مهامك تعطي 80% من الأثر — ابدأ بها","حدّد ساعة «لا اجتماعات» يوميًا للتركيز","أغلق إشعارات العمل بعد وقت محدد","خذ عطلة مرضية نفسية حين تحتاجها دون ذنب","ناقش عبء العمل مع مديرك بواقعية"],"common_mistakes":["الفخر بالإرهاق كبطولة","تأجيل الإجازات لت累积 تراكم","عدم الراحة ظنًا أن التوقف ضعف","خلط وقت العمل بوقت العائلة دون حدود"],"when_to_seek_help":"لو بدأت تفقد الاهتمام بالعمل، أو ظهرت أعراض احتراق نفسي (إرهاق عميق، سخرية، أداء متراجع)، فاطلب مختصًا مبكرًا.","related_questions":["إيه الاحتراق النفسي؟","إزاي أقول لا من غير ذنب؟"],"risk_level":"medium","language":"mixed","tags":["عمل","ضغط","موازنة"]},{"id":"stress-chronic-effects","question":"ما أثر التوتر المزمن على الجسم؟","alternative_questions":["التوتر الطويل بيعمل إيه في الجسم","أنا متوتر من سنة وحاسس وجع","هل الاسترس يرفع الضغط","التوتر وأمراض القلب"],"title":"آثار التوتر المزمن","category":"التوتر","subcategory":"الأثر الجسدي","keywords":["توتر مزمن","أثر جسدي","كورتيزول","مناعة","ضغط دم","قلب","إجهاد مزمن"],"short_answer":"التوتر المزمن يرفع كورتيزول باستمرار، فيضعف المناعة، يرهق القلب، يربك الهضم، ويعكّر المزاج والنوم.","answer":"جسمك صُمم لتحمّل دفعات قصيرة من الكورتيزول، لا مستويات مرتفعة دائمة.\n\nمع التوتر المزمن يحدث:\n• قلب وأوعية: ارتفاع ضغط، تسارع، التهاب مزمن.\n• مناعة: ضعف المقاومة، بطء الشفاء.\n• هضم: اضطراب المعدة، متلازمة القولون العصبي.\n• دماغ: تراجع الذاكرة والتركيز، اضطراب نوم.\n• مزاج: قلق، اكتئاب، انفعال.\n\nالخبر الجيد: أغلب هذه الأضرار قابلة للتراجع عند خفض مستوى التوتر وعلاج أسبابه.","practical_steps":["راقب مؤشرات جسمك: نوم، هضم، ضغط","أدخل نشاطًا بدنيًا معتدلًا يوميًا لتفريغ الكورتيزول","خصّص وقتًا للهدوء اليومي (تأمل، ذكر، طبيعة)","نم 7-9 ساعات بانتظام","افحص ضغط دمك وسكر الدم دوريًا"],"common_mistakes":["تجاهل الأعراض الجسدية واعتبارها «طبيعية»","الاعتماد على المسكّنات دون معالجة التوتر","تأجيل الراحة «حتى يهدى الضغط» — لا يهدى وحده"],"when_to_seek_help":"لو ظهرت أعراض جسدية متكررة (ألم صدر، ضغط مرتفع، اضطراب نوم مزمن) فاطلب طبيبًا ومختصًا نفسيًا معًا.","related_questions":["أعراض القلق الجسدية","إيه الاحتراق النفسي؟"],"risk_level":"medium","language":"mixed","tags":["توتر مزمن","صحة جسدية","أثر"]},{"id":"stress-exam-time","question":"كيف أتعامل مع توتر فترة الامتحانات؟","alternative_questions":["أنا طالب وبتوتر في الامتحانات","خايف أفشل في الامتحان","قلق الامتحانات بيعمللي نسيان","إزاي أذاكر وأنا هادي"],"title":"توتر الامتحانات","category":"التوتر","subcategory":"الدراسة","keywords":["امتحانات","قلق اختبار","مذاكرة","طلاب","نسيان","توتر دراسي","اختبار"],"short_answer":"قلق الامتحانات طبيعي، لكنه يصير عائقًا حين يعطّل الاستذكار. النوم والتنظيم وتمارين التنفس أكثر فاعلية من السهر.","answer":"نسبة معتدلة من القلق تحفّز الأداء، لكن الزيادة تعطّل الذاكرة العاملة.\n\nأكبر فخ: السهر حتى الصباح. النوم هو ما يثبّت ما ذاكرته. حرمت منه = نسيان في اللحظة.\n\nثاني فخ: المذاكرة العشوائية. خطة واضحة على ورق تقلّل نصف القلق.\n\nثالث فخ: الحديث السلبي «هفشل». هذا يفعّل الخوف ويعطّل التذكّر. استبدله بـ«ذاكرتُ، سأقدّم ما أستطيع».","practical_steps":["خطة مذاكرة: قسّم المنهج لأجزاء يومية واقعية","تقنية بومودورو: 25 دقيقة تركيز + 5 استراحة","تمرين تنفس 4-7-8 قبل النوم وقبل الامتحان","نم 7-8 ساعات — الذكريات تُثبَّت في النوم","يوم الامتحان: لا تراجع جديد، ثق بما ذاكرت"],"common_mistakes":["السهر ليلة الامتحان (أسوأ ما تفعله لذاكرتك)","مقارنة نفسك بزملاء أكثر تجهيزًا","شرب مشروبات طاقة بكثرة فترتجف وتتوتر","التركيز على ما فات من امتحانات سابقة"],"when_to_seek_help":"لو قلق الامتحانات يسبب نسيانًا كاملًا، أرقًا مزمنًا، أو ذعرًا فعليًا داخل لجنة الامتحان، فاستشر مختصًا.","related_questions":["ضغط الدراسة إزاي أتعامل معاه","إزاي أوقف الأفكار المتسارعة"],"risk_level":"medium","language":"mixed","tags":["امتحانات","طلاب","قلق اختبار"]},{"id":"depression-what-is-depression","question":"ما هو الاكتئاب النفسي؟","alternative_questions":["يعني إيه اكتئاب","إيه الفرق بين الحزن والاكتئاب","حاسس كله ملوش طعم ده اكتئاب","أنا مش حاسس بأي حاجة ده مرض"],"title":"الاكتئاب النفسي","category":"الاكتئاب","subcategory":"مفهوم الاكتئاب","keywords":["اكتئاب","حزن مستمر","فقد اهتمام","كآبة","depression","مزاج منخفض","انطفاء"],"short_answer":"الاكتئاب ليس مجرد حزن، بل حالة مزاجية مستمرة (أسبوعان+) يفقد فيها الاهتمام والطاقة والمتعة، وتؤثر على الحياة.","answer":"الاكتئاب اضطراب مزاجي يتميز بأعراض تستمر أسبوعين على الأقل:\n\n• مزاج منخفض معظم اليوم\n• فقدان الاهتمام بما كان ممتعًا\n• إرهاق ونقص طاقة\n• اضطراب نوم وشهية\n• شعور بقلة القيمة أو ذنب\n• صعوبة تركيز\n• أفكار موت أو يأس\n\nالفرق عن الحزن: الحزن رد فعل طبيعي على فقد، يخفّ بمرور الوقت. الاكتئاب يستمر ويشلّ الحياة ويؤثر على الجسد والتفكير. التشخيص يحدده مختص.","practical_steps":["لا تنتظر «الدافع» — افعل مهام صغيرة أولًا فتأتي الرغبة بعدها","حافظ على روتين نوم وأكل ثابت مهما قلّ","تحرّك 15 دقيقة يوميًا ولو داخل البيت","أخبر شخصًا تثق به بما تشعر به","سجّل يوميات مزاج لاكتشاف الأنماط"],"common_mistakes":["القول «تعلّم تتجاوز» — الاكتئاب ليس اختيارًا","عزل النفس ورفض التواصل","محاولة التعافي بالعمل الزائد أو الإهمال","تأجيل العلاج خوفًا من «الملصق»"],"when_to_seek_help":"اطلب مساعدة فورًا لو ظهرت أفكار عن الموت أو إيذاء النفس. وكذلك لو استمرت الأعراض أسبوعين+, أو أثّرت على عملك وعلاقاتك. الاكتئاب قابل للعلاج.","related_questions":["إيه الفرق بين الحزن والاكتئاب","هل الاكتئاب ضعف إيمان","إزاي أعرف إني محتاج علاج نفسي"],"risk_level":"high","language":"mixed","tags":["اكتئاب","مفهوم","أعراض"]},{"id":"depression-sadness-difference","question":"ما الفرق بين الحزن الطبيعي والاكتئاب؟","alternative_questions":["أنا حزين ولا مكتئب","إمتى الحزن يبقى اكتئاب","فرق الحزن والاكتئاب","حزني مستمر هل ده اكتئاب"],"title":"الحزن مقابل الاكتئاب","category":"الاكتئاب","subcategory":"التشخيص التفريقي","keywords":["حزن","اكتئاب","فرق","تشخيص","حزن طبيعي","فقد","رد فعل"],"short_answer":"الحزن رد فعل طبيعي يخفّ بمرور الوقت ويأتي في موجات. الاكتئاب ثابت ثقل يومي، يفقد المتعة ويشلّ الحياة.","answer":"الفرق ليس في الكمية بل في النوع والمدة.\n\nالحزن الطبيعي:\n• رد فعل على فقد أو صدمة\n• يأتي في موجات، بينها لحظات طبيعية\n• تحتفظ بالقدرة على الفرح لأشياء أخرى\n• يخفّ تدريجيًا\n\nالاكتئاب:\n• ثقل مستمر معظم اليوم يوميًا\n• فقدان المتعة من كل شيء\n• شعور بقلة القيمة أو ذنب مفرط\n• يستمر أسبوعين+\n• أعراض جسدية (نوم، شهية، طاقة)\n\nالحد الفاصل دقيق، والتشخيص النهائي لمختص. لا تحكم على نفسك وحدك.","practical_steps":["راقب المزاج أسبوعين: هل موجات أم ثبات؟","سجّل هل مازلت تستمتع بأي شيء؟","لاحظ هل يوجد ذنب مفرط أو قلة قيمة","استشر مختصًا عند الشك — التقييم آمن"],"common_mistakes":["تصنيف كل حزن بأنه اكتئاب","تجاهل اكتئاب حقيقي واعتباره «حزن عابر»","الخوف من السؤال خشية التشخيص"],"when_to_seek_help":"لو الحزن مستمر أكثر من أسبوعين، أو فقدت المتعة من كل شيء، أو ظهرت أفكار يأس، فاطلب مختصًا فورًا.","related_questions":["ما هو الاكتئاب النفسي","الحزن بعد الفقد إزاي أتعامل معاه"],"risk_level":"medium","language":"mixed","tags":["حزن","اكتئاب","تشخيص"]},{"id":"depression-symptoms-checklist","question":"ما هي علامات الاكتئاب التي يجب الانتباه لها؟","alternative_questions":["أعراض الاكتئاب إيه","إزاي أعرف إني مكتئب","علامات تحذيرية للاكتئاب","أنا عندي كم من الأعراض ده اكتئاب"],"title":"علامات الاكتئاب","category":"الاكتئاب","subcategory":"الأعراض","keywords":["أعراض اكتئاب","علامات","كشف","مؤشرات","تشخيص اكتئاب","أعراض"],"short_answer":"أبرز العلامات: حزن مستمر، فقدان متعة، إرهاق، اضطراب نوم/شهية، صعوبة تركيز، شعور بقلة قيمة، وأفكار يأس — لمدة أسبوعين+.","answer":"اتفق المعالجون على مجموعة أعراض. للاكتئاب حاجة لخمسة على الأقل منها لمدة أسبوعين:\n\n1) مزاج منخفض معظم اليوم\n2) فقدان الاهتمام والمتعة\n3) تغيّر وزن/شهية (زيادة أو نقص)\n4) أرق أو نوم مفرط\n5) إرهاق أو فقدان طاقة\n6) شعور بقلة قيمة أو ذنب مفرط\n7) صعوبة تركيز أو قرار\n8) أفكار متكررة عن الموت\n\nهذه قائمة إرشادية لا تشخيصية. التقييم النهائي لمختص، ويستبعد أسبابًا جسدية (غدة، فيتامينات).","practical_steps":["سجّل أعراضك أسبوعًا بتواريخها","لاحظ هل تؤثر على عملك وعلاقاتك","اطلب موعد تقييم من مختص نفسي","أخبر طبيب العائلة لاستبعاد أسباب جسدية"],"common_mistakes":["تشخيص نفسك من قائمة إنترنت وحدك","الانتظار حتى «تشتد» قبل طلب المساعدة","إخفاء الأعراض خوفًا من حكم الآخرين"],"when_to_seek_help":"فورًا لو ظهرت أي فكرة عن إيذاء النفس أو الموت. وإلا لو استمرت الأعراض أسبوعين+, فاطلب تقييمًا.","related_questions":["ما هو الاكتئاب النفسي","إمتى الحزن يبقى اكتئاب"],"risk_level":"high","language":"mixed","tags":["أعراض","اكتئاب","تشخيص"]},{"id":"depression-not-weakness","question":"هل الاكتئاب دليل على ضعف الشخصية؟","alternative_questions":["الاكتئاب ضعف شخصية","ليه الناس بتحكم عليا إني ضعيف","هل الاكتئاب عيب","أنا مش ضعيف بس حاسس محتاج مساعدة"],"title":"الاكتئاب ليس ضعفًا","category":"الاكتئاب","subcategory":"وصمة","keywords":["ضعف","وصمة","عار","اكتئاب ضعف","خرافات","وصمة نفسية","حكم"],"short_answer":"لا. الاكتئاب اضطراب له أساس بيولوجي ونفسي واجتماعي. الشخصية القوية قد تصاب به، والطلب للعلاج قوة لا ضعف.","answer":"الاكتئاب ليس خيارًا ولا دليل ضعف. هو اضطراب يتداخل فيه:\n• عوامل بيولوجية (كيمياء الدماغ، الوراثة)\n• عوامل نفسية (أنماط تفكير، صدمات)\n• عوامل اجتماعية (ضغوط، فقد، عزلة)\n\nأشخاص أقوياء أنجزوا كثيرًا أصيبوا بالاكتئاب. العبء الحقيقي هو الوصمة التي تمنع الناس من طلب المساعدة.\n\nطلب العلاج قرار شجاع. كما تذهب لطبيب عند كسر، تذهب لمختص عند «كسر نفسي».","practical_steps":["تحدّث بصدق مع شخص تثق به أولًا","ذكّر نفسك أن المرض ليس هويتك","اطلب مختصًا دون ذنب","شارك تجربتك حين تشعر بالأمان لتكسر الوصمة"],"common_mistakes":["إخفاء الأعراض خوفًا من الحكم","مقارنة نفسك بآخرين «أقوى»","إجبار النفس على الظهور «بخير» فتتأخر المعالجة"],"when_to_seek_help":"لو شعرت بالأعراض أكثر من أسبوعين، أو أن الوصمة تمنعك من العلاج، فتحدّث لمختص — كل ما بُكر بالعلاج كان أسرع التعافي.","related_questions":["هل الاكتئاب ضعف إيمان","إزاي أعرف إني محتاج علاج نفسي"],"risk_level":"medium","language":"mixed","tags":["وصمة","اكتئاب","توعية"]},{"id":"depression-treatment-overview","question":"ما هي طرق علاج الاكتئاب؟","alternative_questions":["إزاي يعالجوا الاكتئاب","العلاج النفسي بيفيد في الاكتئاب","هل لازم دوا للاكتئاب","علاج الاكتئاب إيه"],"title":"علاج الاكتئاب","category":"الاكتئاب","subcategory":"العلاج","keywords":["علاج اكتئاب","علاج نفسي","دواء","CBT","علاج معرفي سلوكي","مضادات اكتئاب","علاج"],"short_answer":"العلاج الرئيسي نوعان: العلاج النفسي (خصوصًا CBT) والأدوية. كثيرًا ما يجمعهما المختص حسب شدة الحالة.","answer":"لا يوجد حل واحد. أنواع العلاج:\n\n• العلاج النفسي: أبرزه العلاج المعرفي السلوكي (CBT) — يساعدك على إعادة بناء أفكار وسلوكيات تزيد الاكتئاب. فعّال في الحالات الخفيفة والمتوسطة.\n• الأدوية: مضادات الاكتئاب يصفها طبيب نفسي، تستغرق 2-6 أسابيع لإظهار الأثر. مفيدة في الحالات المتوسطة والشديدة.\n• تغييرات نمط حياة: نوم، حركة، غذاء، تواصل.\n• العلاج بالصدمات الكهربائية (ECT) في حالات مقاومة وشديدة بإشراف دقيق.\n\nالعلاج فردي. ما ينفع واحدًا قد لا ينفع آخر. الطبيب والمختص يقرران الخطة المناسبة.","practical_steps":["اطلب تقييمًا من مختص نفسي أو طبيب نفسي","ناقش الخيارات العلاجية بصراحة معه","التزم بالخطة — العلاج النفسي يحتاج جلسات منتظمة","إن وُصفت أدوية، لا توقفها فجأة حتى لو تحسنت","أبلغ المختص بأي أعراض جانبية"],"common_mistakes":["توقيف الدواء عند أول تحسّن (يخطر انتكاس)","رفض العلاج النفسي ظنًا أن الدواء كافٍ","تأجيل العلاج انتظارًا لتحسّن تلقائي","اللجوء لمهدّئات أو أعشاب دون إشراف"],"when_to_seek_help":"أي درجة اكتئاب تستحق تقييمًا. العاجل: أفكار موت أو إيذاء — توجه للطوارئ أو خط مساعدة فورًا.","related_questions":["إيه العلاج المعرفي السلوكي","هل الدوا بيخلي شخص مدمن"],"risk_level":"high","language":"mixed","tags":["علاج","اكتئاب","CBT"]},{"id":"depression-helping-loved-one","question":"كيف أساعد قريبًا مكتئبًا؟","alternative_questions":["صاحبي مكتئب إزاي أساعده","أخويا حاسس بطلة حياة إيه أقول","واحد قريب لي مكتئب ورفض علاج","إزاي أقف جنب شخص مكتئب"],"title":"مساعدة قريب مكتئب","category":"الاكتئاب","subcategory":"الدعم","keywords":["مساعدة","دعم","قريب مكتئب","رعاية","مرافق","صديق مكتئب","عائلة"],"short_answer":"كن حاضرًا بلا حكم، استمع أكثر مما تنصح، شجّعه على العلاج، وامنع العزلة. لا تقاومه بعنف «إياك تفكّر كده».","answer":"الاكتئاب يعزل الشخص ويجعله يصدّ الناس. ما تحتاجه قريبك:\n\n• حضور لا حكم: «أنا هنا، مش لازم تتكلم» أحيانًا يكفي.\n• استماع دون إصلاح: لا تقفز لحلول، بل اسمع.\n• دعم للعلاج: ساعده على الموعد، اذهب معه إن قبل.\n• مهام صغيرة: «تعال نمشي» أفضل من «تحسّن».\n• رعاية نفسك أيضًا: الدعم طويل، لا تُحرق.\n\nتجنّب: «فكّر بإيجابية»، «غيرتك ناقصة»، «انظر لمن هو أسوأ». هذه تزيد الذنب لا تحسّن.","practical_steps":["تواصل منتظم بلا ضغط: رسالة قصيرة يوميًا","اقترح أنشطة بسيطة معًا (مشي، شاي)","ساعده عمليًا: طبخة، ترتيب، موعد","شجّعه بلطف على طلب مختص","كن صبورًا — التعافي بطيء وموجات"],"common_mistakes":["قول «تقوّى» أو «عندك كل خير»","الصراخ أو التهديد لإجباره على التحسّن","إهمال نفسك من فرط الاهتمام به","إخفاء المرض عن مختص خوفًا من «الفضيحة»"],"when_to_seek_help":"فورًا لو ذكر قريبك فكرة إيذاء أو موت — لا تتركه وحده وتواصل مع طوارئ أو خط مساعدة. وكذلك إن رفض العلاج وتفاقمت أعراضه.","related_questions":["علامات خطر الانتحار","إزاي أقنع حد يروح لعلاج نفسي"],"risk_level":"high","language":"mixed","tags":["دعم","عائلة","اكتئاب"]},{"id":"depression-suicide-warning","question":"ما علامات خطر الانتحار التي يجب الانتباه لها؟","alternative_questions":["إزاي أعرف حد بيفكر يأذي نفسه","صاحبي بيقول مش عايز أعيش","علامات خطر الانتحار","أنا بفكر في الموت كتير"],"title":"علامات خطر الانتحار","category":"الاكتئاب","subcategory":"أزمة","keywords":["انتحار","خطر","إيذاء نفس","أفكار موت","إنذار","أزمة","وقاية","suicide"],"short_answer":"علامات تستدعي تدخلًا فوريًا: التحدث عن الموت، ترتيب أمور، وداع، عزلة مفاجئة، سلوك خطير، تحسّن مفاجئ بعد كساد. اتصل بطوارئ أو خط مساعدة فورًا.","answer":"هذه علامات إنذار، لا تتجاهلها أبدًا:\n\n• الحديث عن الموت أو «الراحة» أو «الاختفاء»\n• ترتيب الأغراض، كتابة وصية، وداع مفاجئ\n• عزلة وانسحاب من العائلة والأصدقاء\n• سلوك متهوّر (قيادة سريعة، إدمان)\n• إعطاء أشياء ثمينة\n• تحسّن مفاجئ بعد فترة كساد (قد يعني اتخاذ قرار)\n• البحث عن وسائل\n\nالانتحار ليس رغبة في الموت بل رغبة في إنهاء ألم لا يُطاق. التدخل المبكر ينقذ. لا تترك الشخص وحده. أزل الوسائل. اطلب مساعدة فورًا.","practical_steps":["اسأل مباشرة بلطف: «هل تفكر في إيذاء نفسك؟» — السؤال لا يزيد الخطر","ابقَ معه، لا تتركه وحده","أزل وسائل الخطر إن أمكن","اتصل بطوارئ أو خط مساعدة نفسية فورًا","خذه لمستشفى أو مختص فورًا"],"common_mistakes":["الاعتقاد أن السؤال عن الانتحار يزرع الفكرة — غير صحيح","وعد الشخص بكتمان السر — الأمان أهم من السر","تجاهل التلميحات كأنها «دراما»","تركه وحده «للهدوء»"],"when_to_seek_help":"في أي شك جدّي، اتصل بطوارئ أو خط مساعدة على الفور. هذه حالة طارئة لا تنتظر موعدًا.","related_questions":["إزاي أساعد قريب مكتئب","أرقام خطوط المساعدة النفسية"],"risk_level":"crisis","language":"mixed","tags":["أزمة","انتحار","وقاية"]},{"id":"sadness-what-is-normal","question":"متى يكون الحزن طبيعيًا؟","alternative_questions":["حزني طبيعي ولا محتاج علاج","إمتى الحزن يبقى مشكلة","أنا حزين من فترة طويلة","الزعل الطبيعي قد إيه"],"title":"الحزن الطبيعي","category":"الحزن","subcategory":"مفهوم الحزن","keywords":["حزن طبيعي","زعل","مشاعر","رد فعل","موجات","طبيعي","خبرة مؤلمة"],"short_answer":"الحزن رد فعل طبيعي على ألم أو فقد. طبيعي ما دام يأتي في موجات، يخفّ بمرور الوقت، ولا يشلّ حياتك تمامًا.","answer":"الحزن ليس عدوًا. هو رد فعل صحي لنفس سليمة على فقد أو خيبة أو ألم.\n\nالحزن الطبيعي:\n• يأتي في موجات — لحظات حزن بينها لحظات طبيعية\n• يخفّ تدريجيًا مع الأيام\n• يحترم قدرتك على الاستمرار في الحياة\n• يسمح بالفرح أحيانًا\n• يتعامل مع حدث محدد\n\nالمشكلة تبدأ حين يصير ثقلًا يوميًا لا يخفّ، أو يفقد المتعة من كل شيء، أو يعطّل العمل والعلاقات. هنا قد يكون حزنًا تحوّل إلى اكتئاب ويحتاج مختصًا.","practical_steps":["اسمح لنفسك بالحزن دون مقاومة","عبّر: كتابة، حديث، فن، بكاء","حافظ على روتين أساسي (نوم، أكل) مهما قلّ","لا تعزل نفسك تمامًا — تواصل بقدر تحمل","ضع حدًا زمنيًا للتفكير («ساعة حزن» يوميًا)"],"common_mistakes":["كبت الحزن ظنًا أنه ضعف","تخدير الألم بمشتتات أو إدمان","عزل النفس فترة طويلة","مقارنة حزنك بحزن الآخرين"],"when_to_seek_help":"لو الحزن مستمر أكثر من أسابيع قليلة دون أي خفوت، أو شلّ حياتك، أو ظهرت أفكار يأس، فاطلب مختصًا.","related_questions":["إيه الفرق بين الحزن والاكتئاب","الحزن بعد الفقد إزاي أتعامل معاه"],"risk_level":"low","language":"mixed","tags":["حزن","مشاعر","طبيعي"]},{"id":"sadness-crying-is-ok","question":"هل البكاء علامة ضعف؟","alternative_questions":["البكاء ضعف","أنا برجع بسرعة إيه المشكلة","ليه ممنوع أعبّر عن حزني","البكاء بيفيد إيه"],"title":"البكاء ليس ضعفًا","category":"الحزن","subcategory":"تعبير","keywords":["بكاء","ضعف","تعبير","دموع","تفريغ","مشاعر","تطهير نفسي"],"short_answer":"لا. البكاء آلية طبيعية لتفريغ التوتر، يفرز الدماغ هرمونات مهدّئة بعده. منعه يزيد الألم داخليًا.","answer":"البكاء ليس ضعفًا بل آلية فسيولوجية للتنظيم.\n\nعند البكاء:\n• يفرز الدماغ الأوكسيتوسين والإندورفين (مسكّنات طبيعية)\n• ينخفض الكورتيزول (هرمون التوتر)\n• تُطلق مشاعر مكبوتة قبل أن تتراكم\n\nمنع البكاء «لأني قوي» يجعل الألم يختمر داخل الجسد كتوتر عضلي أو اكتئاب لاحق.\n\nالفارق بين القوي والضعيف ليس في البكاء، بل في التعافي بعد البكاء والعودة للحياة. حتى أقوى الشخصيات بكت.","practical_steps":["اسمح لنفسك بمكان آمن للبكاء","لا تستحِ من دموعك أمام من تثق به","بعد البكاء اشرب ماءً واسترح","لا تحكم على نفسك بأنها «انهارت»"],"common_mistakes":["كبت البكاء خوفًا من الحكم","الاستخفاف ببكاء الآخرين","ربط البكاء بالرجولة أو «الصلابة»"],"when_to_seek_help":"لو البكاء لا يتوقف لساعات يوميًا، أو يصاحبه يأس شديد أو أفكار موت، فاطلب مختصًا.","related_questions":["متى يكون الحزن طبيعيًا","إزاي أعبّر عن مشاعري"],"risk_level":"low","language":"mixed","tags":["بكاء","تعبير","مشاعر"]},{"id":"loneliness-alone-vs-lonely","question":"ما الفرق بين الوحدة والعزلة؟","alternative_questions":["وحدي لكن مش حاسس بوحدة","أنا وسط ناس وحاسس بوحدة","فرق الوحدة والعزلة","ليه حاسس وحيد رغم إني متجوز"],"title":"الوحدة والعزلة","category":"الوحدة","subcategory":"مفهوم الوحدة","keywords":["وحدة","عزلة","وحيد","عزلة اجتماعية","شعور بالوحدة","تواصل"],"short_answer":"العزلة أن تكون وحيدًا جسديًا (وقد تكون مفيدة). الوحدة شعور بأنك غير متصل عاطفيًا حتى وسط الناس.","answer":"تمييز مهم:\n\nالعزلة (Solitude): أن تكون وحيدًا جسديًا. قد تكون اختيارية ومفيدة للراحة والإبداع والتأمل.\n\nالوحدة (Loneliness): شعور بأنك غير متصل عاطفيًا. يمكنك أن تشعر بها وسط عائلة أو في حفلة، وأن لا تشعر بها وأنت وحيد.\n\nالوحدة المؤذية ليست في عدد الناس حولك، بل في جودة التواصل. شخصان متفاهمان يكفيان. ألف شخص بلا عمق لا يطفئ الوحدة.","practical_steps":["قيّم: هل مشكلتك قلة الناس أم ضعف العمق؟","استثمر في علاقة واحدة أو اثنتين بعمق بدل عشرات سطحيًا","ميّز بين وقت العزلة المريح (صحة) والوحدة المؤذية","انضم لمجموعة ذات اهتمام مشترك لا لمجرد ملء الفراغ"],"common_mistakes":["محاولة ملء الوحدة بعلاقات سطحية كثيرة","الخلط بين الرغبة في العزلة والوحدة","التواصل الإلكتروني الزائد ظنًا أنه بديل للعمق"],"when_to_seek_help":"لو الوحدة مزمنة، تسبب حزنًا أو قلقًا، أو تدفعك لعلاقات مؤذية لتعبئتها، فاطلب مختصًا.","related_questions":["إزاي أوصل لحد بصدق","ليه بحس بوحدة رغم إني متجوز"],"risk_level":"low","language":"mixed","tags":["وحدة","عزلة","تواصل"]},{"id":"loneliness-after-moving","question":"كيف أتعامل مع الوحدة بعد الانتقال لمدينة جديدة؟","alternative_questions":["اتنقلت مدينة جديدة وحاسس وحيد","ما بعرفش حد في المدينة الجديدة","إزاي أكون صداقات في مكان جديد","الاغتراب صعب إزاي أتعامل"],"title":"الوحدة بعد الانتقال","category":"الوحدة","subcategory":"الانتقال","keywords":["انتقال","مدينة جديدة","اغتراب","هجرة","صداقات جديدة","تكيف","بداية جديدة"],"short_answer":"الوحدة بعد الانتقال طبيعية وتحتاج وقتًا. ابنِ روتينًا، انضم لمجموعات ذات اهتمام، وكن صبورًا — الصداقات تحتاج أشهرًا.","answer":"الانتقال لمدينة جديدة فقد لشبكة الأمان القديمة. الشعور بالوحدة في الأشهر الأولى طبيعي تمامًا.\n\nما يسرّع التكيف:\n• بناء روتين يومي يمنح إحساس الاستقرار\n• الانضمام لأنشطة منتظمة (نادٍ، مسجد، تطوع، دورة)\n• المبادرة لا انتظار أن يدعوك أحد\n• الحفاظ على تواصل مع الأهل (جسر أمان)\n• تقبّل أن الصداقات العميقة تحتاج أشهرًا\n\nالخطأ الشائع: العزلة في البيت بانتظار أن «يحدث شيء». الأشياء تصنعها أنت.","practical_steps":["اخرج يوميًا ولو لمشية قصيرة لتعتاد المكان","انضم لنشاط منتظم أسبوعي (رياضة، دورة، تطوع)","ابدأ محادثات صغيرة (جار، بائع، زميل)","ادعُ شخصًا واحدًا لقهوة بعد عدة لقاءات","حافظ على تواصل مع أهلك وأصدقائك القدامى"],"common_mistakes":["مقارنة المدينة الجديدة بالقديمة باستمرار","العزلة بانتظار الصداقات تأتي وحدها","الاعتماد الكلي على الإنترنت للتواصل","اليأس بعد أسابيع قليلة"],"when_to_seek_help":"لو بعد أشهر تشعر بحزن عميق، أو القلق يعطّل تكيفك، أو ظهرت أفكار يأس، فاطلب مختصًا.","related_questions":["إزاي أكون صداقات بصدق","الوحدة والعزلة إيه الفرق"],"risk_level":"low","language":"mixed","tags":["انتقال","اغتراب","صداقات"]},{"id":"loneliness-in-marriage","question":"لماذا أشعر بالوحدة رغم أنني متزوج؟","alternative_questions":["متجوز وحاسس وحيد","جوزي جنبي بس حاسس بوحدة","الزواج ملوش عمق إيه الحل","ليه قرب جسدي وبعد نفسي"],"title":"الوحدة داخل الزواج","category":"الوحدة","subcategory":"العلاقات","keywords":["وحدة في الزواج","بعد نفسي","زواج","اتصال عاطفي","قرب","علاقة زوجية"],"short_answer":"الوحدة وسط زواج تعني غياب الاتصال العاطفي لا الجسدي. القرب الجسدي دون نفسي يزيد الألم. الحل في الحوار العميق لا الانفصال فورًا.","answer":"أقسى وحدة تلك التي تشعر بها وأنت تنام بجانب شريك. سببها غياب العمق العاطفي:\n\n• حوار سطحي (مواضيع المنزل والأطفال فقط)\n• انشغال كل طرف بعالمه\n• خلافات غير محلولة تراكمت\n• اختلاف لغات الحب\n• تراجع وقت ثنائي خالص\n\nهذا لا يعني فشل الزواج بل يعني احتياجه صيانة. كثيرًا ما يُصلح بجلسات حوار صادقة أو استشارة زوجية. الأطفال والعمل لا يجب أن يلغيا «نحن».","practical_steps":["خصص وقتًا أسبوعيًا خالصًا لكما بلا أطفال وشاشات","تعلّم لغة حب شريكك (كلمات، وقت، هدية، خدمة، لمس)","عبّر عن احتياجك بـ«أنا» لا اتهام: «أشعر بالبعد» لا «أنت لا تهتم»","ناقشا الخلافات القديمة المعلّقة بواسطة مستشار إن لزم","أعِد بناء عادات صغيرة: شاي مساءً، مشية، حديث قبل النوم"],"common_mistakes":["تأجيل الحوار انتظارًا لتحسّن تلقائي","اتهام الشريك بدل التعبير عن الحاجة","الخلط بين القرب الجسدي والاتصال العاطفي","افتراض أن الزواج القديم لا يحتاج جهدًا"],"when_to_seek_help":"لو الحوار بينكما متوقف أو يتحول لخصام، أو شعرت أن العلاقة باردة لشهور، فاستشارة زوجية متخصصة فعّالة جدًا.","related_questions":["إزاي أحسّن التواصل مع شريكي","لغات الحب إيه"],"risk_level":"medium","language":"mixed","tags":["زواج","وحدة","اتصال عاطفي"]},{"id":"fear-what-is-fear","question":"ما هو الخوف النفسي؟","alternative_questions":["يعني إيه الخوف","إيه الفرق بين الخوف والقلق","أنا بخاف من كل حاجة","الخوف الطبيعي إمتى"],"title":"الخوف النفسي","category":"الخوف","subcategory":"مفهوم الخوف","keywords":["خوف","فزع","رعب","هلع","حذر","رد فعل","تهديد","خطر"],"short_answer":"الخوف رد فعل فوري على خطر محدد وحاضر. يختلف عن القلق في أنه له مصدر واضح وزمن قصير.","answer":"الخوف استجابة فورية لتهديد محدد وحاضر (كلب، حادث، تهديد). يفعّل جسمك في ثوانٍ: قلب، عضلات، حواس.\n\nالفرق عن القلق:\n• الخوف: سبب حاضر وواضح، يخفّ بزوال التهديد.\n• القلق: توقّع خطر مستقبلي غامض، أطول أمدًا.\n\nالخوف مفيد — يحميك. لكنه يصبح مشكلة حين يستمر بعد زوال الخطر، أو يستثيره ما لا يستحق، أو يجعلك تتجنب حياتك.","practical_steps":["تعرّف خوفك: ما المصدر الحقيقي؟","ميّز: خوف يحمي أم خوف يعطّل؟","تعامل مع الخطر الفعلي، ثم هدّئ جسدك","لا تتجنّب كل ما يخيفك — التعرّض المتدرّج يقوّي"],"common_mistakes":["الخلط بين الخوف الطبيعي والمرضي","تجنّب كل ما يثير خوفًا (يعزّز الخوف)","إخفاء الخوف واعتباره عيبًا"],"when_to_seek_help":"لو الخوف يعطّل حياتك اليومية، أو يستثيره ما لا يستحق، أو يصاحبه نوبات هلع، فاطلب مختصًا.","related_questions":["إيه الفرق بين الخوف والرهاب","إيه أعراض نوبة الهلع"],"risk_level":"low","language":"mixed","tags":["خوف","مفهوم","رد فعل"]},{"id":"fear-of-future","question":"كيف أتعامل مع الخوف من المستقبل؟","alternative_questions":["خايف من بكرة","أنا خايف على مستقبلي","مش عارف إيه هيحصل إيه أعمل","الخوف من المجهول بيعطّلني"],"title":"الخوف من المستقبل","category":"الخوف","subcategory":"المستقبل","keywords":["خوف المستقبل","مجهول","ترقب","قلق الغد","حيرة","عدم يقين","خوف من الغد"],"short_answer":"الخوف من المجهول طبيعي. الحل ليس في التحكم بالمستقبل (مستحيل) بل في بناء مهاراتك اليوم والتوكل مع الأخذ بالأسباب.","answer":"المستقبل مجهول بالتعريف، ومحاولة التحكم به مصدر قلق دائم.\n\nبدلًا من محاولة التنبؤ، ركّز على:\n• ما أتحكم فيه اليوم (مهاراتي، علاقاتي، قراراتي)\n• بناء مرونة نفسية لأتعامل مع أي سيناريو\n• الأخذ بالأسباب ثم القبول بما لا أملك\n• تقسيم المخاوف الكبيرة لأسئلة أصغر قابلة للعمل\n\nالخوف من المستقبل يُختصر حين تبني ثقة في قدرتك على التعامل، لا في معرفة ما سيحدث.","practical_steps":["اكتب مخاوفك، صنّفها: ما أتحكم فيه / لا أتحكم","اصنع خطة لما يمكنك، اقبل ما لا يمكنك","طوّر مهارة أو عادة جديدة أسبوعيًا (ثقة بالنفس)","قلّل استهلاك الأخبار السلبية المفرطة","مارس اليقظة الذهنية: عِش اللحظة الحالية"],"common_mistakes":["محاولة التنبؤ بكل سيناريو (يستنزف الطاقة)","التجمّد انتظارًا لليقين","الخلط بين الحذر المعقول والخوف المرضي"],"when_to_seek_help":"لو الخوف من المستقبل يعطّل قراراتك أو نومك لأسابيع، أو يصاحبه نوبات هلع، فاطلب مختصًا.","related_questions":["إزاي أوقف الأفكار المتسارعة","إيه تقنية اليقظة الذهنية"],"risk_level":"low","language":"mixed","tags":["مستقبل","خوف","مجهول"]},{"id":"fear-of-failure","question":"كيف أتغلب على الخوف من الفشل؟","alternative_questions":["خايف أفشل","ما بقدرش أبدأ حاجة خايف تطلع غلط","الخوف من الفشل مأسسني","إزاي أتجاوب مع الفشل"],"title":"الخوف من الفشل","category":"الخوف","subcategory":"الأداء","keywords":["خوف الفشل","فشل","أتشفيم","تجنب","طموح","إقدام","خوف الإخفاق"],"short_answer":"الخوف من الفشل غالبًا خوف من الحكم لا من الفشل نفسه. عُد تعريف الفشل من «نهاية» إلى «معلومة» فتخف سلطته.","answer":"الخوف من الفشل غالبًا خوف من:\n• حكم الآخرين\n• تأكيد شعور بقلة القيمة\n• خيبة من لا يريد خيبتك\n\nأعد تأطير الفشل:\n• الفشل حدث لا هوية — «فشلت في هذا» لا «أنا فاشل»\n• كل نجاح بُني على محاولات سابقة فشلت\n• الفشل معلومة توجّه المحاولة التالية\n• من لا يحاول لا يفشل، لكنه لا ينجح أيضًا\n\nابدأ صغيرًا. خفوف صغيرة متكررة تخفض حساسية الخوف الكبير.","practical_steps":["قسّم الهدف الكبير لخطوات صغيرة أقل إخافة","عيّن «يوم محاولة» أسبوعيًا بلا حكم على النتيجة","احتفل بالمحاولة لا بالنجاح فقط","اكتب ما تعلمته من كل فشل (يحوّله لمعلومة)","تحدّث مع من فشلوا ثم نجحوا — الفشل طبيعي"],"common_mistakes":["تجنّب البدء خوفًا من الفشل (فشل مضمون)","الكمالية: «إما مثالي أو لا أبدأ»","ربط قيمتك الذاتية بالنتائج","إخفاء الفشل خوفًا من الحكم فيفقد قيمته التعليمية"],"when_to_seek_help":"لو الخوف من الفشل يعطّل حياتك (تأجيل كل شيء، قلق شديد، تجنّب)، فالعلاج المعرفي السلوكي فعّال جدًا.","related_questions":["إزاي أبني ثقتي بنفسي","الكمالية إزاي أعالجها"],"risk_level":"medium","language":"mixed","tags":["فشل","خوف","طموح"]},{"id":"phobia-what-is-phobia","question":"ما هو الرهاب؟","alternative_questions":["يعني إيه رهاب","إيه الفرق بين الخوف والرهاب","أنا بخاف من حشرات لدرجة الإغماء ده رهاب","الرهاب أنواعه إيه"],"title":"الرهاب","category":"الرهاب","subcategory":"مفهوم الرهاب","keywords":["رهاب","فوبيا","خوف مرضي","خوف شديد","تجنب","أنواع رهاب","phobia"],"short_answer":"الرهاب خوف شديد ومستمر من شيء أو موقف لا يستحق هذا الخطر فعليًا، يدفع للتجنّب ويعطّل الحياة.","answer":"الرهاب خوف غير متناسب مع الخطر الفعلي. صاحبه يعرف أن خوفه مبالغ فيه لكنه لا يستطيع التحكم به.\n\nأنواع شائعة:\n• رهاب اجتماعي (خوف من النقد أو الإحراج أمام الناس)\n• رهاب الأماكن المغلقة (claustrophobia)\n• رهاب المرتفعات\n• رهاب الحشرات أو الحيوانات\n• رهاب الإبر والدم\n• رهاب الأماكن المفتوحة (agoraphobia)\n\nالرهاب قابل للعلاج بفاعلية كبيرة عبر التعرّض المتدرّج (Exposure) ضمن علاج معرفي سلوكي. نسبة تحسّن عالية.","practical_steps":["لا تتجنّب مصدر الخوف تمامًا — التجنّب يعزّز الرهاب","تعرّف درجة الخوف (0-10) عند التفكير فيه","اعرض نفسك تدريجيًا: صور، فيديو، بعد، ثم قرب","تعاون مع مختص لتصميم سلم تعرّض آمن","كافئ نفسك على كل خطوة تخطّيها"],"common_mistakes":["الاعتماد على الأمان (شخص يرافقك دائمًا) بدل العلاج","تجنّب كل ما يثير الرهاب فيتسع","القول «تقوّى» — الرهاب لا يُعالج بالإرادة وحدها"],"when_to_seek_help":"أي رهاب يعطّل حياتك (عمل، علاقات، تنقل) يستحق علاجًا. التعرّض المتدرّج بمعرفة مختص فعّال جدًا.","related_questions":["إيه الفرق بين الخوف والرهاب","إزاي أعالج الرهاب الاجتماعي"],"risk_level":"medium","language":"mixed","tags":["رهاب","خوف","علاج"]},{"id":"phobia-social","question":"كيف أتعامل مع الرهاب الاجتماعي؟","alternative_questions":["بخاف أتكلم قدام ناس","أنهار في الحفلات والتجمعات","خوفي من الناس بمنعني أخرج","إزاي أتغلب على الخوف الاجتماعي"],"title":"الرهاب الاجتماعي","category":"الرهاب","subcategory":"رهاب اجتماعي","keywords":["رهاب اجتماعي","خوف اجتماعي","خجل","إحراج","نقد","تجمعات","تحدث علني"],"short_answer":"الرهاب الاجتماعي خوف شديد من أحكام الناس يصل لتجنّب المواقف. يعالج بالتعرّض المتدرّج وإعادة بناء الأفكار الكارثية.","answer":"ليس مجرد خجل. الرهاب الاجتماعي خوف عميق من الإحراج أو النقد، يسبب أعراضًا جسدية (تعريق، احمرار، رعشة) ويدفع لتجنّب المواقف.\n\nالأفكار الشائعة المسببة:\n• «الكل ينظر إليّ»\n• «إن أخطأت سأكون سخيفًا»\n• «لا بد أن أكون مثاليًا في الكلام»\n\nالحقيقة: الناس أقل انتباهًا مما نظن، وأخطاؤك الصغيرة لا تُذكر بعد دقائق. التعرّض المتدرّج يكسر الدائرة:\n\nصغير: تحية جار ← متوسط: سؤال في اجتماع ← أكبر: عرض قصير.","practical_steps":["ابدأ بمواقف خوف منخفض (4-5/10) قبل الأعلى","ركّز انتباهك للخارج (الناس، الموضوع) لا الداخل (نبضك، عرقك)","اختبر أفكارك: «هل أحكم على الآخرين لو أخطأوا؟»","تدرّب على إجابات بسيطة جاهزة («موافق»، «شكرًا»)","لا تتجنّب — التجنّب يعزّز الخوف"],"common_mistakes":["تجنّب كل تجمع فيتسع الرهاب","التركيز على الذات يضخّم الأعراض","توقع الكمال في الأداء الاجتماعي","شرب الكحول «للشجاعة» (يخلق اعتمادًا)"],"when_to_seek_help":"لو الخوف الاجتماعي يعطّل دراستك أو عملك أو علاقاتك، فالعلاج المعرفي السلوكي فعّال جدًا. لا تتأخر.","related_questions":["إزاي أتكلم بثقة قدام ناس","إيه الرهاب"],"risk_level":"medium","language":"mixed","tags":["رهاب اجتماعي","خجل","تحدث"]},{"id":"ocd-what-is-ocd","question":"ما هو الوسواس القهري؟","alternative_questions":["يعني إيه وسواس قهري","أفكار بتجيلي وبتكدّرني إيه دي","أنا بعمل حاجات غصب عني ده وسواس","إزاي أعرف إني عندي وسواس"],"title":"الوسواس القهري","category":"الوسواس القهري","subcategory":"مفهوم الوسواس","keywords":["وسواس","وسواس قهري","أفكار قهرية","سلوك قهري","OCD","توهم","شكوك","طقوس"],"short_answer":"الوسواس القهري اضطراب فيه أفكار مزعجة متكررة (وساوس) تدفع لسلوكيات قهرية (طقوس) لتخفيف التوتر مؤقتًا، فتستمر.","answer":"دائرة الوسواس:\n\n1) فكرة مزعجة تتطفل (وسواس): «بيدي ملوث»، «ما أكونش أذيت أحدًا»، «الباب مفتوح».\n2) توتر شديد.\n3) سلوك (طقس) يخفف التوتر: غسل، فحص، ترديد.\n4) راحة مؤقتة تعزّز الطقس.\n5) الفكرة تعود أقوى.\n\nالمصاب يعرف أن أفكاره غير منطقية لكنه لا يستطيع التوقف. الإرادة وحدها لا تكفي. العلاج الفعّال هو العلاج المعرفي السلوكي بأسلوب «التعرّض ومنع الاستجابة» (ERP) وأحيانًا أدوية.","practical_steps":["لا تطلب طمأنة من الآخرين — تعزّز الوسواس","ميّز الفكر الوسواسي: «هذه فكرة وسواس، ليست حقيقة»","أخّر الطقس دقائق، ثم زد التأخير تدريجيًا","تعاون مع مختص في تصميم سلم تعرّض ومنع استجابة","توقع انتكاسات — العلاج عملية لا حدث"],"common_mistakes":["الاستسلام للطقس ظنًا أنه «يحمي»","طلب الطمأنة المستمرة من الأهل","إخفاء الوسواس فلا يُعالج","القول «تجاهل الفكرة» — صعب وحدك دون خطة"],"when_to_seek_help":"أي وسواس قهري يستنزف وقتك (ساعة+ يوميًا) أو يعطّل حياتك يستدعي علاجًا متخصصًا. ERP فعّال جدًا.","related_questions":["إزاي أعالج الوسواس","إيه الفرق بين الوسواس والشك العادي"],"risk_level":"medium","language":"mixed","tags":["وسواس","قلق","طقوس"]},{"id":"ocd-contamination","question":"كيف أتعامل مع وسواس التلوث؟","alternative_questions":["بغسل إيدي كتير لحد ما تنشف","حاسس كل حاجة وسخة","خايف المس حاجة تخليني أمرض","وسواس النظافة بياخد وقتي"],"title":"وسواس التلوث","category":"الوسواس القهري","subcategory":"أنواع الوسواس","keywords":["تلوث","نظافة","غسل","جراثيم","وسواس النظافة","خوف من المرض","تطهير"],"short_answer":"وسواس التلوث يجعلك تغسل وتطهّر بشكل مفرط. يعالج بالتعرّض التدريجي لل«ملوث» مع منع الطقس، فيتعلم الدماغ أن الخطر مبالغ فيه.","answer":"وسواس التلوث شائع. الدماغ يرسل إنذار «خطر» لما لا يستحق، فيندفع المريض لغسل/تطهير مفرط.\n\nالدائرة: لمس ← خوف ← غسل ← راحة مؤقتة ← حساسية أكبر. كل غسل يعزّز الفكرة أن الخطر حقيقي.\n\nالعلاج (ERP): تعرّض متدرّج للمثير مع منع الطقس:\n• المس شيئًا «ملوثًا» قليلًا\n• لا تغسل فورًا، انتظر دقائق\n• لاحظ أن القلق يرتفع ثم يهبط وحده\n• زد التعرّض تدريجيًا\n\nالمختص يصمم سلمًا آمنًا. لا تفعل ذلك فجأة وحيدًا.","practical_steps":["اصنع سلمًا: من الأقل إثارة للأكثر (باب، نقود، ثم قمامة)","ابدأ بالمثير الأدنى، انتظر 10 دقائق قبل الغسل","لا تطلب طمأنة أثناء التعرّض","سجّل مستوى القلق قبل وبعد (ستراه يهبط)","كافئ نفسك على إنجاز كل خطوة"],"common_mistakes":["الغسل «المثالي» بدل العلاج (يعزّز الوسواس)","تجنّب كل ما يثير الوسواس فيتسع","البدء بالمثير الأصعب فورًا (يفشل)","طلب الطمأنة من الأهل بعد كل لمسة"],"when_to_seek_help":"أي وسواس تلوث يستهلك ساعة+ يوميًا، أو يسبب تلف جلد، أو يعطّل حياتك، فالعلاج المتخصص ضروري.","related_questions":["ما هو الوسواس القهري","إزاي أوقف طقوس الوسواس"],"risk_level":"medium","language":"mixed","tags":["وسواس","تلوث","نظافة"]},{"id":"ocd-intrusive-thoughts","question":"ما هي الأفكار الاقتحامية؟","alternative_questions":["أفكار بتيجي في دماغي تكسفني","حاسس أفكار سيئة مش مني","أفكار عن أذية حد خايف منها","أفكار وسواسية بتكدّرني"],"title":"الأفكار الاقتحامية","category":"الوسواس القهري","subcategory":"الأفكار","keywords":["أفكار اقتحامية","أفكار مزعجة","وسواس أفكار","خوف من الأفكار","taboo thoughts","intrusive"],"short_answer":"الأفكار الاقتحامية أفكار تطفو في الذهن دون إرادة، غالبًا مزعجة أو محرّمة. وجودها لا يعني أنك تريدها — هي ليستك.","answer":"كل البشر لديهم أفكار اقتحامية أحيانًا («ماذا لو دفعت أحدًا؟»، «ماذا لو فعلت كذا؟»). الفرق:\n\n• الشخص السوي: تمر الفكرة وتزول.\n• صاحب الوسواس: يفزع منها، يحسبها دليلًا على نيته، فيعزّزها بالمقاومة والطقوس.\n\nالقاعدة الذهبية: الفكرة لا تعني الرغبة. العقل ينتج أفكارًا عشوائية كالبريد المزعج. ما يهم ليس ظهورها بل رد فعلك. لا تقاومها، لا تناقشها، دعها تمر كغيمة.\n\nالأخطر: من يخاف من أفكار عن إيذاء أحبائه — هذه شائعة جدًا في الوسواس وهي تتعارض مع قيمه الحقيقية. وجودها دليل قيمته لا عكس.","practical_steps":["صنّف الفكرة: «هذه فكرة اقتحامية، ليست رغبتي»","لا تجادل الفكرة أو تثبت عكسها — هذا يغذّيها","دعها تمر دون مقاومة («أه، فكرة جاءت»)","لا تتجنب المثيرات خوفًا من الفكرة","تعاون مع مختص في الوسواس لخطة ERP"],"common_mistakes":["اعتبار الفكرة دليلًا على «نوايا سيئة»","طلب طمأنة («أنا مش هعمل كده صح؟»)","تجنّب المواقف خوفًا من الفكرة","إخفاء الأفكار خجلًا (تبقى عالقة)"],"when_to_seek_help":"لو الأفكار الاقتحامية تسبب معاناة شديدة، أو تستنزف وقتك، أو تمنعك من حياتك، فاطلب مختصًا في الوسواس — العلاج فعّال جدًا.","related_questions":["ما هو الوسواس القهري","إزاي أوقف الأفكار المتسارعة"],"risk_level":"medium","language":"mixed","tags":["أفكار اقتحامية","وسواس","قلق"]},{"id":"panic-what-is-panic-attack","question":"ما هي نوبة الهلع؟","alternative_questions":["يعني إيه نوبة هلع","حسيت إني هموت فجأة إيه ده","قلبي بينبض وجسمي برجف إيه ده","أنا خايف يرجعلي نفس الإحساس"],"title":"نوبة الهلع","category":"نوبات الهلع","subcategory":"مفهوم الهلع","keywords":["هلع","نوبة هلع","خوف شديد","فزع","نوبة قلق","panic attack","ذعر","خوف من الموت"],"short_answer":"نوبة الهلع موجة مفاجئة من الخوف الشديد مع أعراض جسدية (خفقان، ضيق تنفس، خوف من الموت) تبلغ ذروتها خلال 10 دقائق ثم تهبط.","answer":"نوبة الهلع إنذار كاذب — جسمك يفعّل استجابة الخطر بلا خطر حقيقي.\n\nالأعراض الشائعة (تأتي فجأة، تبلغ ذروتها خلال 10 دقائق):\n• خفقان وتسارع قلب\n• ضيق تنفس أو إحساس بالاختناق\n• تعرّق، رعشة\n• ألم أو ضيق صدر\n• دوار، إحساس بغير الواقع\n• تنميل في الأطراف\n• خوف من الموت أو فقد السيطرة\n\nتبدو كأزمة قلبية لكنها ليست كذلك. تمر خلال 10-30 دقيقة. ليست خطيرة رغم شدتها. الخطر يبدأ حين يخاف المريض من تكرارها فيتجنب الأماكن (رهاب الساح).","practical_steps":["تذكّر: «هذه نوبة هلع، ستمر خلال دقائق، لن أموت»","تنفّس ببطء من البطن، لا بسرعة (يزيد الأعراض)","ركّز انتباهك للخارج: عد 5 أشياء تراها","لا تهرب من المكان — البقاء يعلم الدماغ الأمان","اطلب تقييمًا طبيًا أولًا لاستبعاد أسباب قلبية"],"common_mistakes":["التنفس السريع (يضخّم الأعراض)","الهروب من المكان (يعزّز الخوف منه)","الخوف من النوبة نفسها (يزيد تكرارها)","تجنّب الخروج خوفًا من نوبة (رهاب الساح)"],"when_to_seek_help":"لو تكررت النوبات، أو بدأت تتجنب أماكن، أو خفت من النوبة التالية، فاطلب مختصًا — العلاج فعّال جدًا. واطلب طوارئ فورًا عند أول نوبة لاستبعاد سبب قلبي.","related_questions":["إيه الفرق بين نوبة قلق ونوبة هلع","إزاي أوقف نوبة هلع"],"risk_level":"high","language":"mixed","tags":["هلع","نوبة","قلق"]},{"id":"panic-stop-attack","question":"كيف أوقف نوبة الهلع لحظة وقوعها؟","alternative_questions":["إزاي أوقف نوبة هلع وأنا فيها","حاسس نوبة هلع بتيجي إيه أعمل","تمرين لنوبة الهلع","أنا بنم نوبة هلع إزاي أهدى"],"title":"إيقاف نوبة الهلع","category":"نوبات الهلع","subcategory":"التعامل اللحظي","keywords":["إيقاف نوبة","تنفس","تأريض","تمرين","لحظة نوبة","كبح الهلع","grounding"],"short_answer":"أبطئ تنفسك، ثبّت قدميك على الأرض، ركّز انتباهك لخمسة أشياء حولك، وذكّر نفسك أن النوبة ستمر ولا خطر.","answer":"خطة 4 خطوات لحظة النوبة:\n\n1) تنفس ببطء: شهيق 4 ثوانٍ، كتم 4، زفير 6 — كرّر ببطء. التنفس السريع يضخّم الأعراض.\n\n2) تأريض 5-4-3-2-1: سمِّ 5 أشياء تراها، 4 تسمعها، 3 تلمسها، 2 تشمّها، 1 تتذوقها. يخرجك من الدوامة الذهنية.\n\n3) ثبّت جسدك: اضغط قدميك على الأرض، افرك يديك، اشرب ماء بارد.\n\n4) ذكّر نفسك: «هذه نوبة هلع، علاماتها معروفة، ستمر خلال دقائق، لم يمت أحد من نوبة هلع».\n\nلا تهرب من المكان — البقاء يعلم دماغك الأمان. مع التكرار تخف النوبات حدّة وتواترًا.","practical_steps":["احمل بطاقة مكتوبة: «هذه نوبة هلع، ستمر»","تدرّب على التنفس البطيء وقت الراحة","لا تتنفس في كيس ورقي إلا بإشراف (يخفض الأكسجين)","ثبّت قدميك بقوة على الأرض وصف ما تراه بصوت عالٍ","بعد النوبة، لا تتجنّب المكان — عد إليه قريبًا"],"common_mistakes":["الهروب من المكان (يعزّز الخوف منه)","التنفس السريع والعميق (يضخّم الأعراض)","محاولة «محاربة» النوبة (تزيد الاستثارة)","طلب الإسعاف كثيرًا (ثبّت الخوف) بعد استبعاد سبب قلبي"],"when_to_seek_help":"لو تكررت النوبات أو بدأت تتجنب أماكن، فالعلاج المعرفي السلوكي فعّال جدًا في منع تكرارها.","related_questions":["ما هي نوبة الهلع","إيه رهاب الساح"],"risk_level":"high","language":"mixed","tags":["هلع","تنفس","تأريض"]},{"id":"panic-fear-of-recurrence","question":"لماذا أخاف من نوبة هلع قادمة؟","alternative_questions":["خايف نوبة هلع ترجع","بستنى النوبة القادمة بخوف","خوف تكرار النوبة مأسّسني","كيف أكسر دائرة الخوف من النوبة"],"title":"الخوف من تكرار النوبة","category":"نوبات الهلع","subcategory":"الخوف التوقعي","keywords":["خوف التوقع","تكرار نوبة","رهاب النوبة","ترقب","قلق من النوبة","anticipatory anxiety"],"short_answer":"الخوف من نوبة قادمة (خوف التوقع) قد يكون أسوأ من النوبة نفسها. كسر الدائرة بعدم التجنّب وقبول إمكانية النوبة يخفّضه.","answer":"بعد نوبة هلع، يبدأ عقلك في «الترقّب»: متى تأتي التالية؟ هذا الخوف يصبح نوبة قلق مزمنة ويوسّع دائرة التجنّب.\n\nالمفارقة: الخوف من النوبة يزيد احتمال حدوثها، لأنه يرفع الاستثارة. لذا:\n\n• لا تقاوم إمكانية النوبة — قاومتها زادت\n• قل لنفسك: «إن جاءت، سأتعامل معها. مرّت من قبل وستمر»\n• لا تتجنّب الأماكن التي حدثت فيها — التجنّب يثبّت الخوف\n• تعرّض تدريجيًا للمكان دون هروب\n\nهذا جوهر علاج نوبات الهلع: تعليم الدماغ أن النوبة غير خطيرة وأنك قادر على تحمّلها.","practical_steps":["اكتب خطة للنوبة (التنفس، التأريض، العبارة) لتطمئن","عُد للمكان الذي حدثت فيه نوبة سابقًا","لا تحمل «أدوية طوارئ» كإشارة خوف دائمة (ناقش مع مختص)","سجّل كل نوبة: متى، أين، شدتها — سترى أنها تقل","التزم بجلسات علاج معرفي سلوكي"],"common_mistakes":["تجنّب كل مكان حدثت فيه نوبة (يتسع)","الحديث المستمر عن الخوف (يثبّته)","المراقبة المستمرة لنبض القلب","تأجيل الحياة «حتى تختفي النوبات» — لا تختفي وحدها"],"when_to_seek_help":"لو الخوف من النوبة يعطّل خروجك أو عملك، فالعلاج المتخصص ضروري وفعّال.","related_questions":["إزاي أوقف نوبة هلع","إيه رهاب الساح"],"risk_level":"high","language":"mixed","tags":["هلع","خوف توقع","تجنّب"]},{"id":"anxious-attachment-what-is","question":"ما هو التعلق القلق؟","alternative_questions":["يعني إيه التعلق القلق","أنا خايف دايماً إنه يسيبني ده تعلق قلق","ليه بحتاج طمأنة كل شوية من شريكي","إزاي أعرف إني متعلق قلق","ليه بقلق لما حد يقرب مني"],"title":"التعلق القلق","category":"التعلق القلق","subcategory":"مفهوم التعلق القلق","keywords":["تعلق قلق","خوف الهجر","خوف الفقد","الاحتياج","الطمأنة","التشبث","قلق العلاقة"],"short_answer":"التعلق القلق نمط علاقي تتميل فيه للخوف من فقدان الشريك وتحتاج طمأنة مستمرة، وغالبًا يبدأ من تجارب الطفولة.","answer":"التعلق القلق أحد أنماط التعلق. صاحبه يعيش خوفًا دائمًا من أن يتركه الشريك أو لا يحبه.\n\nيظهر في: حاجة مستمرة للطمأنة، حساسية شديدة لردود الشريك، تشبّط زيادة. لما الشريك يبتعد ولو شوية يحس بقلة قيمة وذعر.\n\nالسبب غالبًا طفولة فيها مقدم رعاية متذبذب — ساعة موجود وساعة غايب، فالطفل تعلّم أن الحب غير مضمون. المهم أن النمط قابل للتغيير بالوعي والعلاج.","practical_steps":["لاحظ متى يشتعل الخوف — اكتب الموقف والإحساس والفكرة","قبل التواصل مع الشريك من قلق، انتظر 15 دقيقة واختبر حقيقة الخوف","طوّر مصادر أمان داخلية: هوايات، صداقات، أهداف خاصة","مرّن تهدئة جسدك بالتنفس لما يجيك القلق","اطلب علاجًا نفسيًا متخصصًا في العلاقات والتعلق"],"common_mistakes":["طلب الطمأنة بكثرة — يضغط الشريك ويزيد القلق مؤقتًا","اختبار الشريك بالابتعاد للتأكد من حبه","إلغاء الذات والاهتمامات من أجل الشريك","تفسير صمت الشريك أو انشغاله كرفض"],"when_to_seek_help":"اطلب مختصًا لو القلق على العلاقة يؤثر على نومك وحياتك، أو تدخل علاقات متكررة بنفس النمط، أو تعاني ذعرًا عند ابتعاد الشريك.","related_questions":["إزاي أتحول من التعلق القلق للتعلق الآمن","إيه الفرق بين الحب والتعلق","ليه بختار أطراف بعيدة عني"],"risk_level":"medium","language":"mixed","tags":["تعلق","علاقات","خوف الفقد"]},{"id":"anxious-attachment-signs","question":"ما علامات التعلق القلق؟","alternative_questions":["إزاي أعرف إني متعلق قلق","أعراض التعلق القلق","ليه بفكر فيه طول الوقت","بستنى رسالته كل دقيقة إيه ده"],"title":"علامات التعلق القلق","category":"التعلق القلق","subcategory":"العلامات","keywords":["علامات تعلق","تشبث","خوف الفقد","طمأنة","مراقبة","غيرة","هجر"],"short_answer":"أبرز العلامات: حاجة دائمة للطمأنة، تشبّث، مراقبة ردود الشريك، ذعر عند البعد، وإلغاء الذات من أجله.","answer":"علامات شائعة للتعلق القلق:\n\n• حاجة متكررة للطمأنة («تحبني؟»، «تأكد»)\n• تشبّط ومراسلة مستمرة\n• مراقبة دقيقة لردود الشريك (تأخر، صمت)\n• ذعر عند أي بعد أو خلاف بسيط\n• صعوبة في البقاء وحيدًا\n• إلغاء الاهتمامات والأصدقاء من أجل الشريك\n• غيرة وتفسير الأمور بأسوأ صورة\n• الدخول في علاقات سريعة متتالية\n• الخوف من البوح بمشاعرك حتى لا يبتعد\n\nوجود بعض هذه لا يعني بالضرورة نمطًا مرضيًا، لكن إن طغت وأثرت على حياتك وعلاقاتك، فهي إشارة لاهتمام.","practical_steps":["سجّل متى تشعر بالخوف من الفقد وما الموقف","لاحظ كم مرة تطلب طمأنة في اليوم","قارن اهتماماتك قبل العلاقة وبعدها — هل ألغيت ما يحبك","تحدّث مع مختص لتقييم نمط تعلقّك بدقة"],"common_mistakes":["اعتبار التشبّط دليل حب — هو غالبًا قلق","إخفاء العلامات خوفًا من اتهامك بالضعف","ربط قيمتك بوجود شريك"],"when_to_seek_help":"لو هذه الأنماط تتكرر في كل علاقاتك وتسبب لك ألمًا، فالعلاج النفسي يساعد على الانتقال لتعلق أكثر أمانًا.","related_questions":["ما هو التعلق القلق","إزاي أتحول للتعلق الآمن"],"risk_level":"medium","language":"mixed","tags":["علامات","تعلق قلق","علاقات"]},{"id":"anxious-attachment-becoming-secure","question":"كيف أتحول من التعلق القلق إلى التعلق الآمن؟","alternative_questions":["إزاي أكون متعلق آمن","أنا قلقان أعامل شريكي إزاي","كيف أصلح نمط تعلقي","ليه تعلقي قلق وأبي آمن"],"title":"التحول إلى التعلق الآمن","category":"التعلق القلق","subcategory":"التغيير","keywords":["تعلق آمن","تحول","تغيير نمط","أمان داخلي","اكتفاء ذاتي","علاقات صحية"],"short_answer":"التحول ممكن عبر بناء أمان داخلي (اهتمامات، صداقات، قيم)، تعلّم تهدئة القلق، واختيار شريك متاح، مع علاج نفسي.","answer":"نمط التعلق ليس قدرًا — الدماغ قابل لإعادة التشكيل (الليونة العصبية). خطوات التحول:\n\n1) بناء أمان داخلي: اهتمامات، صداقات، أهداف خاصة. لا تجعل شريكك مصدرك الأوحد للأمان.\n2) تعلّم تهدئة القلق: تنفس، يقظة ذهنية، تأجيل رد الفعل.\n3) اختبر أفكارك: «صمته يعني الغضب» — هل دليل؟\n4) اختيار شريك متاح ومتّسق — التعلق القلق مع شريك متجنب حلقة مؤذية.\n5) علاج نفسي (مخصص في العلاقات) لمعالجة جذور الطفولة.\n\nالتحول تدريجي. انتكاسات طبيعية. المهم الاستمرار.","practical_steps":["خصّص وقتًا أسبوعيًا لشيء تحبه بمفردك","قبل التواصل من قلق، انتظر 20 دقيقة","اكتشف قيمك وأهدافك بعيدًا عن العلاقة","عبّر عن احتياجك بوضوح بدل اختبار الشريك","التزم بجلسات علاج نفسي متخصصة"],"common_mistakes":["الانتظار حتى «يغيرك الشريك» — التغيير يبدأ منك","اختيار شريك متجنب ظنًا أنه يتحداك","اليأس بعد انتكاسة — التحول موجات لا خط مستقيم"],"when_to_seek_help":"العلاج النفسي المتخصص في أنماط التعلق (مثل العلاج المتمركز على العاطفة EFT) فعّال جدًا. لا تتردد.","related_questions":["ما هو التعلق القلق","إيه التعلق الآمن","ليه بختار شريك متجنب"],"risk_level":"medium","language":"mixed","tags":["تحول","تعلق آمن","علاج"]},{"id":"anxious-attachment-vs-love","question":"كيف أفرّق بين الحب والتعلق؟","alternative_questions":["هو ده حب ولا تعلق","حاسس إني مش قادر أستغني عنه حب ولا تعلق","فرق الحب والتعلق المرضي","حبي ده طبيعي ولا مبالغ"],"title":"الفرق بين الحب والتعلق","category":"التعلق القلق","subcategory":"تمييز","keywords":["حب","تعلق","فرق","حب صحي","تعلق مرضي","اعتماد","احتياج"],"short_answer":"الحب يمنح أمانًا ويوسّع حياتك. التعلق يسبب قلقًا ويضيّق حياتك حول شخص. الحب يريد الخير للطرفين، التعلق يخشى الفقد.","answer":"تمييز بسيط لكنه يحرّر:\n\nالحب الصحي:\n• تشعر بالأمان، لا القلق المستمر\n• تحافظ على هويتك واهتماماتك\n• تريد الخير للشريك ولو لم تكن معه\n• تتحمل البعد دون انهيار\n• تتطور وتنمو في العلاقة\n\nالتعلق القلق:\n• قلق دائم على بقاء الشريك\n• تُلغي ذاتك من أجله\n• تفقد قدرتك على الحياة بدونه\n• تختبره، تتشبّط، تطلب طمأنة\n• علاقتك ضيقة ومكثفة ومستنزفة\n\nالسؤال: هل علاقتك توسّع حياتك أم تضيّقها؟","practical_steps":["اسأل: هل حياتي اتسعت أم ضيّقت حوله","لاحظ هل تشعر بالأمان أم القلق المستمر","راجع هل ألغيت اهتماماتك وأصدقاءك","تخيل فراق سلمي — هل تنهار أم تتألم وتتعافى"],"common_mistakes":["تبرير التعلق بأنه «حب قوي»","الخلط بين الشغف الأولي (هيام) والحب الناضج","الاعتقاد أن الألم دليل قوة الحب"],"when_to_seek_help":"لو تشعر أنك لا تستطيع الحياة دون شخص، أو تكرر هذا النمط في علاقاتك، فالعلاج النفسي يساعد على التمييز والتحول.","related_questions":["ما هو التعلق القلق","إيه الحب الصحي","الإعجاب والهيام إيه"],"risk_level":"low","language":"mixed","tags":["حب","تعلق","تمييز"]},{"id":"avoidant-attachment-what-is","question":"ما هو التعلق التجنبي؟","alternative_questions":["يعني إيه تعلق تجنبي","ليه كل ما حد يقرب مني بأهرب","أنا مش حابب أتقرب لحد ليه","كل علاقة بتطفشني بسرعة"],"title":"التعلق التجنبي","category":"التعلق التجنبي","subcategory":"مفهوم التجنبي","keywords":["تعلق تجنبي","ابتعاد عاطفي","استقلال دفاعي","تجنب القرب","تجنّب","انفصال"],"short_answer":"التعلق التجنبي نمط فيه تتجنب القرب العاطفي وتفضّل الاستقلال المفرط دفاعًا ضد ألم الاعتماد على أحد.","answer":"التعلق التجنبي النمط المعاكس للقلق. صاحبه:\n\n• يصعب عليه القرب العاطفي\n• يفضّل الاستقلال المفرط\n• يشعر بالاختناق حين يقترب أحد\n• يقلل من احتياجاته العاطفية («مش محتاج حد»)\n• يبتعد حين تزداد العلاقة قربًا\n\nالجذر غالبًا طفولة فيها مقدم رعاية غير متاح عاطفيًا أو يثبط الحاجة («كن قويًا»)، فتعلم الطفل أن الاعتماد مؤلم وأن الاستقلال أأمن.\n\nالتجنبي يحتاج علاقته كما القلق، لكنه أقل إدراكًا للمشكلة لأن نمطه يبدو «هدوءًا».","practical_steps":["لاحظ متى تشعر بالرغبة في الابتعاد — ما المثير","ميّز بين الحاجة الحقيقية للمساحة والهروب من القرب","تدرّب على مشاركة مشاعر صغيرة مع شخص تثق به","لا تختر شريكًا قلقًا (حلقة مؤذية) دون وعي","اطلب علاجًا نفسيًا لاستكشاف جذور التجنّب"],"common_mistakes":["تفسير التجنّب بأنه «قوة» أو «استقلال صحي»","اختيار شريك قلق فيتغذى النمطان","إنهاء العلاقات عند أول قرب حقيقي","إنكار الاحتياج العاطفي رغم وجوده"],"when_to_seek_help":"لو تكرر إنهاء علاقاتك عند القرب، أو تشعر بعزلة رغم رغبتك في القرب، فالعلاج يساعد على التحول لتعلق آمن.","related_questions":["ما هو التعلق الآمن","ليه بختار شريك قلق","إزاي أقرب من حد وأنا تجنبي"],"risk_level":"medium","language":"mixed","tags":["تعلق تجنبي","ابتعاد","علاقات"]},{"id":"avoidant-attachment-vs-independence","question":"كيف أفرّق بين الاستقلال الصحي والتعلق التجنبي؟","alternative_questions":["استقلالي صحي ولا تجنبي","أنا بحب أكون لوحدي ده طبيعي","محدش محتاج حد إيه المشكلة","فرق الاستقلال والتجنب"],"title":"الاستقلال مقابل التجنّب","category":"التعلق التجنبي","subcategory":"تمييز","keywords":["استقلال","تجنب","تمييز","استقلال صحي","اعتماد","قرب"],"short_answer":"الاستقلال الصحي: تكتفي بذاتك وتقبل القرب حين تختار. التجنّب: ترفض القرب خوفًا من الاعتماد وتشعر بالاختناق عند الاقتراب.","answer":"الفرق دقيق لكنه حاسم:\n\nالاستقلال الصحي:\n• قادر على العيش وحيدًا بدون انهيار\n• يختار القرب بحرية ويستمتع به\n• يحافظ على هويته داخل العلاقة\n• يطلب المساعدة حين يحتاجها دون ذنب\n• قادر على العاطفة الحقيقية\n\nالتجنّب:\n• يرفض القرب خوفًا من الاعتماد\n• يشعر بالاختناق عند الاقتراب\n• ينكر احتياجه العاطفي\n• يقطع العلاقات عند القرب الحقيقي\n• يبدو «قويًا» لكنه محصّن بألم\n\nالسؤال: هل قربك من الناس خيار أم خوف؟","practical_steps":["راقب رد فعلك عند القرب العاطفي — اختناق أم أمان","سجّل متى تنهي علاقات — ما السبب الحقيقي","تحدّث مع مختص لتمييز نمطك","تدرّب على مشاركة مشاعر بسيطة مع شخص آمن"],"common_mistakes":["تبرير التجنّب بـ«أنا كده بطبعى»","الخلط بين الاكتفاء والخوف من القرب","رفض العلاج لأن «مش عندي مشكلة»"],"when_to_seek_help":"لو تكرر قطع علاقاتك عند القرب، أو شعرت بعزلة رغم رغبة في القرب، فالعلاج النفسي فعّال.","related_questions":["ما هو التعلق التجنبي","إزاي أقرب من حد وأنا تجنبي"],"risk_level":"low","language":"mixed","tags":["استقلال","تجنّب","تمييز"]},{"id":"secure-attachment-what-is","question":"ما هو التعلق الآمن؟","alternative_questions":["يعني إيه تعلق آمن","إزاي تكون العلاقة الصحية","إيه سمات الشخص الآمن عاطفياً","ليه ناس علاقاتهم هادية"],"title":"التعلق الآمن","category":"التعلق الآمن","subcategory":"مفهوم التعلق الآمن","keywords":["تعلق آمن","علاقة صحية","أمان عاطفي","ثقة","نضج عاطفي","استقرار"],"short_answer":"التعلق الآمن نمط تشعر فيه بالأمان مع شريكك، تثق به وتطمئن لقربه، وتحافظ على استقلالك دون قلق أو تجنّب.","answer":"التعلق الآمن النمط الصحي. صاحبه:\n\n• يثق بوجود الشريك وحبه\n• يطلب القرب ويمنحه بارتياح\n• يحافظ على هويته واهتماماته\n• يحل الخلافات بحوار لا بتهديد\n• يعبّر عن احتياجاته بوضوح\n• يتحمل البعد دون ذعر\n• يدعم شريكه في استقلاله\n\nهذا النمط يُكتسب إما من طفولة آمنة أو بوعي وعلاج. ليست قدرًا — من أي نمط آخر يمكنك التحول. الأمان ليس غياب المشكلات بل القدرة على التعامل معها دون أن يهتز أساس العلاقة.","practical_steps":["تعلّم التعبير عن احتياجاتك بوضوح دون اتهام","احترم مساحة شريكك ولا تفسرها كرفض","حُل الخلافات بالحوار لا التهديد بالهجر","حافظ على اهتماماتك وعلاقاتك خارج العلاقة","احتفل بنجاحات شريكه دون غيرة"],"common_mistakes":["اعتقاد أن الأمان غياب أي قلق — طبيعي قلق بسيط","تبرير أنماط غير صحية بأنها «حب واهتمام»","افتراض أن الأمان فطري لا قابل للتعلم"],"when_to_seek_help":"لو لم تنشأ في بيئة آمنة، فالعلاج النفسي يساعد على بناء الأمان الداخلي وتعلّم مهارات العلاقة الصحية.","related_questions":["إزاي أتحول للتعلق الآمن","ما هو التعلق القلق","ما هو التعلق التجنبي"],"risk_level":"low","language":"mixed","tags":["تعلق آمن","علاقة صحية","ثقة"]},{"id":"secure-attachment-raising-secure-children","question":"كيف أنشئ تعلقًا آمنًا لدى أطفالي؟","alternative_questions":["إزاي أخلي ابني متعلق آمن","تربية الأطفال على الأمان النفسي","إيه اللي بيخلي الطفل آمن","أزاي أكون أم آمنة"],"title":"تربية الطفل على التعلق الآمن","category":"التعلق الآمن","subcategory":"التربية","keywords":["طفل آمن","تربية","أمان طفل","رعاية","استجابة","تعلق آمن طفولة"],"short_answer":"التعلق الآمن لدى الطفل يُبنى بالاستجابة المتّسقة لاحتياجاته، الدفء، الحدود الواضحة، والاستقرار العاطفي من الوالدين.","answer":"أركان التعلق الآمن في الطفولة:\n\n1) الاستجابة المتّسقة: حين يبكي الطفل أو يحتاج، استجب بانتظام. لا تتجاهل تارة وتبالغ تارة.\n2) الدفء العاطفي: عناق، تواصل بصري، كلمات حب.\n3) الحدود الواضحة اللطيفة: ثبات لا قسوة.\n4) الاستقرار: روتين منتظم، رد فعل متوقع.\n5) علاقة الوالدين: الأمان يبدأ من استقرار بيتهما.\n\nليس المثالية — لا أحد يستجيب 100%. الأهم: «الإصلاح» بعد اللحظات الفاشلة (اعتذر، عناق، إعادة تواصل). هذا يعلم الطفل أن العلاقة تنجو من الخلاف.","practical_steps":["استجب لبكاء طفلك دون إهمال (ليس مدلعًا)","خصص وقتًا خالصًا يوميًا للتواصل معه","اعتذر حين تخطئ في حقه — يعلمه الأمان","حافظ على روتين نوم وأكل ثابت","حافظا أنتما كوالدين على علاقة صحية"],"common_mistakes":["ترك الطفل يبكي «ليتعلم الاعتماد على نفسه» — خرافة تضر","القسوة باسم التربية فالثقة تهتز","التذبذب: استجابة مرة وإهمال مرة","استخدام التهديد بالهجر للضبط («سأتركك»)"],"when_to_seek_help":"لو لديك تاريخ صدمة طفولة أنت نفسك، فالعلاج النفسي لك يساعد على عدم نقله لأطفالك.","related_questions":["ما هو التعلق الآمن","أطفال وبكاء الليل إيه الحل","إزاي أربّي بدون قسوة"],"risk_level":"low","language":"mixed","tags":["تربية","أطفال","تعلق آمن"]},{"id":"emotional-dependence-what-is","question":"ما هو الاعتماد العاطفي؟","alternative_questions":["يعني إيه اعتماد عاطفي","أنا معتمد عليه نفسياً إيه المشكلة","فرق الاعتماد العاطفي والحب","مش قادر أعمل حاجة بدونه"],"title":"الاعتماد العاطفي","category":"الاعتماد العاطفي","subcategory":"مفهوم","keywords":["اعتماد عاطفي","اتكال","احتياج مفرط","اعتماد نفسي","ضعف استقلال","تعلق"],"short_answer":"الاعتماد العاطفي أن تجعل شخصًا واحدًا مصدر قيمتك ومزاجك وقراراتك. يختلف عن الحب بأنه يسلب استقلالك.","answer":"الاعتماد العاطفي يجعل شخصًا محور حياتك النفسية:\n\n• مزاجك معتمد كليًا على ردود فعله\n• قراراتك تنتظر موافقته\n• لا تستطيع الاستمتاع بدونه\n• تشعر بالفقد الكامل لو غاب\n• تسامح على إيذاء خوفًا من فقده\n\nالفرق عن الحب الصحي: الحب يضيف لاستقلالك، الاعتماد يسلبه. الحب يصمد عند البعد، الاعتماد ينهار.\n\nالجذر غالبًا ضعف التقدير الذاتي وغياب مصادر أخرى للمعنى. العلاج يبني الأمان الداخلي ويوسّع مصادر الدعم.","practical_steps":["أعد اكتشاف اهتماماتك وأهدافك بعيدًا عنه","وسّع دائرة علاقاتك الداعمة","تدرّب على اتخاذ قرارات صغيرة بنفسك","عبّر عن اختلافك دون خوف من فقده","اطلب علاجًا نفسيًا لبناء التقدير الذاتي"],"common_mistakes":["تبرير الاعتماد بأنه «حب عميق»","تقليل مصادرك الاجتماعية ليبقى هو الوحيد","الصمت على إيذاء خوفًا من الفقد"],"when_to_seek_help":"لو تشعر أنك لا تستطيع الحياة دون شخص، أو تستمر في علاقة مؤذية خوفًا من الوحدة، فالعلاج النفسي ضروري.","related_questions":["إزاي أبطل اعتماد عاطفي","فرق الحب والاعتماد","إزاي أبني تقدير ذاتي"],"risk_level":"medium","language":"mixed","tags":["اعتماد","حب","استقلال"]},{"id":"emotional-dependence-breaking","question":"كيف أتخلص من الاعتماد العاطفي؟","alternative_questions":["إزاي أبطل اعتماد عاطفي","عايز أبطل أتعلق","مش قادر أستغني عنه إزاي","بناء الاستقلال العاطفي"],"title":"التخلص من الاعتماد العاطفي","category":"الاعتماد العاطفي","subcategory":"التعافي","keywords":["تخلص اعتماد","استقلال عاطفي","اكتفاء ذاتي","تعافي","تعلق","انفصال صحي"],"short_answer":"التخلص تدريجي: وسّع مصادر معناك (أهداف، صداقات، هوايات)، تدرّب على القرار المنفرد، وابنِ تقديرك الذاتي بمفردك.","answer":"كسر الاعتماد عملية بناء لا قطع مفاجئ:\n\n1) وسّع مصادر معناك: هوايات، أهداف مهنية، صداقات، تطوع. لا شخص واحد يحمل كل ثقلك.\n2) تدرّب على القرار المنفرد: ابدأ بقرارات صغيرة لا تستشير فيها.\n3) ابنِ تقدير ذاتك: إنجازات صغيرة، رعاية لنفسك، حديث داخلي رحيم.\n4) قلل التواصل المفرط تدريجيًا (لا قطع درامي).\n5) علاج نفسي لمعالجة الجذور (تقدير ذات، صدمات).\n\nالهدف ليس أن تستغني عن الناس، بل أن تكون علاقاتك اختيارًا لا حاجة.","practical_steps":["حدد نشاطًا تحبه وافعله أسبوعيًا بمفردك","تواصل مع صديق قديم واعيد التواصل","ضع 3 أهداف شخصية لهذا الشهر","تدرّب على قضاء يوم كامل بدون تواصل مفرط","اكتب 5 صفات قيمة فيك لا علاقة لها به"],"common_mistakes":["القطع المفاجئ لكل تواصل (ارتداد أقوى)","القفز لعلاقة جديدة فورًا لتعبئة الفراغ","تأجيل البناء الداخلي بانتظار «الشخص الصحيح»"],"when_to_seek_help":"لو كل محاولة للاستقلال تصاحبها قشعريرة أو ذعر، أو تستمر في علاقة مؤذية رغم وعيك، فالعلاج النفسي فعّال.","related_questions":["ما هو الاعتماد العاطفي","إزاي أبني تقدير ذاتي","الانفصال إزاي أتعافى منه"],"risk_level":"medium","language":"mixed","tags":["استقلال","تعافي","تقدير ذات"]},{"id":"love-what-is-healthy-love","question":"ما هو الحب الصحي؟","alternative_questions":["إيه الحب الحقيقي","حب صحي إيه معناه","إزاي أعرف الحب الصحى","علامات الحب الناضج"],"title":"الحب الصحي","category":"الحب","subcategory":"مفهوم الحب","keywords":["حب صحي","حب ناضج","حب حقيقي","علامات الحب","حب بالغ","علاقة ناجحة"],"short_answer":"الحب الصحي اختيار ناضج يجمع بين الانجذاب والاحترام والأمان، يوسّع حياتك ولا يلغي هويتك، ويثبت في الشدائد.","answer":"الحب الصحي ليس فقط شعورًا، بل اختيار وممارسة يومية. علاماته:\n\n• الاحترام المتبادل للهوية والحدود\n• الأمان — لا قلق مستمر على بقاء العلاقة\n• الدعم للنمو الشخصي لكليكما\n• حل الخلافات بالحوار لا الإذلال\n• الصدق والشفافية\n• الحفاظ على اهتمامات وعلاقات خارجية\n• الثبات في الشدائد لا الهروب\n\nالحب الصحي يبدأ بانجذاب لكنه يستمر بالالتزام. ليس خاليًا من الخلافات، بل قادرًا على تجاوزها دون أن يهتز الأساس.","practical_steps":["اختبر: هل علاقتك تضيف لحياتك أم تستنزفها","حافظ على هواياتك وأصدقائك داخل العلاقة","تعلّم حل الخلافات بالحوار لا الصمت أو الانفجار","عبّر عن تقديرك لشريكك بانتظام","احترم اختلافاته وحدوده"],"common_mistakes":["الخلط بين الهيام الأولي والحب الناضج","توقع أن الحب يعني «نفس الرأي دائمًا»","إلغاء الذات ظنًا أنه دليل حب","ربط الحب بالألم والدراما"],"when_to_seek_help":"لو تكررت علاقاتك بنفس نمط غير صحي، أو تجد صعوبة في الحفاظ على علاقة مستقرة، فالعلاج النفسي يساعد.","related_questions":["إيه فرق الحب والتعلق","إيه الإعجاب والهيام","لغات الحب إيه"],"risk_level":"low","language":"mixed","tags":["حب","علاقة صحية","ناضج"]},{"id":"love-languages","question":"ما هي لغات الحب؟","alternative_questions":["لغات الحب إيه","إزاي أعرف لغة حب شريكي","ليه شريكي مش حاسس بحبي","أنا بحبه بس مش حاسس بيه ليه"],"title":"لغات الحب","category":"الحب","subcategory":"التعبير","keywords":["لغات الحب","تعبير","كلمات","وقت","هدية","خدمة","لمس","gary chapman"],"short_answer":"لغات الحب خمس: كلمات التشجيع، وقت مميز، هدايا، أعمال خدمة، اللمس الجسدي. نفهم لغة شريكنا فنخاطبه بها.","answer":"كل شخص يعبر عن الحب ويستقبله بلغة رئيسية. التحدث بلغة غير لغة شريكك يجعله لا يشعر بحبك رغم نيتك.\n\nاللغات الخمس:\n\n1) كلمات التشجيع: مدح، تقدير، كلمات حب\n2) وقت مميز: انتباه كامل، حوار، نشاط معًا\n3) الهدايا: رموز مادية للتفكير (لا تعني بالضرورة غالية)\n4) أعمال خدمة: مساعدة في مهام (طبخ، إصلاح)\n5) اللمس الجسدي: عناق، قبضة يد، قرب\n\nاكتشف لغتك: ماذا تطلب أكثر؟ ماذا يؤذيك غيابه؟ ثم اكتشف لغة شريكك بمراقبة ما يعبر عنه.","practical_steps":["اسأل شريكه: متى تشعر أني أحبك أكثر","راقب كيف يعبر هو عن حبه (غالبًا لغته)","تحدّث بلغته ولو لم تكن لغتك الطبيعية","تنوّع في اللغات لكن ركّز على لغته الرئيسية","لا تفسر صمته بلغتك — ربما يعبّر بلغة أخرى"],"common_mistakes":["التعبير بلغتك أنت وظن أن شريكك يجب أن يفهم","الإصرار على هدية غالية بينما لغته «وقت»","إهمال لغة لمس لمن لغته لمس احترامًا لحدوده"],"when_to_seek_help":"لو التواصل بينكما متوقف رغم نية الطرفين، فاستشارة زوجية تساعد على فك الاشتباك.","related_questions":["إيه الحب الصحي","إزاي أحسّن التواصل مع شريكي"],"risk_level":"low","language":"mixed","tags":["لغات الحب","تعبير","تواصل"]},{"id":"infatuation-vs-love","question":"ما الفرق بين الإعجاب والحب؟","alternative_questions":["هو ده حب ولا إعجاب","حاسس في فراشات في بطني ده حب","إيه الهيام","حبي الجديد قوي جداً ده طبيعي"],"title":"الإعجاب مقابل الحب","category":"الإعجاب","subcategory":"تمييز","keywords":["إعجاب","هيام","حب","فرق","انجذاب","شغف","بداية علاقة"],"short_answer":"الإعجاب (الهيام) انجذاب كيميائي مكثف في البداية، يستمر أشهرًا. الحب يبنى ببطء بالمعرفة والالتزام ويثبت بعد انتهاء الهيام.","answer":"الإعجاب مرحلة طبيعية في بداية العلاقة. أعراضه: تفكير مستمر، فراشات، نشوة، مثالية الطرف الآخر.\n\nلكنه مرحلة لا علاقة دائمة:\n• مدته 6 أشهر إلى سنتين كيميائيًا\n• يعتمد على الدوبامين لا الالتزام\n• يرى الطرف مثاليًا (يتجاهل العيوب)\n\nالحب يبدأ بعد انتهاء الهيام:\n• يرى العيوب ويقبلها\n• يبني بالمعرفة والوقت\n• يختار البقاء حتى لما يخف الشغف\n• يثبت في الشدائد\n\nليس عيبًا أن تعيش الإعجاب، لكن الخطر أن تتخذ قرارات مصيرية (زواج) في قمته قبل أن ترى بوضوح.","practical_steps":["لا تتخذ قرار زواج في أول 6 أشهر","اختبر العلاقة في مواقف متنوعة (سفر، خلاف، مرض)","لاحظ ما تراه بعد خفوت النشوة الأولية","تحدّث بصراحة عن القيم والأهداف قبل الارتباط"],"common_mistakes":["الاعتقاد أن الهيام دليل الحب الأعظم","اتخاذ قرارات مصيرية في قمة النشوة","الذعر عند خفوت الشغف (طبيعي)","مثالية الطرف وعدم رؤية العيوب"],"when_to_seek_help":"إذا تكرر دخولك في علاقات مكثفة ثم إنهاؤها بعد خفوت الهيام، فالعلاج النفسي يساعد على فهم النمط.","related_questions":["إيه الحب الصحي","ليه بفقد شعوري بعد فترة","الخطوبة إيه معايير الاختيار"],"risk_level":"low","language":"mixed","tags":["إعجاب","هيام","حب"]},{"id":"rejection-how-to-deal","question":"كيف أتعامل مع الرفض؟","alternative_questions":["اترفض إيه أعمل","حاسس إني مرفوض","الرفض بيوجع إزاي أتعامل","محدش بيحبني ليه"],"title":"التعامل مع الرفض","category":"الرفض","subcategory":"مفهوم الرفض","keywords":["رفض","نبذ","إقصاء","ألم الرفض","تعافي","تقدير ذات","ظلم"],"short_answer":"الرفض يفعّل نفس مناطق الألم في الدماغ كالألم الجسدي. عالجه بلا لوم لنفسك، وسّع مصادر قيمتك، ولا تعممه على كل علاقاتك.","answer":"الرفض مؤلم بيولوجيًا — الدماغ يعالجه كألم جسدي. لكنه ليس حكمًا على قيمتك.\n\nأسباب الرفض غالبًا ليست شخصية:\n• عدم تطابق (لا الأفضل ولا الأسوأ، فقط مختلف)\n• ظرف الطرف الآخر (وقت، علاقة سابقة)\n• توقعات مختلفة\n\nأخطار الرفض:\n• تعميمه («لا أحد يحبني»)\n• جلد الذات («أنا السبب»)\n• الانعزال خوفًا من رفض جديد\n• العناد بمطاردة الرافض (يزيد الألم)\n\nالرفض جزء من الحياة. من لا يُرفض لا يجرّب. تقبّله كفرز طبيعي لا كحكم.","practical_steps":["اسمح لنفسك بالحزن دون تعميم","ذكّر نفسك: هذا رفض موقف لا رفض لذاتك","لا تطارد الرافض — الكرامة أولًا","وسّع مصادر قيمتك (أصدقاء، إنجازات، هوايات)","بعد التعافي، عاود المحاولة بحذر وصبر"],"common_mistakes":["تعميم الرفض على كل العلاقات","جلد الذات وبحث عن عيوب متخيلة","مطاردة الرافض محاولة إثبات القيمة","العزلة خوفًا من رفض جديد"],"when_to_seek_help":"لو الرفض يسبب حزنًا طويلًا، أو فقدان ثقة بالنفس، أو عزلة، أو أفكار يأس، فاطلب مختصًا.","related_questions":["إزاي أبني تقدير ذاتي","ليه بحس إني مرفوض دايماً","كيف أتجاوز انفصال"],"risk_level":"medium","language":"mixed","tags":["رفض","تقدير ذات","تعافي"]},{"id":"rejection-fear-of","question":"كيف أتغلب على الخوف من الرفض؟","alternative_questions":["خايف أترفض","ما بطلبش حاجة خايف يقولو لا","الخوف من الرفض بيوقفني","ما بقدرش أتقرب لحد خايف يرفضني"],"title":"الخوف من الرفض","category":"الرفض","subcategory":"الخوف","keywords":["خوف الرفض","خوف النبذ","تجنب","مبادرة","قلق اجتماعي","حساسية"],"short_answer":"الخوف من الرفض طبيعي، لكنه يصير عائقًا إن منعك من المحاولة. تعرّض متدرّج وإعادة تأطير الرفض يخفّضان سلطته.","answer":"الخوف من الرفض يحمينا اجتماعيًا قديمًا، لكنه اليوم مبالغ فيه:\n\n• يتجنب صاحبه المبادرة خوفًا من «لا»\n• يفسر صمت أو تأخر كرفض\n• يخفي مشاعره خوفًا من السخرية\n• يلغي فرصًا قبل تجربتها\n\nالعلاج المعرفي السلوكي:\n1) اختبر الفكرة: «إن رُفضت، ما الأسوأ الذي سيحدث؟» غالبًا أقل مما تتخيل.\n2) تعرّض متدرّج: ابدأ بطلبات صغيرة (سؤال عن طريق)، ثم أكبر.\n3) تقبّل أن الرفض جزء طبيعي — حتى الأكثر شعبية يُرفض.\n4) فصل قيمتك عن النتيجة.\n\nمن لا يُرفض لا يطلب. الرفض مؤلم لكنه ليس قاتلًا، ويتكرر فيصبح أقل تأثيرًا.","practical_steps":["حدد موقفًا صغيرًا تخاف من رفضه وافعله هذا الأسبوع","اكتب سيناريو الرفض وأسوأ نتيجة — غالبًا محتمل","كافئ نفسك على المبادرة لا على النتيجة","تذكّر: الرفض معلومة لا حكم","تحدّث مع مختص إن كان الخوف شللًا"],"common_mistakes":["تجنّب كل موقف قد ينتهي برفض (حياة ضيقة)","ربط قيمتك بالقبول","توقع الرفض قبل حدوثه فتتصرف بدفاعية"],"when_to_seek_help":"لو الخوف من الرفض يعطّل علاقاتك أو فرصك المهنية، فالعلاج النفسي فعّال جدًا.","related_questions":["إزاي أتعامل مع الرفض","إزاي أبني ثقتي بنفسي","الرهاب الاجتماعي إيه"],"risk_level":"medium","language":"mixed","tags":["خوف","رفض","مبادرة"]},{"id":"breakup-how-to-recover","question":"كيف أتعافى من انفصال؟","alternative_questions":["اتفصلت إزاي أنساه","مش قادر أتجاوز الانفصال","حاسس ألم بعد الفراق كبير","إزاي أتجاوز حد فات"],"title":"التعافي من الانفصال","category":"الانفصال","subcategory":"التعافي","keywords":["انفصال","فراق","تعافي","نسيان","ألم الفراق","ما بعد العلاقة","حزن"],"short_answer":"الانفصال فقد حقيقي يستحق الحزن. التعافي يحتاج وقتًا، مسافة، تعبيرًا عن الألم، وإعادة بناء حياة بدون الطرف الآخر.","answer":"الانفصال ليس مجرد نهاية علاقة، بل فقد لشريك وهوية مشتركة ومستقبل متخيّل. حزنه طبيعي ويأتي في موجات.\n\nمراحل التعافي (ليست خطية):\n\n1) صدمة وإنكار\n2) غضب (على الطرف الآخر أو النفس)\n3) تفاوض («لو فعلت كذا...»)\n4) حزن وحيدة\n5) قبول وتعافي\n\nما يسرّع التعافي:\n• مسافة فعلية (لا متابعة على وسائل التواصل)\n• تعبير عن الألم (كتابة، حديث)\n• روتين يومي وإن كان بسيطًا\n• تواصل مع الداعمين\n• إعادة اكتشاف الذات بعيدًا عن العلاقة\n\nما يبطئه: متابعة الطرف، محاولة العودة المتكررة، القفز لعلاقة جديدة فورًا.","practical_steps":["قلّل أو اقطع التواصل والمتابعة لفترة","اكتب رسالة بالألم ولا ترسلها (تفريغ)","حافظ على روتين نوم وأكل مهما قلّ","أعد اكتشاف اهتماماتك القديمة","حدد موعدًا (مثلاً 3 أشهر) لإعادة تقييم مشاعرك"],"common_mistakes":["متابعة الطرف على وسائل التواصل (تطيل الألم)","القفز لعلاقة جديدة لتعبئة الفراغ","جلد الذات («أنا السبب»)","الاتصال المتكرر في لحظات ضعف"],"when_to_seek_help":"لو بعد أشهر تشعر بحزن شديد، أو فقدان الاهتمام بالحياة، أو أفكار يأس، فاطلب مختصًا.","related_questions":["إزاي أنسى حد بحبه","ليه مش قادر أنسى","متى أطلب عودة العلاقة"],"risk_level":"medium","language":"mixed","tags":["انفصال","تعافي","حزن"]},{"id":"breakup-why-cannot-forget","question":"لماذا لا أستطيع نسيان شخص؟","alternative_questions":["ليه مش قادر أنسى","ليه بفكر فيه طول الوقت","محتاج أنساه إزاي","ليه الألم مش بيعدى"],"title":"عدم القدرة على النسيان","category":"الانفصال","subcategory":"الألم المستمر","keywords":["نسيان","تعلق","ألم مستمر","فكار","ذكرى","تعلق قلق","تعافي بطيء"],"short_answer":"عدم النسيان طبيعي — الدماغ يعالج الفقد كصدمة. لا تُجبر نفسك على النسيان، بل اقبل المرور بالألم حتى يخفّ تدريجيًا.","answer":"«النسيان» ليس هدفًا واقعيًا ولا صحيًا. الذكريات لا تُمحى. ما يحدث فعليًا: يخف أثرها العاطفي بمرور الوقت ومع بناء حياة جديدة.\n\nأسباب بقاء الألم:\n\n• التعلق القلق يجعل الفقد كارثيًا\n• استمرار التواصل أو المتابعة (يُجدد الجرح)\n• هويتك كانت مدمجة في العلاقة\n• حزن غير معبَّر عنه\n• توقعات لم تتحقق («كنا سنفعل كذا»)\n• لوم النفس («لو فعلت...»)\n\nلا تقاوم الذكريات — مرورها طبيعي. ما تحتاجه هو بناء حياة تجعل الذكرى تأخذ مكانها الطبيعي كحادث ماضٍ لا حاضر آسر.","practical_steps":["لا تجبر نفسك على النسيان — اقبل مرور الذكريات","قلّل المحفّزات (صور، أماكن، متابعة) لفترة","ابنِ روتينًا جديدًا لا يحتويه","عبّر عن الألم (كتابة، حديث) لتفريغه","حدد أهدافًا شخصية جديدة تستثمر طاقتك فيها"],"common_mistakes":["متابعة الطرف على وسائل التواصل (يجدد الألم)","محاولة قمع الذكريات (تزداد قوة)","جلد الذات على عدم النسيان (يطيل المعاناة)","القفز لعلاقة جديدة فورًا"],"when_to_seek_help":"لو بعد أشهر الألم يمنعك من حياتك، أو يصاحبه يأس، أو ينعكس على عملك ونومك، فاطلب مختصًا.","related_questions":["إزاي أتعافى من انفصال","هو ده حب ولا تعلق","متى أطلب عودة العلاقة"],"risk_level":"medium","language":"mixed","tags":["نسيان","انفصال","ألم"]},{"id":"breakup-should-i-go-back","question":"هل أعود لعلاقة انتهت؟","alternative_questions":["أروحله تاني ولا لأ","إمتى أطلب عودة العلاقة","اتصالحنا كتير بصراحة محتار","هل الرجوع للحب القديم صحى"],"title":"العودة لعلاقة منتهية","category":"الانفصال","subcategory":"قرارات","keywords":["عودة","رجوع","تصالح","علاقة سابقة","قرار","حب قديم"],"short_answer":"العودة ليست ممنوعة، لكنها تحتاج تغييرًا حقيقيًا في أسباب الانفصال لا مجرد حنين. اطلب وقتًا، احذر الدورات المتكررة.","answer":"ليست كل عودة خطأ، لكن ليست كل عودة حكيمة. أسئلة قبل العودة:\n\n1) ما سبب الانفصال؟ هل تغيّر فعليًا أم مجرد حنين؟\n2) هل كلاكما اعترف بمسؤوليته أم يلوم الآخر؟\n3) هل لديكما خطة لمعالجة السبب؟\n4) هل العلاقة ستعود لنفس أنماطها؟\n5) هل الحنين للأشخاص أم للذكريات؟\n\nأخطر ما في العودة: الدورة المتكررة (انفصال/عودة). كل دورة تستهلك ثقة وتزيد الألم.\n\nبعض العلاقات تستحق فرصة ثانية بعد تغيير. بعضها يعود ليتألم أكثر. الفرق: العمل على الجذور لا الاشتياق.","practical_steps":["لا تعد في لحظة حنين — انتظر أسابيع","ناقشا بصراحة أسباب الانفصال قبل العودة","اطلب تغييرات محددة وقابلة للقياس","حدد فترة تجربة قبل قرار الالتزام الكامل","فكّرا في استشارة زوجية لمعالجة الأسباب"],"common_mistakes":["العودة في لحظة وحدة أو حنين","العودة دون مناقشة أسباب الانفصال","العودة لنفس الشخص توقعًا لتغيير دون عمل","الدورات المتكررة من الانفصال والعودة"],"when_to_seek_help":"لو علاقتك في دورة متكررة، أو فيها عنف أو إيذاء، فاستشارة متخصصة ضرورية قبل أي عودة.","related_questions":["إزاي أتعافى من انفصال","علامات العلاقة السامة","إيه الحدود النفسية"],"risk_level":"medium","language":"mixed","tags":["عودة","قرار","علاقة سابقة"]},{"id":"divorce-life-after","question":"كيف أعيد بناء حياتي بعد الطلاق؟","alternative_questions":["اتطلقت إزاي أعيش تاني","حياتي بعد الطلاق إزاي أبنيها","أنا مطلقة وحاسة إني خلصت","إزاي أتجاوز صدمة الطلاق"],"title":"الحياة بعد الطلاق","category":"الطلاق","subcategory":"التعافي","keywords":["طلاق","ما بعد الطلاق","إعادة بناء","صدمة طلاق","تعافي","بداية جديدة","مطلق"],"short_answer":"الطلاق فقد كبير يستحق الحزن. إعادة البناء تبدأ بقبول المشاعر، ثم بناء روتين ودعم، ثم إعادة اكتشاف هويتك منفردة.","answer":"الطلاق نهاية علاقة، لكنه أيضًا فقد لهوية مشتركة وروتين وأحلام. حزنه طبيعي وقد يأتي في موجات أشهرًا.\n\nخطوات إعادة البناء:\n\n1) اسمح بالحزن — لا تتعجل «التجاوز». البكاء والغضب جزء من التعافي.\n2) بناء روتين — الاستقرار اليومي يمنح إحساسًا بالأمان.\n3) شبكة دعم — أصدقاء، عائلة، مجموعة دعم للمطلقين.\n4) إعادة اكتشاف الهوية — من أنت خارج الزواج؟ اهتماماتك، أهدافك.\n5) رعاية الأطفال إن وُجدوا — نموذج صحى أهم من الأبوين معًا في بيت متوتر.\n6) مساعدة قانونية ونفسية — حقك وحقوق أطفالك أولاً.\n\nالطلاق ليس فشلًا. أحيانًا يكون قرارًا شجاعًا لإنهاء وضع مؤذٍ.","practical_steps":["خصّص وقتًا يوميًا للحزن ثم انتقل لروتين","أعد اكتشاف هواياتك وأهدافك القديمة","انضم لمجموعة دعم للمطلقين","اطلب محاميًا لحقوقك إن لزم","احمِ أطفالك من الخلافات بينك وبين طليقك"],"common_mistakes":["القفز لعلاقة جديدة فورًا لتعبئة الفراغ","إشراك الأطفال في خلافاتكم","جلد الذات («أنا السبب»، «لو صبرت»)","العزلة الاجتماعية خجلًا"],"when_to_seek_help":"لو بعد أشهر تشعر بحزن عميق، أو فقدان اهتمام بالحياة، أو صعوبة في رعاية أطفالك، فاطلب مختصًا.","related_questions":["إزاي أتعامل مع حزن الفقد","أطفالي بعد الطلاق إزاي أعينهم","صدمة الطلاق إزاي أعالجها"],"risk_level":"high","language":"mixed","tags":["طلاق","تعافي","إعادة بناء"]},{"id":"divorce-children","question":"كيف أساعد أطفالي بعد الطلاق؟","alternative_questions":["أطفالي بعد الطلاق إزاي أعينهم","ابني متأثر بالطلاق إيه أعمل","إزاي أحمي أطفالي من أثر الطلاق","الطفل بعد انفصال الأبوين إزاي أتعامل"],"title":"أطفال الطلاق","category":"الطلاق","subcategory":"الأطفال","keywords":["أطفال طلاق","طلاق","طفل مطلق","رعاية","تأثير الطلاق","حضانة","تأهيل"],"short_answer":"حماية أطفال الطلاق تبدأ بعدم إشراكهم في خلافاتكم، طمأنتهم بحبكما، الحفاظ على روتين، وتأكيد أن الطلاق ليس خطأهم.","answer":"الطلاق صدمة للأطفال، لكن أسوأ من الطلاق: العيش في بيت متوتر. كيف تقلّل الأثر:\n\n• لا تُشركهم في خلافاتكم — لا شتم الطرف الآخر أمامهم.\n• أكّد أن الطلاق ليس خطأهم («أنتما لم تفعلا شيءًا»).\n• حافظ على روتينهم (مدرسة، نوم، أنشطة).\n• سمح لهم برؤية الطرف الآخر بانتظام إن كان آمنًا.\n• استمع لمشاعرهم دون الدفاع عن نفسك.\n• لا تجعلهم رسلًا بينكما.\n• لا تستخدمهم سلاحًا في الخلاف.\n\nالأطفال يتأقلمون حين يشعرون أن كلا الأبوين ما زال يحبهما ولم يخترا الطلاق ضدهم.","practical_steps":["اجلسا معًا (إن أمكن) لشرح الطلاق بلطف وهدوء","أكّد: «ماما وبابا يحبانكما، نحن من تغير لا أنتما»","حافظ على روتين نوم وأكل ومدرسة ثابت","سمح بزيارات منتظمة للطرف الآخر إن آمن","اطلب مختصًا للأطفال إن لاحظت تغيرات سلوكية"],"common_mistakes":["شتم الطرف الآخر أمام الطفل (يجرحه)","جعل الطفل رسولًا أو جاسوسًا","سؤال الطفل «مع من تريد أن تعيش» (عبء عليه)","التنافس على حب الطفل بإغداق الهدايا","إخفاء الحقيقة بكذب يكتشف لاحقًا"],"when_to_seek_help":"لو ظهرت على الطفل علامات (تراجع دراسي، سلوك عدواني، انطواء، تبول ليلي، أفكار خوف)، فاطلب مختصًا في صحة نفسية للأطفال.","related_questions":["الحياة بعد الطلاق","أطفالي كيف أفهم مشاعرهم","إزاي أربّي بدون قسوة"],"risk_level":"high","language":"mixed","tags":["أطفال","طلاق","رعاية"]},{"id":"betrayal-how-to-heal","question":"كيف أتعافى من خيانة شريكي؟","alternative_questions":["اكتشفت إني متخان إيه أعمل","خيانة شريكي جرحتني إزاي أتجاوز","ألم الخيانة مش بيعدى","إزاي أعفي بعد الخيانة"],"title":"التعافي من الخيانة","category":"الخيانة","subcategory":"التعافي","keywords":["خيانة","غدر","ألم الخيانة","ثقة","علاج الخيانة","صدمة عاطفية","زنا"],"short_answer":"الخيانة صدمة عاطفية تستحق التعافي. تحتاج وقتًا، مسافة، تفريغًا للألم، وقرارًا واعيًا (استمرار أو انفصال) بعد التعافي لا في قمته.","answer":"الخيانة ليست فقط فعلًا، بل صدمة تهز ثقتك بنفسك وبالآخرين. أعراضها تشبه الصدمة: ذكريات، أرق، تقلب مزاج.\n\nمراحل التعافي:\n\n1) صدمة — لا تتخذ قرارًا مصيريًا في هذه المرحلة.\n2) تفريغ الألم — عبّر بصراحة، كتابة، حديث.\n3) فهم لا تبرير — لماذا حدث؟ (لا يبرر الخيانة، لكن يوضح).\n4) قرار — استمرار (مع شروط) أو انفصال. لا تُتخذ في قمة الألم.\n5) إعادة بناء الثقة — إن اخترتما الاستمرار، شهور/سنوات من الشفافية.\n6) المسامحة (لا النسيان) — تحرر قلبك.\n\nالخيانة مسؤولية من خان، لا من خُون. لا تلم نفسك. لكنك تملك قرار التعافي ومسار العلاقة.","practical_steps":["لا تتخذ قرارًا مصيريًا في أول أسابيع","اطلب مسافة مؤقتة إن لزم لتفكير واضح","عبّر عن ألمك (كتابة، حديث لمختص)","إن اخترتما الاستمرار، اشترطا شفافية كاملة","اطلبا استشارة زوجية متخصصة في الخيانة"],"common_mistakes":["اتخاذ قرار (طلاق/عودة) في قمة الألم","لوم النفس («لو كنت...»)","محاولة النسيان دون معالجة (يعود كصدمة)","العفو السريع لإنقاذ العلاقة دون شروط","استخدام الخيانة كسلاح للأبد"],"when_to_seek_help":"الخيانة صدمة تستحق علاجًا متخصصًا. اطلب مختصًا في الصدمات العاطفية أو الاستشارة الزوجية المتخصصة.","related_questions":["إزاي أبني الثقة تاني","متى أعفي عن خيانة","صدمة الخيانة إزاي أعالجها"],"risk_level":"high","language":"mixed","tags":["خيانة","تعافي","صدمة"]},{"id":"betrayal-rebuilding-trust","question":"كيف أعيد بناء الثقة بعد الخيانة؟","alternative_questions":["إزاي أثق فيه تاني","بعد الخيانة مش قادر أثق","بناء الثقة بعد الغدر إزاي","إزاي أعرف إنه اتغير"],"title":"إعادة بناء الثقة","category":"الخيانة","subcategory":"الثقة","keywords":["ثقة","إعادة بناء","بعد خيانة","شفافية","التزام","صبر","تحقق"],"short_answer":"إعادة الثقة تستغرق شهورًا/سنوات من الشفافية الكاملة، الاتساق بين القول والفعل، والصبر. المسؤولية على من خان ليثبت التغيير.","answer":"الثقة لا تُطلب بل تُكسب بالأفعال. من خان عليه أن:\n\n• يجيب كل أسئلة الشريك بصدق (لا تفاصيل مؤذية زائدة)\n• يوفّر شفافية كاملة (هاتف، موقع، مواعيد)\n• يقطع كل تواصل مع الطرف الثالث تمامًا\n• يتحمل غضب وأسئلة الشريك دون دفاعية\n• يبادر بإجراءات (علاج، استشارة)\n• يكون صبورًا — الثقة تُبنى ببطء\n\nمن خُون عليه أن:\n• يطلب ما يحتاجه بوضوح\n• لا يستخدم الخيانة سلاحًا للأبد\n• يلاحظ التغيّر الفعلي ويعترف به\n• يطلب مساعدة مختص للألم\n\nإعادة الثقة قرار ثنائي. إن لم يلتزم من خان بالأفعال، العودة تعيد الجرح.","practical_steps":["اتفقا على شروط شفافية واضحة (هاتف، مواعيد)","حددا جلسات استشارة زوجية منتظمة","سجّل الاتساق بين القول والفعل شهورًا","لا تستعجل المسامحة — خذ وقتك","احتفل بكل خطوة تقدم حقيقية"],"common_mistakes":["طلب الثقة قبل الأفعال (لا تُعطى بل تُكسب)","استخدام الخيانة سلاحًا في كل خلاف","العودة دون شروط أو شفافية","العفو السريع لإنقاذ العلاقة"],"when_to_seek_help":"إعادة بناء الثقة بعد خيانة تستفيد جدًا من استشارة زوجية متخصصة. لا تتردد في طلبها.","related_questions":["إزاي أتعافى من خيانة","متى أعفي عن خيانة","الإخلاص إزاي أحافظ عليه"],"risk_level":"high","language":"mixed","tags":["ثقة","خيانة","علاقة"]},{"id":"jealousy-healthy-vs-unhealthy","question":"ما الفرق بين الغيرة الصحية والمرضية؟","alternative_questions":["غيرتي طبيعية ولا مبالغ","إيه الغيرة الصحية","غيرة شديدة على شريكي إيه الحل","ليه بغير بكتر"],"title":"الغيرة الصحية والمرضية","category":"الغيرة","subcategory":"تمييز","keywords":["غيرة","غيرة صحية","غيرة مرضية","شك","تحكم","متابعة","هاتف"],"short_answer":"الغيرة الصحية نباهة لحماية العلاقة، مؤقتة وعقلانية. المرضية استحواذ، شك دائم، مراقبة، وتجريد الشريك من حريته.","answer":"ليست كل غيرة ضارة. التمييز:\n\nالغيرة الصحية:\n• نباهة لما يوجد مبرر حقيقي\n• تُعبَّر عنها بهدوء\n• تختفي بالحوار والتطمين\n• تحترم الشريك\n• نادرة\n\nالغيرة المرضية:\n• شك دائم بلا دليل\n• مراقبة (هاتف، موقع، مواعيد)\n• استجوابات وتحقيقات\n• تقييد حركة الشريك\n• عزل الشريك عن أهله وأصدقائه\n• تستفسر وتغضب دون تبرير\n• تتصاعد مع الزمن\n\nالغيرة المرضية غالبًا ناتجة عن قلة تقدير ذات، خوف من الفقد، أو تجارب سابقة. صاحبها يعاني قبل أن يعاني شريكه. وهي قد تدمر ما تخاف فقدَه فعلًا.","practical_steps":["ميّز: هل لديك دليل أم خوف؟","عبّر عن خوفك بـ«أنا» لا اتهام («أشعر بالخوف»)","لا تراقب هاتف شريكك — يهدم الثقة","اعمل على تقدير ذاتك بدل التحكم بالشريك","اطلب علاجًا نفسيًا للغيرة المرضية"],"common_mistakes":["تبرير المراقبة بـ«حب واهتمام»","الخلط بين الغيرة ودليل الحب","استجواب الشريك دون دليل","عزل الشريك عن أهله وأصدقائه"],"when_to_seek_help":"لو غيرتك تتحكم بك، تسبب خلافات متكررة، أو تدفعك لمراقبة شريكك، فالعلاج النفسي فعّال جدًا.","related_questions":["إزاي أبطل غيرة","ليه بغير بكتر","علامات العلاقة السامة"],"risk_level":"medium","language":"mixed","tags":["غيرة","تمييز","علاقة"]},{"id":"jealousy-how-to-stop","question":"كيف أتخلص من الغيرة المرضية؟","alternative_questions":["إزاي أبطل غيرة","غيرتي بتفسد علاقتي إيه الحل","ما ابطلش أراقبه إزاي","غيرة قوية إزاي أتحكم فيها"],"title":"التخلص من الغيرة المرضية","category":"الغيرة","subcategory":"العلاج","keywords":["علاج غيرة","تخلص غيرة","مراقبة","شك","ثقة","تحكم","غيرة مفرطة"],"short_answer":"تخلص الغيرة يبدأ ببناء تقدير ذاتك، اختبار افتراضات الشك، إيقاف سلوك المراقبة، وطلب علاج نفسي للجذور.","answer":"الغيرة المرضية لا تُعالج بمراقبة أكثر — كلما راقبت زاد قلقك. الحل عكسي:\n\n1) اعترف — غيرتك مرضية وتؤذيك وعلاقتك.\n2) اختبر الافتراضات — «تأخره يعني الخيانة؟» هل دليل؟\n3) أوقف المراقبة — كل مراقبة تجدد القلق. الهاتف يهدم الثقة.\n4) عبّر عن احتياجك بـ«أنا» — «أحتاج طمأنة» لا «أنت تخونني».\n5) بناء تقدير ذاتك — الغيرة تعكس شعورًا بعدم الكفاية.\n6) علاج نفسي — للجذور (تجارب، تقدير ذات).\n\nالغيور لا يحمي علاقته بل يدمرها. كلما قللت مراقبة الآخر، ازددت ثقة به وبنفسك.","practical_steps":["حدد موعدًا لمراجعة الهاتف وقلّله تدريجيًا حتى صفر","اختبر كل افتراض شك: ما الدليل؟","عبّر عن احتياجك بوضوح بدل الاستجواب","استثمر في هواية أو هدف يبني ثقتك بنفسك","اطلب علاجًا نفسيًا متخصصًا في الغيرة"],"common_mistakes":["متابعة كل تفاصيل شريكك (تزيد القلق)","اتهام الشريك دون دليل","اعتبار الغيرة دليل حب","تأجيل العلاج حتى تنهي العلاقة"],"when_to_seek_help":"الغيرة المرضية قابل للعلاج بفاعلية كبيرة عبر العلاج المعرفي السلوكي. لا تتأخر — العلاج ينقذ علاقتك ويريحك.","related_questions":["الغيرة الصحية والمرضية","إزاي أبني الثقة","علامات العلاقة السامة"],"risk_level":"medium","language":"mixed","tags":["غيرة","علاج","ثقة"]},{"id":"marriage-building-strong","question":"كيف أبني زواجًا قويًا؟","alternative_questions":["إزاي أنجح في زواجي","إيه أسرار الزواج السعيد","إزاي أحمي علاقتي الزوجية","علاقتنا بتراجعت إيه الحل"],"title":"بناء زواج قوي","category":"الزواج","subcategory":"أسس الزواج","keywords":["زواج","زواج سعيد","علاقة زوجية","نجاح الزواج","استقرار","مودة","شراكة"],"short_answer":"الزواج القوي يُبنى على الصداقة، الحوار المنتظم، التقدير المتبادل، الوقت الثنائي، والحفاظ على كل منكما لهويته.","answer":"أبحاث الزواج (مثل جون جوتمان) حددت عوامل النجاح:\n\n• الصداقة أولًا — معرفة دقيقة باهتمامات شريكك وتقديره.\n• الحوار المنتظم — حديث يومي خالص ولو 15 دقيقة.\n• حل الخلافات باحترام — لا ازدراء ولا تجاهل.\n• التقدير العلني والخاص.\n• وقت ثنائي منتظم بلا أطفال وشاشات.\n• الحفاظ على هوية كل طرف (اهتمامات، أصدقاء).\n• توقعات واقعية — الزواج عمل مستمر لا قصة خيالية.\n\nمؤشرات الخطر الأربعة (جوتمان): النقد، الازدراء، الدفاعية، التجاهل. وجودها يستدعي تدخلًا.","practical_steps":["خصص وقتًا ثنائيًا أسبوعيًا خالصًا بلا أطفال وشاشات","تعلم لغة حب شريكك وخاطبه بها","حلّ الخلافات بالحوار لا التهديد بالطلاق","اعرض تقديرك له علنًا وأكثر خاصًا","حافظ على هواياتك وعلاقاتك خارج الزواج"],"common_mistakes":["تأجيل الحوار انتظارًا لتحسّن تلقائي","الخلط بين الحب الشعوري والالتزام","إهمال الوقت الثنائي بعد الأطفال","استخدام التهديد بالطلاق في الخلافات"],"when_to_seek_help":"لو ظهرت أنماط مؤذية (نقد، ازدراء، تجاهل) باستمرار، فالاستشارة الزوجية مبكرة فعّالة جدًا.","related_questions":["إزاي أحل خلافاتي مع شريكي","لغات الحب إيه","إزاي أحسّن التواصل الزوجي"],"risk_level":"low","language":"mixed","tags":["زواج","علاقة","نجاح"]},{"id":"marriage-conflict-resolution","question":"كيف أحلّ خلافاتي مع شريكي؟","alternative_questions":["إزاي أحل مشكلة مع شريكي","دائماً نتخانق إيه الحل","خلافاتي معاه بتكبر إزاي أوقفها","نقاش بيوصل لمشاكل إزاي أنقاش صح"],"title":"حل الخلافات الزوجية","category":"الزواج","subcategory":"حل الخلافات","keywords":["خلافات زوجية","نزاع","نقاش","حوار","مشكلات زواج","تسوية"],"short_answer":"حل الخلاف يبدأ بالاستماع قبل الرد، التركيز على المشكلة لا الشخص، تجنّب الكلمات المطلقة، والبحث عن حل مشترك لا انتصار.","answer":"الخلافات جزء طبيعي من الزواج — حتى أسعد الأزواج يختلفون. الفرق في كيفية الحل:\n\nقواعد الحوار الصحي:\n\n1) استمع قبل أن ترد — كرّر ما فهمته («أعني أنك...»).\n2) ركّز على المشكلة لا الشخص («هذه العادة تزعجني» لا «أنت دائمًا...»).\n3) تجنّب الكلمات المطلقة («دائمًا»، «أبدًا»).\n4) استخدم «أنا» لا «أنت» («أشعر» لا «أنت تفعل»).\n5) خذ استراحة إن اشتعل الغضب (20 دقيقة+) ثم عُد.\n6) ابحث عن حل وسط لا انتصار.\n7) لا تجمع خلافات سابقة في نقاش واحد.\n\nالأخطر: الازدراء (السخرية، لفظ الإهانة). هو أعظم مؤشر على فشل الزواج. تجنّبه.","practical_steps":["اتفقا على «قواعد خلاف»: لا صراخ، لا شتائم، لا هجر","خذ استراحة 20 دقيقة إن اشتعل الغضب","استمع كاملًا قبل أن ترد","ركّز على حل واحد لكل خلاف","اقترح حلًا واطلب مقترح شريكك"],"common_mistakes":["الرد أثناء كلام الشريك","جمع خلافات سابقة في نقاش واحد","استخدام الازدراء والسخرية","التهديد بالطلاق أو الهجر في الخلاف"],"when_to_seek_help":"لو الخلافات متكررة بلا حل، أو تصل للإيذاء اللفظي/الجسدي، فالاستشارة الزوجية فعّالة.","related_questions":["إزاي أتكلم مع شريكي من غير عصبية","الإساءة اللفظية إيه","علامات الزواج المضطرب"],"risk_level":"medium","language":"mixed","tags":["خلافات","زواج","حوار"]},{"id":"marriage-intimacy-decline","question":"لماذا تتراجع العلاقة الحميمة بعد الزواج؟","alternative_questions":["العلاقة الحميمة بعد الجواز قلت","إحساسه نحوي اتغير بعد الجواز","مش عايز يقرب مني ليه","الفرق قبل وبعد الجواز في القرب"],"title":"تراجع القرب الحميم","category":"الزواج","subcategory":"القرب","keywords":["قرب حميم","علاقة جنسية","تراجع رغبة","زواج","قرب جسدي","ود","هوى"],"short_answer":"تراجع القرب شائع نتيجة الضغوط والإرهاق والروتين. يعالج بالحوار الصريح، تجديد العلاقة العاطفية، وطلب مساعدة مختصة إن لازم.","answer":"تراجع القرب بعد فترة من الزواج طبيعي وليس بالضرورة علامة فشل. أسبابه:\n\n• ضغوط (عمل، أطفال، مالية)\n• إرهاق وقلق نوم\n• خلافات غير محلولة\n• اختلاف في الرغبة بين الشريكين\n• روتين وملل\n• مشاكل صحية أو هرمونية\n• أدوية (بعضها يخفض الرغبة)\n\nما يساعد:\n• حوار صريح بلطف (لا ضغط ولا اتهام)\n• إعادة بناء القرب العاطفي قبل الجسدي\n• جدولة وقت ثنائي (ليس رومانسيًا دائمًا، لكن مضمون)\n• تجديد الروتين والأنشطة المشتركة\n• فحص طبي لاستبعاد أسباب صحية\n• استشارة متخصصة إن طال التراجع\n\nالقرب الحميم جزء من العلاقة وليس كلها، لكنه مؤشر على صحتها العامة.","practical_steps":["تحدّث بلطف عن احتياجك دون ضغط","أعد بناء القرب العاطفي (حديث، وقت مميز)","جدول وقتًا ثنائيًا منتظمًا","جربا نشاطًا جديدًا معًا شهريًا","استشر مختصًا زوجيًا إن طال التراجع"],"common_mistakes":["الضغط أو الإلحاح (يزيد النفور)","تفسير التراجع كرفض شخصي","إهمال القرب العاطفي والتركيز على الجسدي فقط","الخجل من طلب مساعدة متخصصة"],"when_to_seek_help":"لو التراجع مستمر ويسبب ضيقًا لأحدكما، فاستشارة زوجية (أو طبية لاستبعاد أسباب صحية) مفيدة جدًا.","related_questions":["إزاي أحسّن التواصل مع شريكي","الوحدة داخل الزواج","إزاي أبني زواجًا قويًا"],"risk_level":"medium","language":"mixed","tags":["قرب","زواج","علاقة حميمة"]},{"id":"engagement-red-flags","question":"ما العلامات الحمراء في فترة الخطوبة؟","alternative_questions":["إيه علامات الخطر في الخطوبة","خاطبي بيتحكم إيه الحل","إمتى أكسر الخطوبة","علامات تحذيرية قبل الجواز"],"title":"العلامات الحمراء في الخطوبة","category":"الخطوبة","subcategory":"اختيار","keywords":["علامات حمراء","خطوبة","اختيار شريك","تحذير","خطر قبل الزواج","علاقة سامة"],"short_answer":"علامات حمراء: التحكم، الغيرة المرضية، العنف اللفظي، الكذب، رفض الحدود، الإهانة. لا تأمل أن يصلحها الزواج.","answer":"الخطوبة فترة تعارف جاد — راقب السلوك لا الوعود. علامات تستدعي إعادة نظر جذرية:\n\n• التحكم في ملابسك، أصدقائك، هاتفك\n• الغيرة المرضية والمراقبة\n• الإهانة أو السخرية (خصوصًا أمام الآخرين)\n• العنف اللفظي أو الجسدي ولو مرة\n• الكذب المتكرر\n• رفض حدودك («مبالغ»)\n• إلقاء اللوم دائمًا عليك\n• عدم الاحترام لأهلك أو من هم أضعف منه\n• إخفاء أمور جوهرية (ديون، علاقات، صحة)\n\nالقاعدة الذهبية: ما تراه في الخطوبة يزداد بعد الزواج. الزواج لا يصلح الشخص، بل يكشفه. لا تأمل أن يتغير بعد الزواج — العكس هو الصحيح. إن رأيت علامة حمراء واضحة، لا تتجاهلها بدافع الحب أو الضغط العائلي.","practical_steps":["راقب كيف يعامل النوادل والبائعين (كيف سيعاملك لاحقًا)","لاحظ كيف يتعامل مع الرفض أو الخلاف","اسأل عن تاريخ علاقاته بصراحة","لا تتجاهل حشرة في معدتك — اكتشف سببها","استشر أهل تثق بهم قبل القرار النهائي"],"common_mistakes":["الأمل في تغيير الشخص بعد الزواج","تجاهل العلامات بدافع الحب أو العمر","الضغط العائلي يقبل بمن لا يناسبك","الخلط بين الهيام الأولي والمعرفة الحقيقية"],"when_to_seek_help":"لو في شك جوهري، استشر مستشارًا أسريًا أو نفسيًا محايدًا قبل القرار. القرار الصعب قبل الزواج أهون من الطلاق بعده.","related_questions":["إزاي أختار شريك حياتي","إيه العلاقة السامة","الحدود النفسية إيه"],"risk_level":"high","language":"mixed","tags":["خطوبة","علامات حمراء","اختيار"]},{"id":"engagement-getting-to-know","question":"ما الأسئلة المهمة في فترة الخطوبة؟","alternative_questions":["إيه أتسأله في الخطوبة","أسئلة مهمة قبل الجواز","إزاي أعرف شريكي صح","موضوعات لازم نتفق عليها قبل الجواز"],"title":"أسئلة فترة الخطوبة","category":"الخطوبة","subcategory":"المعرفة","keywords":["أسئلة خطوبة","معرفة الشريك","قبل الزواج","توافق","قيم","أهداف"],"short_answer":"ناقشا: القيم، الأهداف، الأطفال، المال، الأهل، الدين، حدود الخلافات. التوافق في الأساسيات أهم من التوافق في الذوق.","answer":"الخطوبة فترة استكشاف جاد، لا مجرد إعداد للفرح. مجالات أساسية:\n\n• القيم والدين: ما الأهم في حياتكما؟ ما العبادات والتقاليد؟\n• الأهداف: أين تريدان أن تكونا بعد 5 و10 سنوات؟\n• الأطفال: عدد، تربية، تعليم، أدوار كل طرف.\n• المال: من ينفق؟ كيف تُدار؟ حساب مشترك أم منفصل؟ ديون؟\n• الأهل: دورهم في حياتكما؟ حدود تدخلهم؟\n• العمل: طموح، انتقال، سفر، عمل المرأة.\n• الخلافات: كيف تحلونها؟ ما المسموح والممنوع؟\n• الحدود: خصوصية، أصدقاء، أنشطة منفردة.\n• الماضي: علاقات سابقة، صحة، عائلة.\n• التوقعات: ما الذي تتوقعه من الشريك؟\n\nلا تتجنّبا المواضيع الصعبة خوفًا من الخلاف — اكتشاف الاختلاف قبل الزواج فرصة.","practical_steps":["خصصا جلسات منتظمة للحوار الجاد (لا فقط خرجات)","اكتب كل ما هو غير قابل للتفاوض بالنسبة لك","ناقشا سيناريوهات (مرض، فقد عمل، انتقال)","لا تخف من كسر الخطوبة إن اكتشفت عدم توافق جوهري","استشيرا مستشارًا أسريًا إن لزم"],"common_mistakes":["تأجيل المواضيع الصعبة خوفًا من الخلاف","افتراض التوافق دون نقاش صريح","التركيز على الفرح وتجاهل الزواج","تجاهل خلافات في القيم الجوهرية"],"when_to_seek_help":"استشارة ما قبل الزواج (premarital counseling) فعّالة جدًا لاكتشاف نقاط الخلاف وبناء أساس صحي.","related_questions":["إزاي أختار شريك حياتي","العلامات الحمراء في الخطوبة","إزاي نحل خلافاتنا مستقبلًا"],"risk_level":"low","language":"mixed","tags":["خطوبة","أسئلة","معرفة"]},{"id":"choosing-partner-criteria","question":"كيف أختار شريك حياتي؟","alternative_questions":["إزاي أختار شريك حياتي الصح","معايير اختيار الشريك","إيه المهم في اختيار الزوج/الزوجة","ليه بختار غلط دايماً"],"title":"معايير اختيار الشريك","category":"اختيار شريك الحياة","subcategory":"المعايير","keywords":["اختيار شريك","معايير","زواج","توافق","قيم","شخصية","شريك حياة"],"short_answer":"اختر بناءً على التوافق في القيم، الاحترام، قدرة حل الخلافات، الاستقرار العاطفي. الجاذبية مهمة لكنها لا تكفي.","answer":"معايير جوهرية للتوافق (أبحاث علم النفس):\n\n1) القيم المشتركة — الدين، الأخلاق، رؤية الحياة. الأهم.\n2) الاحترام — كيف يتحدث عنك وعن الآخرين؟\n3) حل الخلافات — هل يحاور أم يهجم؟ هل يلوم أم يتحمل مسؤولية؟\n4) الاستقرار العاطفي — هل يتحكم في انفعالاته؟\n5) الموثوقية — يفي بالوعود، صادق.\n6) الأهداف المشتركة — أطفال، مهنة، مكان الإقامة.\n7) التوافق في نمط الحياة — إنفاق، اجتماعية، دين.\n8) الدعم — هل يدعم نموك؟\n\nما يخدع: الهيام الأولي، الجاذبية فقط، «سأصلحه»، الضغط العائلي، الخوف من العمر.\n\nما يدوم: الصداقة، الاحترام، التوافق في القيم. اختر من تحترمه قبل من تحبه.","practical_steps":["اكتب قائمة قيمك غير القابلة للتفاوض","راقب سلوكه في مواقف ضغط (تأخر، خطأ، خلاف)","اسأل عن علاقاته السابقة وكيف انتهت","لاحظ كيف يعامل أهله ومن هم أضعف منه","استشر أهل تثق بهم قبل القرار"],"common_mistakes":["الاختيار بدافع الهيام فقط","الأمل في تغيير الشخص بعد الزواج","تجاهل العلامات الحمراء بدافع العمر","الضغط العائلي يقبل بمن لا يناسبك"],"when_to_seek_help":"إن تكرر اختيارك لشركاء غير مناسبين، فالعلاج النفسي يكشف أنماطك الجذرية. استشارة ما قبل الزواج مفيدة لأي شخص.","related_questions":["علامات الخطر في الخطوبة","إيه القيم المشتركة","ليه بختار شركاء سامة"],"risk_level":"low","language":"mixed","tags":["اختيار","شريك","معايير"]},{"id":"communication-assertive","question":"كيف أتحدث بوضوح دون عدوان أو انسحاب؟","alternative_questions":["إزاي أتكلم بثقة","ما بقدرش أعبّر عن نفسي إزاي","التواصل الواثق إزاي","أنا سلبى في الكلام إزاي أتغير"],"title":"التواصل الواثق","category":"التواصل","subcategory":"التأكيدية","keywords":["تأكيدية","تواصل واثق","assertive","تعبير","حدود","ثقة","كلام"],"short_answer":"التواصل الواثق بين العدواني والسلبي: تعبّر عن احتياجاتك ورأيك بصدق واحترام، دون إلحاق ولا انسحاب.","answer":"ثلاثة أنماط تواصل:\n\n• السلبي: تكبت رأيك خوفًا من الصراع. تشعر بالإهانة الداخلية.\n• العدواني: تفرض رأيك بإيذاء. تكسب الموقف تخسر العلاقة.\n• الواثق (المثالي): تعبّر بصدق واحترام، تحترم نفسك والآخر.\n\nقواعد الواثق:\n• استخدم «أنا» لا «أنت» («أنا أشعر» لا «أنت تفعل»)\n• كن محددًا («عندما تأخرت شعرت بـ...» لا «أنت دائمًا...»)\n• ركّز على المشكلة لا الشخص\n• احترم حق الآخر في الاختلاف\n• قل «لا» بلطف دون تبرير مفرط\n• حافظ على نبرة هادئة ولغة جسد مفتوحة\n\nالواثق لا يرضي الجميع، لكنه يحترم نفسه وعلاقاته.","practical_steps":["تدرب على صيغة «أنا»: «أشعر... عندما... أحتاج...»","قبل الرد، خذ نفسًا واختر كلماتك","ميّز بين الرأي والحقيقة («أرى» لا «هذا كذا»)","تدرّب على قول لا في مواقف صغيرة","راقب لغة جسدك (وقوف، تواصل بصري)"],"common_mistakes":["الخلط بين الواثق والعنيد","تأجيل التعبير حتى ينفجر في عدوانية","اعتبار اللطف ضعفًا","التركيز على الفوز في النقاش لا الحل"],"when_to_seek_help":"لو تجد صعوبة مستمرة في التعبير عن نفسك، أو تتراجع دائمًا خوفًا من الصراع، فالعلاج النفسي يساعد.","related_questions":["إزاي أقول لا من غير ذنب","الحدود النفسية إيه","إزاي أحل خلافات"],"risk_level":"low","language":"mixed","tags":["تواصل","تأكيدية","ثقة"]},{"id":"communication-active-listening","question":"كيف أستمع جيدًا لشريكي؟","alternative_questions":["إزاي أسمع كويس","أنا بقطع الكلام إزاي أبطل","الاستماع الفعال إزاي","شريكي بيشكى إني مش بسمعه"],"title":"الاستماع الفعّال","category":"التواصل","subcategory":"الاستماع","keywords":["استماع","استماع فعال","انتباه","تواصل","تفهم","حوار","presence"],"short_answer":"الاستماع الفعّال: حضور كامل، عدم مقاطعة، إعادة صياغة ما فهمته، السؤال دون افتراض، والتعاطف قبل الحل.","answer":"أغلب الناس تنتظر دورها للحديث لا تستمع. الاستماع الفعّال مهارة:\n\n• ضع هاتفك جانبًا، تواصل بصري\n• لا تقاطع — اترك فراغًا بعد كلامه\n• أعد صياغة ما فهمته («أعني أنك تشعر بـ...»)\n• اسأل دون افتراض («ماذا حدث بعد؟»)\n• لا تقفز للحلول — التعاطف أولًا\n• لا تحكم («مبالغ»)، افهم وجهة نظره\n• لاحظ لغة جسده (قد تقول أكثر من كلماته)\n\nالاستماع لا يعني الموافقة. يعني «أسمعك وأفهمك». هذا ما يحتاجه أغلب الناس قبل أي حل.\n\nخطأ شائع: تقديم حلول غير مطلوبة. اسأل «هل تريد حلًا أم تريد أن أسمعك فقط؟».","practical_steps":["ضع هاتفك جانبًا عند أي حوار مهم","لا تقاطع — عدّ إلى 3 بعد كلامه","أعد صياغة: «يعني أنك... هل فهمت؟»","اسأل: «هل تريد حلًا أم أسمعك؟»","لا تقلل من مشاعره («مش كبير»)"],"common_mistakes":["تقديم حلول غير مطلوبة","مقاطعة لتصحيح وقائع","التحضير للرد بدل الاستماع","الحكم على المشاعر"],"when_to_seek_help":"لو التواصل بينكما متوقف رغم المحاولة، فاستشارة زوجية أو أسرية فعّالة.","related_questions":["إزاي أتكلم بوضوح","إزاي أحل خلافات","لغات الحب إيه"],"risk_level":"low","language":"mixed","tags":["استماع","تواصل","حوار"]},{"id":"conflict-healthy-rules","question":"ما قواعد الخلاف الصحي؟","alternative_questions":["إزاي نتخانق صح","قواعد الخلاف في العلاقة","الخلاف الصحي إزاي","إمتى الخلاف يكون مضر"],"title":"قواعد الخلاف الصحي","category":"حل الخلافات","subcategory":"قواعد","keywords":["خلاف صحي","قواعد خلاف","نزاع","نقاش","علاقة","حوار","خلاف بني"],"short_answer":"الخلاف الصحي: ركز على المشكلة لا الشخص، استراحة عند الغضب، لا ازدراء ولا هجر، هدف الحل لا الانتصار، وانهِ الخلاف لا تتركه معلقًا.","answer":"الخلافات صحية — تكشف الاختلافات وتفتح حوارًا. الفرق بين الصحي والمضر في القواعد:\n\nالصحي:\n• ركّز على المشكلة لا الشخص\n• استراحة 20 دقيقة عند الغضب، ثم عُد\n• لا ازدراء (سخرية، إهانة)\n• لا هجر أو تهديد\n• استخدم «أنا» لا «أنت»\n• حل خلاف واحد في كل مرة\n• ابحث عن حل وسط لا انتصار\n• اعتذر حين تخطئ\n• انهِ الخلاف (لا تتركه معلقًا)\n\nالمضر (مؤشرات جوتمان للطلاق):\n• النقد («أنت دائمًا...»)\n• الازدراء (السخرية، الإهانة)\n• الدفاعية (إلقاء اللوم)\n• التجاهل (الصمت الجارح)\n\nلو تكررت الأنماط المضرة، فالاستشارة مبكرة فعّالة.","practical_steps":["اتفقا على قواعد خلاف قبل حدوثها","حدد كلمة سلام للاستراحة («لنتوقف الآن»)","استرح 20 دقيقة ثم عُد للحوار","ركّز على مشكلة واحدة فقط","اعتذر وامنح الصفح بعد الحل"],"common_mistakes":["الاستمرار في النقاش أثناء الغضب","جمع خلافات سابقة في نقاش واحد","الازدراء والسخرية","التهديد بالطلاق أو الهجر"],"when_to_seek_help":"لو الخلافات متكررة بلا حل، أو تصل للإيذاء، فالاستشارة الزوجية فعّالة جدًا.","related_questions":["إزاي أحل خلافاتي الزوجية","الإساءة اللفظية إيه","التواصل الواثق إزاي"],"risk_level":"medium","language":"mixed","tags":["خلاف","علاقة","حوار"]},{"id":"conflict-anger-during","question":"كيف أتحكم في غضبي أثناء الخلاف؟","alternative_questions":["أنا بعصب في النقاش إزاي أهدى","غضبي بيخرب العلاقة إيه الحل","إزاي ما اشتعلش وقت الخناق","بقول حاجات أندم عليها إزاي أتحكم"],"title":"التحكم في الغضب أثناء الخلاف","category":"حل الخلافات","subcategory":"إدارة الغضب","keywords":["غضب","خلاف","عصبية","انفعال","تحكم","تهدئة","نقاش"],"short_answer":"لا تناقش وأنت غاضب — استرح 20 دقيقة ولو غادرت الغرفة. التنفس البطيء، تهدئة الجسد، ثم العودة للحوار بهدوء.","answer":"الغضب يفعّل الدماغ الانفعالي ويطفئ المنطقي — لا تناقش وأنت فيه. ما يحدث أثناء الغضب يندم عليه لاحقًا.\n\nخطة اللحظة:\n\n1) لاحظ علامات الغضب (تسارع قلب، توتر عضلات) مبكرًا.\n2) اطلب استراحة: «أنا غاضب، أحتاج 20 دقيقة».\n3) غادر المكان، تنفس ببطء، امشِ.\n4) لا تفكر في الرد — ركّز على التنفس والهدوء.\n5) عُد بعد هدوء الجسد (20 دقيقة على الأقل).\n6) ابدأ بالحوار بهدوء: «ما الذي أزعجني هو...».\n\nالكلمة السرية للزوجين: اتفقا على كلمة سلام تستدعي الاستراحة فورًا دون اعتبارها هروبًا.\n\nهذا مهارة تتعلمها بالتدريب، لا طبع.","practical_steps":["اتفق مع شريكك على كلمة سلام للاستراحة","تعلم علامات غضبك المبكرة (تنفس، توتر)","تنفّس ببطء: شهيق 4، زفير 6 لمدة دقيقتين","امشِ أو اغسل وجهك بماء بارد","عُد للحوار فقط بعد هدوء جسدي حقيقي"],"common_mistakes":["الاستمرار في النقاش أثناء الغضب","القول «أنا هادي» رغم التوتر الجسدي","كسر الاستراحة بالعودة قبل الهدوء","استخدام الاستراحة كعقاب (هجر طويل)"],"when_to_seek_help":"لو غضبك يخرج عن السيطرة، أو يصل للعنف، فالعلاج لإدارة الغضب ضروري وعاجل.","related_questions":["إدارة الغضب إزاي","قواعد الخلاف الصحي","الإساءة اللفظية إيه"],"risk_level":"medium","language":"mixed","tags":["غضب","خلاف","تحكم"]},{"id":"boundaries-what-are","question":"ما هي الحدود النفسية؟","alternative_questions":["يعني إيه حدود نفسية","إزاي أحط حدود مع الناس","أنا مش قادر أقول لا إزاي","إيه معنى الحدود الشخصية"],"title":"الحدود النفسية","category":"الحدود النفسية","subcategory":"مفهوم الحدود","keywords":["حدود نفسية","حدود شخصية","قول لا","استقلال","احترام الذات","خصوصية","assertiveness"],"short_answer":"الحدود النفسية خطوط تحدد وين ينتهي حقك ويبدأ حق غيرك، وتحمي طاقتك وقيمك وعلاقاتك.","answer":"الحدود النفسية قواعد واضحة تحمي نفسك: عاطفيًا وجسديًا ووقتيًا.\n\nأمثلة: حقك ترفض طلبًا يرهقك، تطلب احترام وقتك، ترفض مواضيع حساسة، تحدد متى تتواصل.\n\nالحدود ليست جدران، بل أبواب — تفتحها لمن يحترمها وتغلقها لمن يتجاوز. غيابها يجعلك فريسة للاستغلال، وزيادتها تسبب عزلة. الهدف حد متوازن وواضح.\n\nالحدود السليمة ليست أنانية، بل احترام للذات. من لا يحترم حدودك يعلمك كيف يعاملك.","practical_steps":["حدد قيمك وأولوياتك — ما غير قابل للتفاوض","استخدم صيغة واضحة: «أنا مش قادر دلوقتي»","تدرّب على قول لا في مواقف صغيرة أولًا","لا تبرّر كثيرًا — «لا، مش ينفع» تكفي","لما أحد يتجاوز الحد، ذكّره بهدوء وكرّر"],"common_mistakes":["الشعور بالذنب عند الرفض — رفضك حق","تغيير الحد باستمرار حسب رد فعل الآخر","الحدود كعقاب بدل حماية","انتظار موافقة الآخرين على حدودك"],"when_to_seek_help":"لو تجد صعوبة في تحديد حدود، أو تعيش في علاقة تتجاوزها باستمرار، فالعلاج النفسي فعّال.","related_questions":["إزاي أقول لا من غير ذنب","علامات العلاقة السامة","التواصل الواثق إزاي"],"risk_level":"low","language":"mixed","tags":["حدود","علاقات","تأكيدية"]},{"id":"boundaries-saying-no","question":"كيف أقول لا دون شعور بالذنب؟","alternative_questions":["ما أقدرش أقول لا","بموافق وأنا مجبور إزاي أتغير","حاسس بذنب لما أرفض","إزاي أرفض بذوق"],"title":"قول لا دون ذنب","category":"الحدود النفسية","subcategory":"التأكيدية","keywords":["قول لا","رفض","ذنب","حدود","إرضاء","تأكيدية","assertiveness"],"short_answer":"قول لا حق لا جريمة. لا تبرّر مفرطًا، استخدم صيغًا واضحة، وتذكّر أن رضا الجميع مستحيل.","answer":"صعوبة قول لا غالبًا ناتجة عن:\n• خوف من الرفض أو الصراع\n• ربط القيمة بإرضاء الآخرين\n• تربية على الطاعة المطلقة\n\nقواعد قول لا صحي:\n\n• كن مباشرًا ولطيفًا («لا، شكرًا»)\n• لا تبرّر مفرطًا (التبرير يفتح باب النقاش)\n• لا تعتذر مرة بعد مرة («آسف جدًا...»)\n• لا تؤجل («سأفكر») إن كنت تعرف أنك سترفض\n• اعرض بديلًا إن أردت («لا أستطيع اليوم، لكن الأسبوع القادم»)\n• تقبّل أن البعض لن يعجبه — هذا حقه لا ذنبك\n\nتذكّر: قول نعم لكل شيء تعني قول لا لنفسك ووقتك وصحتك.","practical_steps":["تدرّب على صيغ بسيطة: «لا ينفعني»، «مش قادر»","قبل الرد، اسأل: «هل أريد أم أخاف الرفض؟»","لا تبرّر مفرطًا — التبرير يفتح باب الإقناع","تذكّر: رضا الجميع مستحيل","ابدأ بقول لا في مواقف صغيرة"],"common_mistakes":["التبرير المفرط (يفتح باب النقاش)","تأجيل الرفض («سأفكر») ظنًا أنه أسهل","قول نعم ثم الاعتذار لاحقًا","ربط الذات بإرضاء الآخرين"],"when_to_seek_help":"لو تجد صعوبة مزمنة في قول لا، أو تعيش لإرضاء الآخرين على حساب نفسك، فالعلاج النفسي يساعد.","related_questions":["ما هي الحدود النفسية","إزاي أكون واثق","إزاي أتعامل مع الناس المستغلة"],"risk_level":"low","language":"mixed","tags":["قول لا","حدود","تأكيدية"]},{"id":"toxic-signs","question":"ما علامات العلاقة السامة؟","alternative_questions":["إزاي أعرف العلاقة سامة","حاسس إنه بيتحكم فيا إيه الحل","علامات العلاقة المؤذية","صديقي/شريكي بستغلني إزاي"],"title":"علامات العلاقة السامة","category":"العلاقات السامة","subcategory":"العلامات","keywords":["علاقة سامة","تلاعب","تحكم","إيذاء نفسي","غازلايتنغ","علامات","إساءة"],"short_answer":"علامات العلاقة السامة: التحكم، الإهانة المستمرة، التلاعب النفسي، عزل الضحية، الغيرة المرضية، الازدراء، عدم احترام الحدود.","answer":"العلامات التحذيرية (لا يلزم وجودها كلها):\n\n• التحكم — في ملابسك، أصدقائك، هاتفك، قراراتك\n• الإهانة — نقد جارح، سخرية، خصوصًا أمام الآخرين\n• التلاعب النفسي (Gaslighting) — يجعلك تشك في ذاكرتك وحكمك («لم يحدث»، «مبالغ»)\n• العزل — يبعّدك عن أهلك وأصدقائك\n• الحب المشروط — «إذا فعلت كذا أحبك»\n• عدم احترام حدودك — يتجاوز «لا»\n• إلقاء اللوم دائمًا عليك\n• التهديد بالهجر للسيطرة\n• التذبذب — إساءة ثم اعتذار ثم إساءة (دورة)\n• الغيرة المرضية والمراقبة\n• التصغير من إنجازاتك\n• الشعور بالرهبة من ردة فعله\n\nالإشارة الأهم: كيف تشعر في العلاقة؟ إن كنت في قلق دائم، تمشي على البيض، تفقد قيمتك — هذه علاقة مؤذية.","practical_steps":["اكتب ما يحدث دون تبرير — لتراه بوضوح","تحدّث مع شخص تثق به خارج العلاقة","لا تعزل نفسك — حافظ على علاقاتك الخارجية","حدد ما تقبله وما لا، وراقب احترامه","اطلب مساعدة مختص أو خط مساعدة"],"common_mistakes":["تبرير السلوك («تحت ضغط»، «يحبني»)","العزلة (تسهّل السيطرة)","الأمل في تغيير بدون عمل","الاعتذار للمعتدي (تأثير Gaslighting)"],"when_to_seek_help":"في أي علاقة فيها إيذاء (نفسي أو جسدي)، اطلب مساعدة مختص أو خط مساءة. لا تنتظر — الأنماط تتعمق.","related_questions":["إيه الغازلايتنغ","إزاي أخرج من علاقة سامة","الحدود النفسية إيه"],"risk_level":"high","language":"mixed","tags":["علاقة سامة","تلاعب","إساءة"]},{"id":"toxic-gaslighting","question":"ما هو التلاعب النفسي (Gaslighting)؟","alternative_questions":["إيه الغازلايتنغ","حاسس إني باتجنن في العلاقة","بيخليني أشك في نفسي إيه ده","دائمًا يقول «مفيش حاجة كده» إيه ده"],"title":"التلاعب النفسي (Gaslighting)","category":"العلاقات السامة","subcategory":"تلاعب","keywords":["غازلايتنغ","تلاعب نفسي","إنكار","تشكيك","علاقة سامة","إساءة نفسية"],"short_answer":"الـ Gaslighting أسلوب تلاعب يجعلك تشك في ذاكرتك وحكمك وعقلك، فيصعب عليك الثقة بنفسك والخروج.","answer":"Gaslighting شكل خفي وخطير من الإساءة النفسية. المعتدي ينكر الواقع، فيشك الضحية بنفسه.\n\nأمثلة:\n• «هذا لم يحدث قط» (رغم حدوثه)\n• «مبالغ، تتخيل»\n• «أنت حساس أكثر من اللازم»\n• «كل الناس يرون أنك مخطئ»\n• نقل أقوالك ملفقة\n• إخفاء أشياء ثم إنكارها\n\nالهدف: جعلك تعتمد على حكمه بدل حكمك، فتسهل السيطرة.\n\nعلامات على الضحية:\n• شك دائم في الذاكرة\n• اعتذار دائم\n• صعوبة اتخاذ قرارات بسيطة\n• شعور «كنت مختلفًا قبل هذه العلاقة»\n• تبرير سلوك المعتدي للآخرين\n\nالحل: وثّق الأحداث (كتابة، صور)، لا تعتمد على حكمه، تحدّث لمختص.","practical_steps":["وثّق الأحداث بتواريخها (يمنع التشكيك)","لا تعتمد على حكمه في الأمور المهمة","حافظ على علاقات خارجية تشهد على واقعك","لا تجادل المعتدي — سيصرخ عليك","اطلب مختصًا نفسيًا متخصصًا في الإساءة"],"common_mistakes":["محاولة إقناع المعتدي بالواقع (يزيد التلاعب)","العزلة (تسهّل السيطرة)","الشك في النفس («لعلني مبالغ»)","تأجيل طلب المساعدة"],"when_to_seek_help":"في أي شك في gaslighting، اطلب مختصًا. التلاعب النفسي يترك أثرًا عميقًا يحتاج تعافيًا موجهًا.","related_questions":["علامات العلاقة السامة","إزاي أخرج من علاقة سامة","كيف أعيد الثقة بنفسي"],"risk_level":"high","language":"mixed","tags":["تلاعب","غازلايتنغ","إساءة"]},{"id":"toxic-leaving","question":"كيف أخرج من علاقة سامة؟","alternative_questions":["إزاي أسيب علاقة مؤذية","ما قادرش أتركه رغم إنه بيأذيني","خطوات الخروج من علاقة سامة","ليه بفضل معاه رغم الأذى"],"title":"الخروج من علاقة سامة","category":"العلاقات السامة","subcategory":"الخروج","keywords":["خروج","ترك علاقة","علاقة سامة","تعلق","صدمة","تعافي","حدود"],"short_answer":"الخروج يحتاج خطة (دعم، أمان، مالي)، قرارًا واضحًا، مسافة كاملة، وعلاجًا للجذور التي أبقتك فيها.","answer":"الخروج من علاقة سامة أصعب من دخولها. صعوبته لأن:\n• التعلق والخوف من الوحدة\n• دورة الإساءة/الاعتذار تربك\n• ضعف الثقة بالنفس (نتيجة التلاعب)\n• أمل في التغيير\n\nخطوات الخروج:\n\n1) اعترف — وثّق ما يحدث دون تبرير.\n2) ابنِ دعمًا — أخبر شخصًا تثق به، مختصًا، خط مساعدة.\n3) خطط للأمان — إن كان عنف، خطط مخرج آمن.\n4) استعد استقلالك المالي والمعلوماتي (وثائق).\n5) انقطع تمامًا — لا تواصل، لا متابعة.\n6) تحمَّل الانسحاب — سيكون صعبًا، لكنه يمر.\n7) علاج نفسي — للجذور التي أبقتك (تقدير ذات، صدمات).\n8) أعد بناء حياتك — اهتمامات، علاقات صحية.\n\nلا عودة بعد الخروج. الدورة المتكررة تستهلكك.","practical_steps":["وثّق كل الإساءة (تواريخ، رسائل) قبل المغادرة","أخبر شخصًا تثق به أو خط مساعدة","جهّز مكانًا آمنًا وأموالًا ووثائقك","انقطع تمامًا — لا تواصل ولا متابعة","اطلب مختصًا فور خروجك للتعافي"],"common_mistakes":["العودة بعد كل اعتذار (دورة)","العزلة (تسهّل العودة)","مواجهة المعتدي بنية «إصلاحه»","القفز لعلاقة جديدة فورًا"],"when_to_seek_help":"في أي علاقة فيها إيذاء، اطلب مساعدة فورًا. خطوط مساعدة الإساءة متاحة. المختص يساعدك على الخروج والتعافي.","related_questions":["علامات العلاقة السامة","إيه الغازلايتنغ","إزاي أبني ثقتي بنفسي"],"risk_level":"high","language":"mixed","tags":["خروج","علاقة سامة","تعافي"]},{"id":"confidence-how-to-build","question":"كيف أبني ثقتي بنفسي؟","alternative_questions":["إزاي أزيد ثقتي بنفسي","أنا واثقش في نفسي إزاي أتغير","بناء الثقة بالنفس","عايز أكون واثق إزاي"],"title":"بناء الثقة بالنفس","category":"الثقة بالنفس","subcategory":"بناء","keywords":["ثقة بنفس","بناء ثقة","اعتماد على الذات","ثقة","شجاعة","كفاءة"],"short_answer":"الثقة تُبنى بالأفعال لا بالأقوال: تنجز مهام صغيرة، تفي بوعودك لنفسك، تواجه مخاوف صغيرة، فتتراكم الأدلة على كفاءتك.","answer":"الثقة بالنفس ليست شعورًا تأتي ثم تفعل، بل عكسه — تفعل ثم يأتي الشعور.\n\nمصدر الثقة الحقيقي: أدلة متراكمة على قدرتك. كيف تجمعها:\n\n• أنجز مهام صغيرة بانتظام — كل إنجاز دليل.\n• أفي بوعودك لنفسك — أصغر وعد مهم.\n• واجه مخاوف صغيرة ومتدرّجة.\n• تعلّم مهارة وأتقنها — الكفاءة تولد الثقة.\n• توقّف عن المقارنة بمن سبقك بسنوات.\n• ركّز على تقدمك أنت لا غيرك.\n• تقبّل الفشل كجزء من التعلم.\n• أحط نفسك بأشخاص يدعمون نموك.\n\nالثقة الحقيقية ليست غرورًا ولا ادعاء الكمال. هي «أستطيع المحاولة، وإن فشلت سأتعافى».","practical_steps":["أصغر وعد لنفسك يوميًا والتزم به","تعلم مهارة جديدة وأتقنها خلال شهر","واجه مخاوف صغيرة متدرجة أسبوعيًا","سجّل إنجازاتك الأسبوعية ولو صغيرة","لا تقارن نفسك إلا بنفسك الأمس"],"common_mistakes":["انتظار الثقة قبل الفعل (لا تأتي)","المقارنة المستمرة بالآخرين","ربط الثقة بالمظهر فقط","تجنب كل ما يخيف (يثبت لك أنك عاجز)"],"when_to_seek_help":"لو ضعف الثقة يعطّل حياتك (علاقات، عمل، قرارات)، فالعلاج النفسي فعّال جدًا.","related_questions":["إزاي أبني تقدير ذاتي","كيف أتغلب على الخوف من الفشل","إزاي أبطل جلد ذاتي"],"risk_level":"low","language":"mixed","tags":["ثقة","بناء","كفاءة"]},{"id":"confidence-public-speaking","question":"كيف أتحدث بثقة أمام الناس؟","alternative_questions":["إزاي أتكلم قدام ناس","بخاف أتكلم في اجتماع","عرض تقديمي بخاف إزاي أتغلب","الخوف من التحدث العلني إزاي"],"title":"الثقة في التحدث العلني","category":"الثقة بالنفس","subcategory":"التحدث","keywords":["تحدث علني","عرض","خطابة","خوف اجتماعي","ثقة","اجتماع","presentation"],"short_answer":"الثقة في التحدث مهارة تُكتسب بالتدريب: تحضير جيد، تركيز على الرسالة لا على نفسك، تنفس، وتعرّض متدرّج للجمهور.","answer":"الخوف من التحدث العلني شائع جدًا. يُعالج بالاستعداد والممارسة لا بالانتظار حتى «تزول الخوف».\n\nخطوات:\n\n1) تحضير — اعرف موضوعك جيدًا، أصعب من الجمهور.\n2) ممارسة بصوت عالٍ — أمام مرآة أو صديق.\n3) تركيز على الرسالة لا على نفسك — «ما الذي أحتاج الجمهور لمعرفته؟»\n4) تنفس بطيء قبل وأثناء الحديث.\n5) ابدأ بجمهور صغير وازد تدريجيًا.\n6) تقبّل التوتر البسيط — طبيعي ومحفّز.\n7) لا تطلب الكمال — أخطاء صغيرة لا تُذكر.\n8) سجل نفسك وشاهد نقاط قوتك.\n\nالعظماء في الخطابة كانوا خائفين أولًا. الفرق: تدربوا رغم الخوف.","practical_steps":["تدرّب بصوت عالٍ 3 مرات قبل أي عرض","تخيّل الجمهور صديقًا تشرح له","تنفّس ببطء 5 مرات قبل البدء","ابدأ بحديث لجمهور صغير وازدد","ركّز على رسالتك لا على حكمهم"],"common_mistakes":["حفظ نص حرفيًا (يفقدك عند أي خطأ)","التركيز على نفسك لا على الرسالة","تجنب كل فرصة للتحدث (يعزّز الخوف)","القراءة من شاشة دون تواصل بصري"],"when_to_seek_help":"لو الخوف من التحدث يعطّل دراستك أو عملك، فالعلاج المعرفي السلوكي فعّال جدًا.","related_questions":["إزاي أبني ثقتي بنفسي","الرهاب الاجتماعي إزاي أعالجه","إزاي أتكلم بوضوح"],"risk_level":"medium","language":"mixed","tags":["تحدث","عرض","ثقة"]},{"id":"self-esteem-what-is","question":"ما هو تقدير الذات؟","alternative_questions":["يعني إيه تقدير ذات","فرق التقدير والثقة","إزاي أعرف تقديري لنفسي عالي","تقدير الذات إيه أهميته"],"title":"تقدير الذات","category":"تقدير الذات","subcategory":"مفهوم","keywords":["تقدير ذات","قيمة ذاتية","ثقة","احترام النفس","self-esteem","كفاءة"],"short_answer":"تقدير الذات تقييمك لقيمتك الكلية. يختلف عن الثقة (التي هي في مواقف محددة) بأنه إحساس عام بقيمتك.","answer":"تقدير الذات = كم ترى نفسك ذا قيمة، بغض النظر عن الإنجازات.\n\nالفرق عن الثقة:\n• الثقة: «أستطيع فعل هذا» (مرتبط بموقف)\n• تقدير الذات: «أنا ذو قيمة» (عام)\n\nعلامات تقدير ذات صحي:\n• لا تنتظر إطراء الآخرين لتشعر بقيمتك\n• تقبل النقد دون انهيار\n• تضع حدودًا وتحميها\n• لا تجلد ذاتك على الأخطاء\n• لا تقارن نفسك باستمرار\n• ترضى عن حياتك بشكل عام\n• تقبل المديح دون رفضه\n\nتقدير الذات لا يبنى على المظهر أو الإنجاز وحدهما. يبنى على قبولك لنفسك بكامل نقاط ضعفك وقوتك.","practical_steps":["اكتب 5 صفات قيمة فيك لا علاقة لها بالمظهر","لاحظ متى تجلد ذاتك واختبر صوتك الداخلي","تقبّل المديح دون رفضه («شكرًا» بدل «لا، أنا...»)","ضع حدودًا صغيرة وحمِها","لا تقارن يومك بيوم آخرين على وسائل التواصل"],"common_mistakes":["ربط القيمة بالإنجازات أو المظهر فقط","انتظار إطراء الآخرين للشعور بالقيمة","المقارنة المستمرة بالآخرين","رفض المديح ظنًا أنه تواضع"],"when_to_seek_help":"لو تشعر بانعدام القيمة باستمرار، أو تنتظر الآخرين ليمنحوك قيمتك، فالعلاج النفسي فعّال.","related_questions":["إزاي أبني تقديري","جلد الذات إزاي أبطل","الثقة بالنفس إزاي"],"risk_level":"low","language":"mixed","tags":["تقدير ذات","قيمة","ثقة"]},{"id":"self-esteem-build","question":"كيف أرفع تقديري لذاتي؟","alternative_questions":["إزاي أزيد تقديري لنفسي","حاسس إني بلا قيمة إزاي","عايز أحب نفسي إزاي","تقديري لنفسي واطي إيه الحل"],"title":"رفع تقدير الذات","category":"تقدير الذات","subcategory":"بناء","keywords":["رفع تقدير","حب الذات","قيمة ذات","بناء","احترام النفس","تقدير ذاتي"],"short_answer":"رفع التقدير يبدأ بصوت داخلي رحيم، فعل أشياء تعتز بها، حدود واضحة، وعلاقات تدعم قيمتك لا تنهبها.","answer":"تقدير الذات يُبنى يوميًا بأفعال صغيرة:\n\n1) صوت داخلي رحيم — استبدل جلد الذات بحديث صديق محب. «أخطأت، سأتعلم» لا «أنا غبي».\n\n2) أفعال تتماشى مع قيمك — إن كنت تقدر الصدق، التزم به. إن كنت تقدر الكرم، افعل. التقدير يأتي من الاتساق.\n\n3) إنجازات صغيرة — أهداف يومية قابلة للتحقيق. كل إنجاز دليل على كفاءتك.\n\n4) حدود واضحة — تحميها = تحترم نفسك.\n\n5) علاقات صحية — أحط نفسك بمن يرى قيمتك لا من يقللها.\n\n6) رعاية ذاتك — نوم، غذاء، حركة. جسدك يستحق الرعاية.\n\n7) خدمة — ساعد غيرك. هذا يمنح معنى ويثبت قيمتك.\n\n8) لا مقارنة — رحلتك فريدة. قارن نفسك بالأمس لا بالآخرين.\n\nتقدير الذات ليس غرورًا، بل اعترافًا متوازنًا بقيمتك.","practical_steps":["اكتب 3 صفات تقدرها فيك يوميًا","استبدل صوت الجلد بصوت الصديق الرحيم","حدد هدفًا صغيرًا أسبوعيًا وأنجزه","أحط نفسك بمن يدعم قيمتك","امنح جسدك رعاية (نوم، غذاء، حركة)"],"common_mistakes":["ربط التقدير بإنجازات كبيرة فقط","انتظار الآخرين ليمنحوك القيمة","جلد الذات على جلد الذات (دائرة)","المقارنة بحياة الآخرين على وسائل التواصل"],"when_to_seek_help":"لو تشعر بانعدام القيمة رغم المحاولات، أو تنتظر الآخرين لتعرف قيمتك، فالعلاج النفسي فعّال.","related_questions":["جلد الذات إزاي أبطل","الثقة بالنفس إزاي أبني","إزاي أكون واثق"],"risk_level":"low","language":"mixed","tags":["تقدير ذات","بناء","حب الذات"]},{"id":"self-criticism-how-to-stop","question":"كيف أوقف جلد الذات؟","alternative_questions":["إزاي أبطل أوبخ نفسي","الصوت الداخلي الناقد إزاي أسكته","بجلد نفسي على أي غلطة إيه الحل","ما أبطلش أتهم نفسي"],"title":"إيقاف جلد الذات","category":"جلد الذات","subcategory":"التعامل","keywords":["جلد ذات","صوت ناقد","لوم ذات","انتقاد ذات","self-criticism","جلب ذاتي"],"short_answer":"لا تحارب الصوت الناقد بل خاطبه كصديق رحيم: لاحظه، سمّه، اختبر صحته، واستبدله بحديث لطيف. مع الوقت يخفت.","answer":"الصوت الناقد الداخلي ليس أنت — إنما أصوات استدخلتها (ناقد طفولي، معلم قاسٍ). خطوات تعامله:\n\n1) لاحظه — سمّه حين يظهر («صوت الناقد يتحدث الآن»).\n2) سمّه — أعطه اسمًا («ها هو الناقد»)، يفصلك عنه.\n3) اختبره — «هل هذا صحيح؟ ما الدليل؟» غالبًا مبالغ.\n4) استبدله بحديث صديق رحيم — «ماذا تقول لصديق في نفس موقفك؟» قل لنفسك.\n5) ركّز على الفعل لا الهوية — «أخطأت» لا «أنا فاشل».\n6) تقبّض أنك إنسان — الأخطاء جزء من التعلم.\n\nالهدف ليس إسكات الصوت كليًا (مستحيل)، بل أن يخفت صوته ولا يتحكم بك. مع التدريب يصبح الصوت الرحيم هو الغالب.","practical_steps":["اكتب أفكارك الناقدة واختبر صحتها","سمّ الناقد باسم لتفصلك عنه","اسأل: «ماذا أقول لصديق في موقفي؟» قله لنفسك","ركّز على الفعل: «أخطأت» لا «أنا سيء»","تدرّب يوميًا — التغيير تراكمي"],"common_mistakes":["محاربة الصوت بالقوة (يزيد قوة)","جلد الذات على جلد الذات (دائرة)","تصديق الناقد كأنه حقيقة","توقع نتيجة فورية"],"when_to_seek_help":"لو الصوت الناقد شديد، يستدعي أفكار يأس أو يعطّل حياتك، فالعلاج النفسي (خصوصًا CBT) فعّال جدًا.","related_questions":["تقدير الذات إزاي أبني","الكمالية إزاي أعالج","إزاي أحب نفسي"],"risk_level":"medium","language":"mixed","tags":["جلد ذات","صوت ناقد","رأفة"]},{"id":"perfectionism-what-is","question":"ما هي الكمالية المرضية؟","alternative_questions":["يعني إيه كمالية","أنا كمالي ومضايقني إيه الحل","فرق الكمالية والطموح","بخاف أي غلطة إزاي أهدى"],"title":"الكمالية المرضية","category":"الكمالية","subcategory":"مفهوم","keywords":["كمالية","مثالية","طموح","خوف الخطأ","perfectionism","كمال"],"short_answer":"الكمالية المرضية سعي مستحيل للكمال يربط قيمتك بالخلو من الخطأ. تختلف عن الطموح بأنها تعطّلك لا تدفعك.","answer":"تمييز مهم:\n\nالطموح الصحي:\n• يهدف للتميز ضمن واقع\n• يقبل الخطأ كجزء من التعلم\n• يفرح بالإنجاز\n• يحفّز العمل\n\nالكمالية المرضية:\n• تطلب المستحيل (لا خطأ أبدًا)\n• تربط القيمة الذاتية بالكمال\n• تؤجل العمل «حتى يكتمل»\n• تسبب قلقًا قبل وأثناء وبعد\n• تجعل الإنجاز غير مفرح («كان يمكن أفضل»)\n• تتجنب المهام خوفًا من عدم الإتقان\n\nالجذر غالبًا: قيمة ذات مشروطة («محبوب إن كنت مثاليًا»)، تربية نقدية، مقارنات.\n\nالكمالية لا تجعلك ناجحًا — بل تعيقك. كبار المنجزين يتميزون بالتقدم لا الكمال.","practical_steps":["حدد «جيد بما يكفي» لكل مهمة قبل البدء","تحدّى الفكرة: «ما الأسوأ إن لم يكن مثاليًا؟»","تعلّم إنهاء المهام «غير المكتملة قليلًا»","ركّز على التقدم لا الكمال","احتفل بالإنجاز بدل البحث عن الخطأ"],"common_mistakes":["تبرير الكمالية بـ«الطموح»","تأجيل الإنجاز «حتى يكتمل» (لا يحدث)","ربط القيمة بالخلو من الخطأ","انتقاد الإنجاز بدل الاحتفال به"],"when_to_seek_help":"لو الكمالية تعطّل عملك أو تسبب قلقًا شديدًا أو تأخرًا مزمنًا، فالعلاج النفسي (CBT) فعّال جدًا.","related_questions":["جلد الذات إزاي أبطل","خوف الفشل إزاي","إزاي أبطل تأجيل"],"risk_level":"medium","language":"mixed","tags":["كمالية","طموح","خوف الخطأ"]},{"id":"perfectionism-procrastination","question":"لماذا تسبب الكمالية التأجيل؟","alternative_questions":["أنا كمالي وما ببدأش إزاي","بأجل لأن خايف ميطلعش مظبوط","علاقة الكمالية والتأجيل","ما بقدرش أبدأ لحد ما يبقى مثالي"],"title":"الكمالية والتأجيل","category":"الكمالية","subcategory":"التأجيل","keywords":["تأجيل","كمالية","مماطلة","خوف الخطأ","تسويف","بدء"],"short_answer":"الكمالي يؤجل لأن بدء المهمة يكشف عدم الكمال. الحل: ابدأ بنسخة «سيئة» عمدًا، ثم حسّنها. الإنجاز يخفّض القلق.","answer":"المفارقة: الكمالي يطلب الإتقان لكنه يؤجل. لماذا؟\n\nبدء المهمة = مواجهة احتمال عدم الكمال. التأجيل يحمي من هذه المواجهة مؤقتًا («سأبدأ حين أكون مستعدًا»). لكن الاستعداد التام لا يأتي.\n\nالحل العملي:\n\n1) قاعدة «النسخة السيئة»: ابدأ بمسودة متعمدة رديئة. الهدف: وجود، لا إتقان.\n2) حسّن بعد ذلك — التعديل أسهل من البدء.\n3) حدد وقتًا محدودًا — 25 دقيقة فقط (بومودورو).\n4) قسّم المهمة لخطوات صغيرة جدًا.\n5) تقبّل «جيد بما يكفي» كمعيار.\n6) كافئ نفسك على البدء، لا على الكمال.\n\n«إنجاز 80% اليوم أفضل من 100% لن يأتي أبدًا».","practical_steps":["اكتب مسودة سيئة عمدًا ثم حسّنها","حدد وقتًا قصيرًا (25 دقيقة) للبدء","قسّم المهمة لخطوات صغيرة جدًا","حدد معيار «جيد بما يكفي» قبل البدء","كافئ نفسك على البدء لا على الكمال"],"common_mistakes":["انتظار «الظروف المثالية» للبدء","محاولة الإتقان في المسودة الأولى","ربط قيمتك بنتيجة المهمة","تأجيل البدء حتى «أستعد أكثر»"],"when_to_seek_help":"لو التأجيل المزمن يعطّل دراستك أو عملك، فالعلاج النفسي (CBT) فعّال جدًا.","related_questions":["ما هي الكمالية المرضية","إزاي أوقف جلد الذات","ضغط الدراسة إزاي أدير"],"risk_level":"medium","language":"mixed","tags":["تأجيل","كمالية","بدء"]},{"id":"adolescence-changes","question":"ما التغيرات النفسية في المراهقة؟","alternative_questions":["ابني مراهق ومش فاهمه","ليه بنتي اتغيرت في المراهقة","تغيرات المراهق النفسية","أنا مراهق وحاسس مش فاهم نفسي"],"title":"تغيرات المراهقة النفسية","category":"المراهقة","subcategory":"مفهوم المراهقة","keywords":["مراهقة","تغيرات نفسية","مراهق","بلوغ","هوية","استقلال","عواصف"],"short_answer":"المراهقة فترة تغيرات بيولوجية ونفسية: البحث عن الهوية، الحاجة للاستقلال، تقلب المزاج، تأثير الأقران، وحساسية مفرطة.","answer":"المراهقة ليست «عناد» بل فترة تطور طبيعي. تغيرات نفسية أساسية:\n\n• البحث عن الهوية — «من أنا؟» تجارب، ملابس، مجموعات.\n• الحاجة للاستقلال — تقليل الاعتماد على الأهل، رأي خاص.\n• تأثير الأقران — صديق المراهق أهم من أهله أحيانًا.\n• تقلب المزاج — هرمونات ونضج دماغ (الدماغ الأمامي يكتمل في 25).\n• حساسية مفرطة — نقد بسيط قد يفجر انفعالًا.\n• تجربة حدود — كسر القواعد لاختبارها.\n\nهذه التغيرات ليست تمردًا ضدك شخصيًا، بل تطور طبيعي. المراهق يحتاج حبًا ثابتًا رغم تقلباته، وحدودًا واضحة لطيفة، وحضورًا لا سيطرة.","practical_steps":["استمع أكثر مما تنصح — المراهق يحتاج أذنًا لا حكمًا","حافظ على الحب رغم الخلافات («أحبك ولو اختلفت معك»)","ضع حدودًا واضحة واشرح سببها لا تفرضها","احترم خصوصيته (غرفة، هاتف، يوميات)","لا تسخر من اهتماماته وأحلامه"],"common_mistakes":["اعتبار كل تغير «عنادًا» أو «قلة أدب»","السيطرة المفرطة (تدفع للتمرد)","السخرية من مشاعره («مش كبير»)","مقارنته بإخوته أو بغيره"],"when_to_seek_help":"لو ظهرت علامات: انعزال طويل، تغير حاد في النوم/الأكل، أفكار يأس، أو سلوك خطير، فاطلب مختصًا في المراهقين.","related_questions":["إزاي أتعامل مع مراهق متمرد","ليه مراهقي بيستعزل","كيف أحمي مراهقي من المخاطر"],"risk_level":"low","language":"mixed","tags":["مراهقة","تغيرات","تربية"]},{"id":"adolescence-rebellious","question":"كيف أتعامل مع مراهق متمرد؟","alternative_questions":["ابني مراهق ومش بيسمع","بنتي بتخالف كل القواعد","مراهق متمرد إيه أعمل","مراهقي بيعاند في كل حاجة"],"title":"التعامل مع مراهق متمرد","category":"المراهقة","subcategory":"التربية","keywords":["تمرد","مراهق","عناد","معارضة","تربية","حدود","خلاف"],"short_answer":"التمرد غالبًا طلب استقلال لا عداوة. تعامل بالاستماع، الحدود الواضحة المشروحة، اختيار معاركك، والحب الثابت رفضًا للسلوك لا للشخص.","answer":"التمرد في المراهقة غالبًا صوت يقول: «أريد أن أكون مستقلًا». كيف تتعامل:\n\n• اختر معاركك — ليست كل قاعدة تستحق المعركة. حفاظ على الجوهر (أمان، أخلاق) ومرون في التفاصيل (ملابس، موسيقى).\n• اشرح لا تفرض — «لماذا هذه القاعدة؟» يقلل المقاومة.\n• استمع قبل أن تحكم — غالبًا وراء العناد حاجة لم تُفهم.\n• رفض السلوك لا الشخص — «أحبك، لا أقبل هذا الفعل».\n• حافظ على الحب رغم الخلاف — هذا الأمان الذي يمنعه من الانحراف.\n• شاركه في وضع القواعد — يلتزم بما ساهم فيه.\n• لا تساوم على الأمان (لا قيادة متهورة، لا مخدرات).\n\nالمراهق المتمرد غالبًا يحتاج مزيدًا من الحب لا أقل. التمرد الشديد أحيانًا صرخة «انتبه إليّ».","practical_steps":["اختر معاركك — مرون في التفاصيل، حازم في الجوهر","اشرح سبب القاعدة بدل فرضها","استمع لرأيه قبل أن ترفض","أظهر حبك رفضًا للسلوك لا له","شاركه في وضع قواعد المنزل"],"common_mistakes":["خوض معركة على كل تفصيلة (يستنزف العلاقة)","فرض القواعد دون شرح","العقاب القاسي (يزيد التمرد)","ربط الحب بالطاعة"],"when_to_seek_help":"لو التمرد يصاحبه سلوك خطير (مخدرات، عنف، هروب)، أو انهيار العلاقة كليًا، فاطلب مختصًا في المراهقين.","related_questions":["تغيرات المراهقة النفسية","إزاي أحمي مراهقي","حدود نفسية مع أبنائي"],"risk_level":"medium","language":"mixed","tags":["مراهقة","تمرد","تربية"]},{"id":"children-school-refusal","question":"كيف أتعامل مع رفض طفلي للمدرسة؟","alternative_questions":["بنتي بترفض تروح المدرسة","ابني بيبكي كل صباح قبل المدرسة","خوف الطفل من المدرسة إيه الحل","طفلي بيمثل عشان ما يروحش المدرسة"],"title":"رفض الطفل للمدرسة","category":"الأطفال","subcategory":"المدرسة","keywords":["رفض مدرسة","خوف مدرسة","طفل","فوبيا مدرسة","بكاء صباح","تعب بطن"],"short_answer":"رفض المدرسة غالبًا قلق لا كسل. ابحث عن السبب (تنمر، صعوبة، فراق)، تعاون مع المدرسة، وعرّضه متدرّجًا. لا تتهمه بالتمثيل.","answer":"رفض المدرسة ليس «كسلًا» أو «تمثيلًا». غالبًا قلق له سبب:\n\n• تنمر من أقران\n• صعوبة في مادة أو معلم\n• قلق الفراق (خصوصًا صغار)\n• تغير (انتقال، طلاق، أخ جديد)\n• اضطراب تعلم غير مشخص\n• مشكلة مع صديق\n\nالعلامات الجسدية (ألم بطن، صداع صباحًا) حقيقية — القلق يظهر في الجسم. لا تتهمه بالتمثيل.\n\nالتعامل:\n• استمع بلطف — «ما الذي يزعجك في المدرسة؟»\n• تعاون مع المدرسة لا ضدّها.\n• عرّض متدرّج — ساعة، نصف يوم، يوم.\n• لا تبقه في البيت (يعزّز الرفض).\n• كافئ الحضور لا الغياب.\n• اطلب مختصًا إن استمر.","practical_steps":["اسأل بلطف: «ما الذي يزعجك؟ من يزعجك؟»","تواصل مع المدرسة لمعرفة السبب","عرّضه متدرّجًا (ساعة ثم نصف يوم)","لا تبقه في البيت (يعزّز القلق)","كافئ الحضور لا الغياب"],"common_mistakes":["اتهام الطفل بالتمثيل (الألم الجسدي حقيقي)","إبقاؤه في البيت (يعزّز الرفض)","إجباره بقسوة (يزيد القلق)","إهمال التنمر كسبب محتمل"],"when_to_seek_help":"لو الرفض مستمر أسابيع، أو يصاحبه أعراض جسدية شديدة، أو اكتئاب، فاطلب مختصًا في صحة الأطفال النفسية.","related_questions":["ابني بيتبول ليلاً إيه السبب","كيف أفهم مشاعر طفلي","تنمر على ابني إزاي أساعده"],"risk_level":"medium","language":"mixed","tags":["أطفال","مدرسة","قلق"]},{"id":"children-bedwetting","question":"لماذا يتبول طفلي ليلاً رغم كبره؟","alternative_questions":["ابني بيتبول ليلاً إيه السبب","بنتي 7 سنين وبتتبول بالليل","تبول ليلي عند الأطفال إيه الحل","خايف عليه من الإحراج إزاي أعينه"],"title":"التبول الليلي","category":"الأطفال","subcategory":"مشكلات شائعة","keywords":["تبول ليلي","سلس ليلي","طفل","تبول لا إرادي","enuresis","نوم"],"short_answer":"التبول الليلي شائع حتى سن 7-10، وغالبًا وراثي/نضجي لا نفسي. عوّد على عادات، لا تعاقب، واطلب طبيبًا إن استمر بعد 7.","answer":"التبول الليلي (السلس الليلي) شائع: 15% من الأطفال في 5 سنوات، 5% في 10 سنوات.\n\nأسباب:\n• وراثة (أحد الوالدين كان كذلك غالبًا)\n• تأخر نضج المثانة\n• نوم عميق صعب الاستيقاظ\n• أحيانًا: توتر، تغير، التهاب بول\n\nنقاط مهمة:\n• الطفل لا يفعلها عمدًا — لا تعاقب ولا تُحرّج.\n• غالبًا يتحسن وحده مع الوقت.\n• علامات الطبيب: بعد 7 سنوات، أو أعراض التهاب بول، أو جفاف سابق ثم عودة.\n\nالتعامل:\n• قلل السوائل مساءً.\n• أخرجه للحمام قبل النوم.\n• كافئ الصباحات الجافة.\n• أجهزة إنذار (فعّالة بعد 7 سنوات).\n• لا تناقش الأمر أمام الآخرين.","practical_steps":["قلل السوائل بعد العصر","أخرجه للحمام قبل النوم مباشرة","كافئ الصباحات الجافة بمخطط نجوم","احمِ فراشه ولا تُحرّجه","استشر طبيبًا بعد 7 سنوات أو عند أعراض التهاب"],"common_mistakes":["معاقبة الطفل أو السخرية منه (يزيد المشكلة)","مناقشة الأمر أمام الإخوة أو الضيوف","ربط الأمر بشخصية الطفل («كسلان»)","تأجيل استشارة الطبيب عند علامات الخطر"],"when_to_seek_help":"بعد 7 سنوات، أو إذا عاد بعد جفاف سابق 6+ أشهر، أو مع أعراض التهاب بول (حرقة، تكرار)، فاستشر طبيب أطفال.","related_questions":["رفض الطفل للمدرسة","كيف أفهم مشاعر طفلي","تربية بدون قسوة إزاي"],"risk_level":"low","language":"mixed","tags":["أطفال","تبول ليلي","نوم"]},{"id":"parenting-without-harshness","question":"كيف أربّي بدون قسوة؟","alternative_questions":["إزاي أربّي من غير ضرب","بفقد أعصابي مع أبنائي إزاي أتحكم","تربية بلا عنف إزاي","أنا عصبي مع أولادي إيه الحل"],"title":"التربية بدون قسوة","category":"التربية","subcategory":"أساليب التربية","keywords":["تربية","بلا قسوة","ضرب","عقاب","تأديب","حنان","حدود"],"short_answer":"التربية الفعّالة تجمع الحب والحدود. بدل الضرب: عواقب طبيعية، حرمان مؤقت، حوار. اهدأ قبل التأديب ولا تعاقب وأنت غاضب.","answer":"الضرب لا يعلّم — يخيف. أبحاث كثيرة أظهرت أن الضرب يزيد العدوان، يضعف الثقة، ويضر العلاقة. بدائله:\n\n• عواقب طبيعية — أهمل لعبة؟ تُخزن أسبوعًا.\n• حرمان مؤقت — نشاط ممتع أُلغي (متناسب مع الفعل).\n• جلوس هدّئ — مكان هادئ حتى يهدأ.\n• حوار بعد الهدوء — ما الخطأ؟ ما البديل؟\n• تعزيز الإيجابي — امتدح السلوك الحسن (أقوى من العقاب).\n\nقاعدة ذهبية: لا تعاقب وأنت غاضب. اهدأ أولًا (تنفس، اترك الغرفة)، ثم تعامل بحكمة.\n\nالقسوة ليست حبًا. الطفل الذي يخافك لا يحترمك — يطيعك خوفًا ثم يتمرد حين يكبر. الحب مع الحدود يبني احترامًا داخليًا.","practical_steps":["قبل العقاب: اهدأ (تنفس، اترك الغرفة 5 دقائق)","استبدل الضرب بعواقب طبيعية أو حرمان مؤقت","امتدح السلوك الحسن (أقوى من العقاب)","اشرح سبب العقاب والسلوك البديل","اعتذر حين تخطئ في حق طفلك (يعلمه الاحترام)"],"common_mistakes":["العقاب أثناء الغضب (مبالغ وغير عادل)","الضرب كحل سريع (يضر العلاقة)","التركيز على الأخطاء وتجاهل الإيجابي","التهديد دون تنفيذ (يفقد مصداقيتك)"],"when_to_seek_help":"لو تجد صعوبة في التحكم بغضبك مع أطفالك، أو تخشى إيذاءهم، فالعلاج لإدارة الغضب والتربية ضروري وعاجل.","related_questions":["إزاي أدير غضبي","تربية الطفل على التعلق الآمن","حدود نفسية مع أبنائي"],"risk_level":"medium","language":"mixed","tags":["تربية","حدود","حنان"]},{"id":"parenting-screen-time","question":"كيف أدير وقت الشاشات لأطفالي؟","alternative_questions":["ابني مدمن موبايل إيه الحل","قد إيه شاشة مسموح للطفل","إزاي أقلل شاشات أولادي","بنتي على التابايت طول اليوم"],"title":"إدارة وقت الشاشات","category":"التربية","subcategory":"نمط الحياة","keywords":["شاشات","موبايل","تابلت","طفل","إدمان شاشة","وقت شاشة","تربية رقمية"],"short_answer":"وقت الشاشات محدود بسن الطفل: أقل من سنتين صفر، 2-5 سنة ساعة، أكبر من 6 ساعات محدودة. نوعية المحتوى أهم من الكمية.","answer":"توصيات عامة للأكاديمية الأمريكية لطب الأطفال:\n\n• أقل من 18 شهرًا: لا شاشات (عدا فيديو عائلي).\n• 18-24 شهرًا: محتوى تعليمي عالي الجودة، مع والدين.\n• 2-5 سنوات: ساعة يوميًا كحد أقصى، محتوى جيد، مع والدين.\n• 6+ سنوات: حدود واضحة، لا تطغى على النوم واللعب والدراسة.\n\nنقاط عملية:\n• نوعية المحتوى أهم من الكمية — تعليمي وملائم للعمر.\n• لا شاشات في غرفة النوم ولا أثناء الأكل.\n• توقف قبل النوم بساعة (الضوء الأزرق يؤخر النوم).\n• كن قدوة — طفلك يقلل وقت شاشاتك أنت.\n• شاركه المحتوى — ناقشه.\n• بدائل: لعب، قراءة، نشاط بدني، طبيعة.\n\nلا تحذف الشاشات فجأة — قلّل تدريجيًا وقدم بدائل.","practical_steps":["حدد مناطق بلا شاشات (طاولة طعام، غرفة نوم)","حدد أوقات بلا شاشات (قبل النوم بساعة)","كن قدوة — قلّل شاشاتك أمام طفلك","قدم بدائل جذابة (لعب، رحلات، قصص)","قلّل تدريجيًا لا فجأة"],"common_mistakes":["استخدام الشاشة كمربية (تترك الطفل بها ساعات)","الشاشات في غرفة النوم (تضر النوم)","التناقض — تطلب منه ما تفعله أنت","الحذف المفاجئ (يثير تمردًا)"],"when_to_seek_help":"لو وقت الشاشات يطغى على نوم الطفل أو دراسته أو علاقاته، أو يصاحب انسحاب اجتماعي، فاطلب مختصًا.","related_questions":["تربية بدون قسوة","رفض الطفل للمدرسة","كيف أحمي مراهقي من المخاطر"],"risk_level":"low","language":"mixed","tags":["شاشات","أطفال","تربية رقمية"]},{"id":"study-pressure-managing","question":"كيف أتعامل مع ضغط الدراسة؟","alternative_questions":["أنا طالب ومضغوط إزاي أدير","المذاكرة بتطحني إيه الحل","ضغط الدراسة بيجيبلي قلق","مش قادر أوازن دراستي وحياتي"],"title":"إدارة ضغط الدراسة","category":"ضغط الدراسة","subcategory":"التعامل","keywords":["ضغط دراسة","طالب","مذاكرة","توتر دراسي","قلق امتحانات","إدارة وقت"],"short_answer":"أدر ضغط الدراسة بخطة واقعية، نوم كافٍ، فترات راحة، تقسيم المهام، وطلب مساعدة. لا تضحِّ بصحتك من أجل درجة.","answer":"ضغط الدراسة حقيقي لكنه قابل للإدارة:\n\n• خطة واقعية — قسّم المنهج لأجزاء يومية، لا تنتظر اللحظة الأخيرة.\n• تقنية بومودورو — 25 دقيقة تركيز + 5 راحة.\n• نوم كافٍ — 7-8 ساعات. السهر يضر الذاكرة.\n• حركة — 20 دقيقة يوميًا تخفض القلق.\n• لا تذاكر ساعات متواصلة — العقل يتعب وتقل الفائدة.\n• اطلب مساعدة — معلم، زميل، ولي أمر عند الصعوبة.\n• لا تقارن نفسك — لكل شخص وتيرته.\n• لا تربط قيمتك بدرجاتك — الدرجة ليست أنت.\n\nتذكر: شهادتك مهمة، لكنها ليست أهم من صحتك النفسية. طالب متوازن يتفوق على طالب منهك.","practical_steps":["اصنع خطة أسبوعية واقعية وقسّم المنهج","تقنية بومودورو: 25 دقيقة تركيز + 5 راحة","نم 7-8 ساعات — الذاكرة تُثبّت في النوم","تحرك 20 دقيقة يوميًا لخفض القلق","اطلب مساعدة عند الصعوبة ولا تكابر"],"common_mistakes":["السهر ليلة الامتحان (يضر الذاكرة)","المذاكرة ساعات متواصلة دون راحة","ربط القيمة الذاتية بالدرجات","مقارنة النفس بالمتفوقين باستمرار"],"when_to_seek_help":"لو ضغط الدراسة يسبب قلقًا شديدًا، أرقًا مزمنًا، أو أفكار يأس، فاطلب مختصًا. صحتك أهم من أي امتحان.","related_questions":["توتر الامتحانات إزاي","كمالية وتأجيل إزاي أعالج","إزاي أوقف الأفكار المتسارعة"],"risk_level":"medium","language":"mixed","tags":["دراسة","طلاب","إدارة"]},{"id":"work-pressure-balance","question":"كيف أوازن بين العمل والحياة؟","alternative_questions":["إزاي أوازن شغل وحياة","شغلي بياخد كل وقتي إيه الحل","work-life balance إزاي","مش قادر أفصل شغل عن البيت"],"title":"موازنة العمل والحياة","category":"ضغط العمل","subcategory":"الموازنة","keywords":["موازنة","work-life","عمل","حياة","حدود","وقت عائلة","استرخاء"],"short_answer":"الموازنة ليست توزيعًا متساويًا للوقت، بل حضور كامل لكل مجال. ضع حدودًا واضحة، حدّد أولويات، واحمِ وقتك الشخصي.","answer":"الموازنة ليست 50-50 بين العمل والحياة، بل وجود كامل في كل منهما:\n\n• حدود واضحة — ساعة محددة لإنهاء العمل، لا إيميلات بعدها.\n• فصل مكاني — إن عملت من البيت، ركن خاص، أغلقه بعد العمل.\n• أولويات — 3 مهام مهمة يوميًا، لا قائمة لا تنتهي.\n• وقت عائلة وشخصي محمي كموعد طبي.\n• طقس إغلاق اليوم — نشاط يفصلك عن العمل (مشية، استحمام).\n• لا تجلب العمل للسرير.\n• استراحات قصيرة فعّالة (لا شاشات).\n\nلا أحد في فراش الموت تمنى لو عمل أكثر. لكن لا تضحِّ بطموحك — التوازن وليس الإهمال.\n\nتذكر: عمل لا يتوقف ينتج إرهاقًا لا إنجازًا. الإنتاجية تحتاج راحة.","practical_steps":["حدد ساعة محددة لإنهاء العمل والزمها","أغلق إشعارات العمل بعد وقت محدد","ضع طقسًا يفصل العمل عن البيت (مشية، استحمام)","احمِ وقت عائلة وشخصي كموعد طبي","خذ إجازاتك بالكامل دون ذنب"],"common_mistakes":["الإيميلات بعد ساعات العمل (لا حدود)","العمل من السرير (يربط السرير بالتوتر)","تأجيل الإجازات «حتى يهدى» (لا يهدى)","الفخر بالإرهاق كبطولة"],"when_to_seek_help":"لو بدأت تفقد الاهتمام بالعمل، أو تشعر بإرهاق عميق، أو أثر على علاقاتك — اطلب مختصًا (علامات احتراق نفسي).","related_questions":["إيه الاحتراق النفسي","ضغط العمل المستمر إزاي","إزاي أقول لا في الشغل"],"risk_level":"medium","language":"mixed","tags":["عمل","موازنة","حدود"]},{"id":"burnout-what-is","question":"ما هو الاحتراق النفسي؟","alternative_questions":["يعني إيه برنأوت","إزاي أعرف إني محترق نفسيًا","أنا محترق من الشغل إيه الأعراض","احتراق وظيفي إزاي أعالجه"],"title":"الاحتراق النفسي","category":"الاحتراق النفسي","subcategory":"مفهوم","keywords":["احتراق نفسي","برنأوت","إرهاق مزمن","فقد شغف","عمل","إنهاك"],"short_answer":"الاحتراق النفسي إرهاق مزمن يصاحبه فقدان الشغف، سخرية، وانخفاض إنجاز. نتيجة ضغط طويل دون راحة أو معنى.","answer":"الاحتراق النفسي (Burnout) ليس مجرد إرهاق — متلازمة كاملة بأبعاد ثلاثة:\n\n1) الإرهاق العاطفي — استنزاف، لا طاقة، صعوبة النهوض.\n2) اللامبالاة/السخرية — تباعد عن العمل، فقدان الاهتمام، سخرية.\n3) انخفاض الإنجاز — شعور بعدم الكفاءة رغم العمل.\n\nيختلف عن التعب العادي: لا يخفّ بإجازة قصيرة، يستمر، يزداد.\n\nأسبابه:\n• ضغط عمل مستمر دون راحة\n• غياب السيطرة على العمل\n• مكافأة غير عادلة\n• علاقات عمل سيئة\n• غياب المعنى\n• توقعات غير واقعية\n\nليس ضعفًا — استجابة طبيعية لضغط مطوّل. يتطلب تدخلًا حقيقيًا لا إجازة فقط.","practical_steps":["تعرف الأعراض مبكرًا (إرهاق، لامبالاة، إنجاز منخفض)","خذ إجازة حقيقية (لا عمل فيها)","أعد تقييم ضغط العمل مع مديرك","أعد اكتشاف معنى عملك أو ابحث عن بديل","اطلب مختصًا نفسيًا متخصصًا في الاحتراق"],"common_mistakes":["القول «أنا بس محتاج إجازة» (لا يكفي غالبًا)","الاستمرار رغم الأعراض حتى الانهيار","ربط الاحتراق بضعف الشخصية","تجاهل الأسباب البيئية (عمل سام)"],"when_to_seek_help":"الاحتراق النفسي يستحق علاجًا متخصصًا. لو أعراضه مستمرة، اطلب مختصًا — التأخير يطيل التعافي.","related_questions":["موازنة العمل والحياة","أعراض الاكتئاب","إزاي أدير ضغط الشغل"],"risk_level":"high","language":"mixed","tags":["احتراق","عمل","إرهاق"]},{"id":"anger-management-techniques","question":"كيف أتحكم في غضبي؟","alternative_questions":["إزاي أتحكم في عصبيتي","بعصب بسرعة إيه الحل","أنا غضوب وبيأذي الناس إزاي أتغير","تمارين لإدارة الغضب"],"title":"إدارة الغضب","category":"إدارة الغضب","subcategory":"تقنيات","keywords":["غضب","عصبية","إدارة غضب","تحكم انفعال","تهدئة","انفعال"],"short_answer":"لا تناقش وأنت غاضب: لاحظ علامات الغضب مبكرًا، استرح، تنفس ببطء، ثبّت جسدك، ثم عُد بهدوء. الغضب مهارة تُتعلم لا طبع.","answer":"الغضب عاطفة طبيعية، لكن التحكم فيه مهارة:\n\nخطة اللحظة:\n\n1) لاحظ علاماتك المبكرة — تسارع قلب، توتر عضلات، سخونة وجه.\n2) استرح — «أحتاج دقائق»، اترك المكان.\n3) تنفّس ببطء — شهيق 4، كتم 4، زفير 6 (5 مرات).\n4) ثبّت جسدك — قدم على الأرض، ماء بارد على وجه.\n5) لا تفكر في الرد — ركّز على الهدوء.\n6) عُد بعد هدوء جسدي حقيقي (20+ دقيقة).\n7) عبر عن غضبك بهدوء: «ما أزعجني هو...».\n\nإستراتيجيات طويلة المدى:\n• نم نومًا كافيًا (الإرهاق يقلل التحكم).\n• الرياضة تخفض التوتر المتراكم.\n• تعرّف محفّزاتك (مواقف، أشخاص، أوقات).\n• عالج أسبابك الجذرية (ضغط، خلافات).\n\nالغضب شعور، السلوك اختيار. يمكنك أن تشعر بالغضب دون أن تؤذي.","practical_steps":["تعرف علامات غضبك المبكرة (قلب، عضلات، سخونة)","تنفّس ببطء: شهيق 4، كتم 4، زفير 6","غادر المكان 20 دقيقة قبل العودة","ماء بارد على وجهك يخفض الاستثارة","عبر عن غضبك بهدوء: «ما أزعجني هو...»"],"common_mistakes":["الاستمرار في النقاش أثناء الغضب","كبت الغضب (ينفجر لاحقًا أقوى)","تفريغ الغضب بالعنف (يعزّز النمط)","القول «أنا كده» دون محاولة تغيير"],"when_to_seek_help":"لو غضبك يخرج عن السيطرة، أو يصل للعنف، أو يؤذي علاقاتك، فالعلاج لإدارة الغضب فعّال وضروري.","related_questions":["التحكم في الغضب أثناء الخلاف","التنظيم الانفعالي إزاي","إزاي أهدى جسمي وقت القلق"],"risk_level":"medium","language":"mixed","tags":["غضب","إدارة","تحكم"]},{"id":"grief-stages","question":"ما مراحل الحزن بعد الفقد؟","alternative_questions":["اتوفى لي قريب ومش قادر أتجاوز","مراحل الحزن إيه","ليه حزني بعد الفقد مش بيعدى","إزاي أتعامل مع فقد عزيز"],"title":"مراحل الحزن","category":"الحزن بعد الفقد","subcategory":"الفقد","keywords":["حزن","فقد","وفاة","مراحل الحزن","تعافي","كوبلر روس","حداد"],"short_answer":"الحزن يمر بموجات لا خطوات ثابتة: صدمة، غضب، تفاوض، حزن، قبول. لا ترتيب محتم، وقد تتداخل وتعود.","answer":"نموذج كوبلر-روس للحزن (ليس خطيًا بل موجات):\n\n1) الصدمة/الإنكار — «هذا غير حقيقي». حماية مؤقتة.\n2) الغضب — «لماذا؟» على الله، الأطباء، النفس، المتوفى.\n3) التفاوض — «لو فعلت كذا لما حدث». أفكار «ما لو».\n4) الحزن — ألم عميق، وحدة، بكاء.\n5) القبول — ليس الرضا، بل التسليم بالواقع.\n\nالحقائق المهمة:\n• لا ترتيب محتم — قد تتنقل ذهابًا وإيابًا.\n• موجات — تأتي وتخفّ وتعود، لكنها تقل شدة.\n• مدة متفاوتة — لا جدول ثابت. شهور إلى سنوات طبيعية.\n• لا «تتجاوز» الفقد — تتعايش معه. المتوفى يبقى جزءًا منك.\n\nالحزن دليل الحب. من لم يحزن لم يحب. لكن إن استمر بشدة أشهرًا أو أعاق حياتك، فاطلب مساعدة.","practical_steps":["اسمح لنفسك بكل المشاعر دون حكم","عبّر: بكاء، كتابة، حديث مع ثقة","حافظ على روتين أساسي (نوم، أكل) مهما قلّ","لا تتسرع في التخلص من أغراض المتوفى","أعطِ نفسك وقتًا — لا جدول للتعافي"],"common_mistakes":["تأجيل الحزن «حتى أقوى» (يعود أقوى)","القول «تقوّى» أو «مرّ وقت كافٍ»","إخفاء المشاعر أمام الأطفال (يحتاجون نموذجًا)","تجنّب ذكرى المتوفى (يؤجل الحزن)"],"when_to_seek_help":"لو بعد 6-12 شهرًا الحزن شديد بدون أي خفوت، أو يصاحبه يأس، أو تعطّل حياتك، أو أفكار عن الانضمام للمتوفى — اطلب مختصًا.","related_questions":["كيف أساعد طفلي على الحزن","متى يكون الحزن اكتئابًا","الحزن الطبيعي إمتى"],"risk_level":"high","language":"mixed","tags":["حزن","فقد","تعافي"]},{"id":"grief-helping-children","question":"كيف أساعد طفلي على الحزن؟","alternative_questions":["اتوفى جدّه ومش عارفة أقول إزاي","طفلي فقد حيوانه الأليف إزاي أعينه","كيف أشرح الموت لطفلي","ابني حزين بعد وفاة أبوه إيه أعمل"],"title":"مساعدة الطفل على الحزن","category":"الحزن بعد الفقد","subcategory":"الأطفال","keywords":["طفل حزين","موت","فقد طفل","تربية","حداد","شرح الموت","حزن طفل"],"short_answer":"اشرح الموت بصدق بسيطة مناسبة لعمره، اسمح بمشاعره، حافظ على روتين، وكن نموذجًا. لا تقل «سافر» أو «نام».","answer":"كيف تساعد طفلك على الحزن:\n\n• صراحة مناسبة للعمر — «مات: جسده توقف عن العمل، لا يعود». تجنّب «سافر» أو «نام» (يخيفه من السفر/النوم).\n• اسمح بمشاعره — بكاء، غضب، لعب (طريقة الطفل في المعالجة).\n• لا تخفِ حزنك — رؤيتك تحزن بصدق يعلمه أن الحزن طبيعي.\n• حافظ على روتين — الاستقرار يمنحه أمانًا.\n• شاركه — «ماذا تتذكر عنه؟» ارسموا، اكتبوا.\n• لا تستعجل — لكل طفل وتيرته.\n• اعتناء خاص — قد يرجع لتبويل ليلي، صعوبة نوم، عناد (مؤقت).\n• لا تجعله «رجل البيت» (عبء لا يحتمله).\n\nالأطفال يفهمون أكثر مما نظن. الصدق اللطيف أفضل من الكذب الذي يكتشف.","practical_steps":["اشرح الموت بصدق بسيطة مناسبة لعمره","اسمح بمشاعره — بكاء، غضب، لعب","حافظ على روتين نوم وأكل ومدرسة","لا تخفِ حزنك (نموذج صحي)","شاركه ذكريات: ارسموا، اكتبوا، تحدثوا"],"common_mistakes":["الكذب («سافر»، «نام») فيكتشف ويفقد الثقة","إخفاء الحزن عن الطفل (يعتقد أنه ممنوع)","جعله «رجل البيت» بعد فقد الأب (عبء)","استعجال تعافيه («تقوّى»)"],"when_to_seek_help":"لو ظهرت على الطفل علامات (تبول مستمر، انطواء، تراجع دراسي، كوابيس متكررة) لأشهر، فاطلب مختصًا في صحة الأطفال.","related_questions":["مراحل الحزن","متى يكون الحزن اكتئابًا","طفلي يتبول ليلاً"],"risk_level":"medium","language":"mixed","tags":["أطفال","حزن","فقد"]},{"id":"trauma-what-is","question":"ما هي الصدمة النفسية؟","alternative_questions":["يعني إيه صدمة نفسية","إزاي أعرف إني متصدم","أعراض الصدمة النفسية","هل كل خبر سيء صدمة"],"title":"الصدمة النفسية","category":"الصدمات النفسية","subcategory":"مفهوم","keywords":["صدمة","trauma","صدمة نفسية","اضطراب ما بعد الصدمة","PTSD","حدث مؤذي"],"short_answer":"الصدمة رد فعل نفسية على حدث مهدد (عنف، حادث، فقد). قد تسبب ذكريات اقتحامية، تجنّب، تيقّظ، وتبدّل في المزاج.","answer":"الصدمة النفسية استجابة لحدث مهدد للحياة أو السلامة (عنف، حادث، اعتداء، كارثة، فقد مفاجئ). ليس كل خبر سيء صدمة.\n\nأعراض اضطراب ما بعد الصدمة (PTSD) — إن استمرت شهرًا+:\n\n1) ذكريات اقتحامية — صور، كوابيس، فلاشباك.\n2) تجنّب — أماكن، أشخاص، أحاديث تذكر بالحدث.\n3) تيقّظ — سهولة استثارة، أرق، تركيز صعب، تجمّد.\n4) تبدّل مزاج — سلبية، عزلة، شعور بالذنب، فقد المتعة.\n\nليس كل من يعيش حدثًا يصاب بالصدمة. لكن إن استمرت الأعراض وأثّرت، فالعلاج المتخصص (EMDR، CBT للصدمات) فعّال جدًا.\n\nلا تتجاهلها — الصدمة لا تختفي وحدها، تتراكم وتظهر لاحقًا.","practical_steps":["اعترف بما حدث دون إنكار أو تضخيم","لا تعزل نفسك — تواصل مع داعمين","حافظ على روتين أساسي (نوم، أكل)","تجنّب الكحول والمهدئات للتعامل","اطلب مختصًا متخصصًا في الصدمات"],"common_mistakes":["تجنّب الحديث عن الحدث (يؤجل المعالجة)","تخدير الألم بالإدمان (يعود أقوى)","القول «تقوّى» أو «نَسَ» (لا يُنسى بل يُعالج)","تأجيل العلاج انتظارًا لاختفاء تلقائي"],"when_to_seek_help":"أي صدمة تستمر أعراضها أكثر من شهر، أو تعطّل حياتك، أو تشمل أفكار يأس، تستدعي علاجًا متخصصًا فورًا.","related_questions":["إيه علاج الصدمات","الخيانة صدمة إزاي أعالجها","كيف أساعد قريبًا بعد صدمة"],"risk_level":"high","language":"mixed","tags":["صدمة","PTSD","علاج"]},{"id":"trauma-treatment","question":"كيف تُعالج الصدمات النفسية؟","alternative_questions":["إيه علاج الصدمات","EMDR إيه","علاج نفسي للصدمة","كيف أتجاوز صدمة قديمة"],"title":"علاج الصدمات","category":"الصدمات النفسية","subcategory":"العلاج","keywords":["علاج صدمة","EMDR","CBT صدمات","علاج نفسي","تعافي صدمة","معالجة"],"short_answer":"أبرز علاجات الصدمة: CBT الموجه للصدمة، وEMDR (إزالة حساسية وإعادة معالجة). كلاهما فعّال ويعيد معالجة الذكرى المؤذية.","answer":"الصدمة تُعالج، وليس بالضرورة بالحديث الطويل عنها. علاجات مثبتة:\n\n1) CBT للصدمات (Trauma-Focused CBT) — إعادة بناء الأفكار، تعرّض متدرّج للذكريات بأمان.\n\n2) EMDR (إزالة حساسية وإعادة معالجة بحركة العين) — يعالج الذكرى المؤذية عبر تحريك العين أو النقر، يخفّف شحنتها العاطفية. فعّال جدًا ومدعوم بأبحاث.\n\n3) العلاج الزوجي/الأسري — لو أثرت الصدمة على العلاقات.\n\n4) أدوية — مضادات اكتئاب قد تساعد الأعراض (بإشراف طبيب نفسي).\n\nما لا يفيد:\n• تخدير بالكحول/المهدئات (يعود أقوى)\n• تجنّب كل ما يذكر بالحدث (يثبّت الصدمة)\n• الإجبار على الحديث قبل الاستعداد\n\nالصدمة القديمة قابلة للعلاج في أي عمر. لا «فوات أوان».","practical_steps":["اطلب مختصًا متخصصًا في الصدمات (ليس أي معالج)","اسأل عن طرقه (CBT صدمات، EMDR)","لا تتسرع — العلاج بوتيرتك","لا تخدّر الألم بالإدمان","كن صبورًا — التعافي موجات"],"common_mistakes":["تأجيل العلاج «سيختفي وحده» (لا يختفي)","اختيار معالج غير متخصص في الصدمات","الإجبار على سرد تفاصيل قبل الاستعداد","تخدير الألم بدل معالجته"],"when_to_seek_help":"أي صدمة (حديثة أو قديمة) تستمر أعراضها أو تعطّل حياتك تستدعي علاجًا متخصصًا. كل ما بُكر كان أسرع التعافي.","related_questions":["ما هي الصدمة النفسية","الخيانة صدمة إزاي أعالجها","كيف أساعد قريبًا بعد صدمة"],"risk_level":"high","language":"mixed","tags":["علاج","صدمة","EMDR"]},{"id":"forgiveness-what-is","question":"ما هو التسامح؟","alternative_questions":["يعني إيه أسامح","التسامح ضعف ولا قوة","إزاي أسامح اللي أذاني","العفو إيه فايدته"],"title":"التسامح","category":"التسامح","subcategory":"مفهوم","keywords":["تسامح","عفو","صفح","مسامحة","تسامح نفسي","تحرر","غفران"],"short_answer":"التسامح قرار تحرر قلبك من ثقل الغضب. ليس نسيانًا ولا تبريرًا ولا تصالحًا. للسامح لا للمُسامَح.","answer":"خرافات شائعة عن التسامح:\n• «يعني نسيان» — لا، التسامح مع الذكرى.\n• «يعني تبرير» — لا، يعترف بالأذى ويختار التحرر.\n• «يعني تصالح» — لا، يمكنك سامح من لا تراه.\n• «يعني ضعف» — لا، قوة لا يملكها إلا قوي.\n\nالتسامح قرار داخلي: تُطلق الحق القديم في الغضب، فتتحرر أنت. المُسامَح قد لا يعرف حتى.\n\nلماذا تسامح؟ لأن الغضب المتراكم يأكلك أنت لا من أساء. تشبّثك بالاستياء مثل شرب السم وتوقع موت عدوك.\n\nالتسامح عملية، ليس حدثًا. قد يستغرق وقتًا. ويمكنك سامح دون العودة لعلاقة مؤذية.","practical_steps":["اعترف بألمك دون تبرير الأذى","تخلَّ عن الحق في الانتقام (يحررك أنت)","تذكّر أن الإنسان يخطئ — ولربما أنت أخطأت يومًا","لا تشترط اعتذار المُسيء لتسامح","سامح في قلبك، ولا تعد لعلاقة مؤذية إن لزم"],"common_mistakes":["تأجيل التسامح «حتى أهدأ» (لا يأتي وحده)","اشتراط اعتذار المُسيء (قد لا يعتذر)","الخلط بين التسامح والعودة لعلاقة مؤذية","اعتبار التسامح ضعفًا"],"when_to_seek_help":"لو تجد صعوبة في التسامح رغم رغبتك، أو الأذى صدمة عميقة، فالعلاج النفسي يساعد على المعالجة والتسامح.","related_questions":["إزاي أنسى أذى قديم","التسامح في الإسلام","صدمة الخيانة إزاي أعالجها"],"risk_level":"low","language":"mixed","tags":["تسامح","عفو","تحرر"]},{"id":"emotional-intelligence-what-is","question":"ما هو الذكاء العاطفي؟","alternative_questions":["يعني إيه ذكاء عاطفي","إزاي أزيد ذكائي العاطفي","EQ إيه","أهمية الذكاء العاطفي"],"title":"الذكاء العاطفي","category":"الذكاء العاطفي","subcategory":"مفهوم","keywords":["ذكاء عاطفي","EQ","مشاعر","تعاطف","إدارة انفعال","ذكاء وجداني"],"short_answer":"الذكاء العاطفي قدرة على فهم مشاعرك وإدارتها، وفهم مشاعر الآخرين والتعاطف معهم. أربع مهارات قابلة للتطوير.","answer":"الذكاء العاطفي (EQ) أربع مهارات (سالوفي و ماير):\n\n1) الوعي الذاتي — معرفة ما تشعر به ولماذا.\n2) الإدارة الذاتية — تحكم في انفعالاتك لا كبتها.\n3) الوعي الاجتماعي — قراءة مشاعر الآخرين (تعاطف).\n4) إدارة العلاقات — تواصل، حل خلافات، قيادة.\n\nلماذا مهم؟ أبحاث تربطه بنجاح العلاقات والعمل أكثر من IQ. يمكنك أن تكون عبقريًا وعاجزًا اجتماعيًا.\n\nالعاطفة معلومة — تخبرك بحاجة أو خطر. الذكي عاطفيًا يقرأها ويتصرف بحكمة، لا يكبتها ولا ينفجر بها.\n\nخبر جيد: قابل للتطوير في أي عمر. ليست موهبة فطرية فقط.","practical_steps":["سمِّ مشاعرك بدقة («إحباط» لا «غضب»، «قلق» لا «توتر»)","قبل الرد الانفعالي، استرح دقيقة","اسأل الآخرين عن مشاعرهم واستمع","تدرّب على التعاطف: «ماذا أشعر لو مكانه؟»","راقب تأثير كلامك على الآخرين"],"common_mistakes":["اعتبار العاطفة ضعفًا (إنكارها)","الخلط بين الذكاء العاطفي واللين","الاعتقاد أنه فطري لا قابل للتطوير","كبت المشاعر بدل فهمها"],"when_to_seek_help":"لو تجد صعوبة مستمرة في فهم مشاعرك أو إدارتها أو قراءة الآخرين، فالعلاج النفسي يطوّر هذه المهارات.","related_questions":["التنظيم الانفعالي إزاي","إزاي أتعاطف مع الآخرين","إزاي أفهم مشاعري"],"risk_level":"low","language":"mixed","tags":["ذكاء عاطفي","EQ","مشاعر"]},{"id":"emotion-regulation-skills","question":"كيف أتحكم في مشاعري؟","alternative_questions":["إزاي أتحكم في مشاعري","مشاعري بتحكمني إيه الحل","التنظيم الانفعالي إزاي","بفقد سيطرة على انفعالاتي"],"title":"التنظيم الانفعالي","category":"التنظيم الانفعالي","subcategory":"مهارات","keywords":["تنظيم انفعالي","تحكم مشاعر","انفعال","إدارة عاطفة","تهدئة","DBT"],"short_answer":"التنظيم الانفعالي: سمِّ مشاعرك، اقبلها دون حكم، هدّئ جسدك، ثم اختر ردك. لا تكبت ولا تنفجر — افهم واختر.","answer":"التنظيم الانفعالي مهارة مكتسبة. نموذج بسيط (من DBT):\n\n1) سمِّ — «أشعر بالغضب» لا «أنا غاضب». التسمية تخفض شدّتها.\n2) اقبل — لا تكبت («لا تغضب») ولا تضخّم. اقبل أنها هنا الآن.\n3) هدّئ الجسد — تنفس بطيء، ماء بارد، مشي.\n4) افهم — ما السبب؟ ما الحاجة وراءها؟\n5) اختر الرد — ما التصرف المناسب؟ ليس كل شعور يستحق ردًا.\n\nالخرافة: «تحكم في مشاعرك» = كبتها. الحقيقة: تشعر بها، تفهمها، ثم تختار ردك.\n\nلا يمكنك منع شعور، لكنك تملك رد فعلك. هذه المساحة بين المثير والاستجابة هي حريتك.\n\nمع التدريب اليومي، تصبح هذه المساحة أكبر وتحكمك أعمق.","practical_steps":["سمِّ مشاعرك بدقة («إحباط» لا «غضب»)","تنفّس ببطء 6 أنفاس في الدقيقة لتهدئة الجسد","اسأل: ما الحاجة وراء هذا الشعور؟","قبل الرد، استرح دقيقة واختر","سجّل مشاعرك يوميًا لاكتشاف أنماطك"],"common_mistakes":["كبت المشاعر (تنفجر لاحقًا)","التفريغ الانفعالي على الآخرين","الحكم على المشاعر («لا تغضب»)","الرد فورًا دون مساحة اختيار"],"when_to_seek_help":"لو تجد صعوبة مزمنة في التحكم بانفعالاتك، أو تؤذي علاقاتك، فالعلاج (خصوصًا DBT) فعّال جدًا.","related_questions":["إدارة الغضب إزاي","الذكاء العاطفي إيه","إزاي أهدى جسمي وقت القلق"],"risk_level":"medium","language":"mixed","tags":["تنظيم انفعالي","مشاعر","تحكم"]},{"id":"islamic-depression-not-weak-faith","question":"هل الاكتئاب دليل ضعف الإيمان؟","alternative_questions":["الاكتئاب ضعف إيمان","حاسس إني إيماني ضعيف لما بكتئب","هل المسلم يصاب بالاكتئاب","علاقة الدين بالصحة النفسية"],"title":"الاكتئاب وضعف الإيمان","category":"الصحة النفسية الإسلامية","subcategory":"تصحيح مفاهيم","keywords":["اكتئاب","إيمان","ضعف إيمان","إسلام","صحة نفسية","ابتلاء","خرافات"],"short_answer":"لا. الاكتئاب مرض له أسباب بيولوجية ونفسية، يصيب المؤمن والصالح. الأنبياء والأولياء حزنوا وابتلوا. لا تربط مرضًا بضعف إيمان.","answer":"ربط الاكتئاب بضعف الإيمان خرافة تضر المرضى وتؤخر العلاج. الحقائق:\n\n• الاكتئاب مرض له أساس بيولوجي (كيمياء الدماغ) ونفسي واجتماعي. يصيب المتدين وغير المتدين.\n• الأنبياء ابتلوا: يعقوب عليه السلام حزن حتى ابيضّت عيناه من الحزن. قال: «إنما أشكو بثي وحزني إلى الله». هذا حزن عميق، لم يكن ضعف إيمان.\n• الابتلاء بالمرض يرفع الدرجات ويكفّر الذنوب لمن صبر.\n• الأخذ بالعلاج من التوكل لا منافٍ له. النبي ﷺ قال: «تداووا».\n• المسألة العظمى: قد يكون الاكتئاب ابتلاء، والعلاج طريق الخلاص الذي قدّره الله.\n\nخطورة الربط بضعف الإيمان: يزيد ذنب المريض، يؤخر علاجه، قد يدفعه لليأس من رحمة الله. الصحيح: مرض يحتاج علاجًا، مع توبة وتزكية وتوكل.","practical_steps":["فرّق بين مرض النفس وضعف الإيمان","اطلب العلاج النفسي كأي مرض جسدي","داوم على الأذكار والدعاء مع العلاج","لا تستمع لمن يربط مرضك بضعف دينك","تذكّر أن الابتلاء يرفع الدرجات لمن صبر"],"common_mistakes":["ربط كل حزن بضعف الإيمان","تأجيل العلاج انتظارًا للشفاء بالإيمان وحده","الشعور بالذنب الديني بسبب المرض","الاستماع لمن يتهم المريض بقلة الدين"],"when_to_seek_help":"الجمع بين العلاج النفسي والرعاية الروحية قوة. اطلب مختصًا نفسيًا ولا تنقطع عن عباداتك بما تطيق.","related_questions":["كيف عالج الإسلام القلق","أدعية للهم والحزن","هل المسألة ابتلاء أم مرض"],"risk_level":"medium","language":"ar","tags":["إسلامية","اكتئاب","إيمان"]},{"id":"islamic-anxiety-treatment","question":"كيف عالج الإسلام القلق والهم؟","alternative_questions":["إزاي الدين يعالج القلق","أدعية للقلق والهم","الصبر يساعد على القلق إزاي","علاج الهم في السنة النبوية"],"title":"الصبر والقلق في المنظور الإسلامي","category":"الصحة النفسية الإسلامية","subcategory":"القلق والهم","keywords":["صبر","قلق","هم","غم","إيمان","دعاء","سنة","تزكية النفس","اليقين","التوكل"],"short_answer":"الإسلام يجمع التوكل على الله والأخذ بالأسباب، فيوازن بين السكينة القلبية والعلاج النفسي — لا تعارض بينهما.","answer":"الإسلام يعالج القلق بمنهج متكامل: تزكية القلب باليقين والتوكل، والأخذ بالأسباب بما فيه العلاج.\n\nالصبر ليس استسلامًا، بل ثبات مع العمل. والرضا ليس تعطيلًا، بل طمأنينة بعد الجهد.\n\nالأذكار والدعاء أدوات لتهدئة القلب، والصحابة كانوا يأخذون بالطب ولا يتنازلون عن التوكل. الإيمان يعطي معنى للابتلاء فيخفّ وقعه، والعلاج النفسي يطوّر المهارات. الاثنان يتكاملان.\n\nمهم: الاكتئاب والقلق الشديد أمراض تحتاج مختصًا، والإيمان لا يلغي الحاجة للعلاج — كما لا يلغي الصلاة الحاجة للدواء الجسدي. ربط المرض النفسي بضعف الإيمان خطأ يضر المريض.","practical_steps":["داوم على الأذكار الصباحية والمسائية فهي حصن قلبي","صلِ ركعتين حاجة عند القلق واستفرغ همك في السجود","اقرأ سورة الواقعة أو آخر آل عمران قبل النوم للطمأنينة","تأمل معنى الابتلاء: تكفير ذنوب ورفعة درجات","اجمع بين الدعاء وطلب العلاج النفسي المتخصص"],"common_mistakes":["اعتقاد أن ضعف الإيمان سبب وحيد للقلق — يزيد ضغطًا على المريض","ترك العلاج النفسي والاكتفاء بالدعاء فقط","الشعور بالذنب الديني بسبب المرض النفسي","ربط كل ابتلاء بذنب معين بدون دليل"],"when_to_seek_help":"اطلب مساعدة مختص لو الأعراض مستمرة وتعيق عبادتك وعملك وعلاقاتك، أو لو ظهرت أفكار يأس شديد. الجمع بين العلاج النفسي والرعاية الروحية قوة لا تناقض.","related_questions":["هل الاكتئاب ضعف إيمان","أدعية تهدئة القلق","إزاي أجمع بين التوكل والعلاج"],"risk_level":"low","language":"ar","tags":["إسلامية","صبر","قلق"]},{"id":"islamic-sabr-meaning","question":"ما الفرق بين الصبر والاستسلام في الإسلام؟","alternative_questions":["الصبر مش يعنى استسلام","إزاي أصبر من غير ما أستسلم","فرق الصبر والرضا","الصبر في الإسلام معناه إيه"],"title":"الصبر والاستسلام","category":"الصحة النفسية الإسلامية","subcategory":"مفاهيم","keywords":["صبر","استسلام","رضا","تسليم","عجز","سلبية","إسلام","تزكية"],"short_answer":"الصبر ثبات مع العمل والأخذ بالأسباب لا تركها. الاستسلام عجز وسلبية. الصابر يفعل ويثبت، المستسلم يتخلى.","answer":"خلط شائع يضر: اعتبار الصبر استسلامًا. الفرق جوهري:\n\nالصبر:\n• ثبات على الحق والعمل\n• أخذ بالأسباب مع التوكل\n• تحمّل المشقة في الطريق الصحيح\n• لا يعني الرضا بالظلم\n• يعقبه فرج\n\nالاستسلام (المذموم):\n• عجز وترك عمل\n• «هكذا قدر الله» دون سعي\n• قبول الظلم صمتًا\n• ركون إلى المعصية\n\nمن أمثلة الصبر: يعقوب عليه السلام حزن ولم ييأس، قال «فصبر جميل» ودعا وبحث عن يوسف. لم يجلس ينتظر.\n\nالرضا مرحلة بعد الصبر: طمأنينة بفضل الله بعد الجهد، لا قبله.\n\nالصبر فعل لا ترك. من خلط بينهما خذل نفسه ودينه.","practical_steps":["بعد البلاء: اسأل «ما الذي أقدر فعله؟» وافعله","لا تقل «قدر الله» لتبرير ترك الأسباب","الصبر على الطاعة، عن المعصية، وعلى البلاء","ادعُ الله واعمل — الاثنان معًا","تأمل سير الصابرين من الأنبياء"],"common_mistakes":["تبرير العجز بـ«الصبر»","ترك الأخذ بالأسباب باسم التوكل","القبول بالظلم باسم الصبر","خلط الرضا (بعد الجهد) بالاستسلام (قبله)"],"when_to_seek_help":"لو البلاء يحتاج علاجًا نفسيًا (صدمة، اكتئاب)، فطلبه من التوكل لا منافٍ له.","related_questions":["كيف عالج الإسلام القلق","التوكل والأخذ بالأسباب","هل الاكتئاب ضعف إيمان"],"risk_level":"low","language":"ar","tags":["صبر","استسلام","إسلامية"]},{"id":"islamic-tawakkul-and-effort","question":"كيف أجمع بين التوكل والأخذ بالأسباب؟","alternative_questions":["التوكل يعنى أترك الأسباب","إزاي أتوكل وأاخد بالأسباب","فرق التوكل والاكتفاء بالدعاء","هل السعي ينافي التوكل"],"title":"التوكل والأخذ بالأسباب","category":"الصحة النفسية الإسلامية","subcategory":"مفاهيم","keywords":["توكل","أسباب","سعي","يقين","تواكل","إسلام","اعتماد على الله"],"short_answer":"التوكل أخذ بالأسباب مع اعتماد القلب على الله، لا ترك الأسباب. تركها «تواكل» لا توكل. النبي ﷺ تأمّر وهاجر وتداوى.","answer":"حقيقة التوكل يسيء فهمها كثيرون. التوكل درجة عليا من الإيمان، يقوم على:\n\n1) الأخذ بالأسباب كاملةً (سعي، عمل، علاج، تدبير).\n2) اعتماد القلب على الله وحده في النتيجة.\n3) الرضا بما قدّره الله بعد الجهد.\n\nأما ترك الأسباب فهو «تواكل» مذموم، يظنه صاحبه توكلًا.\n\nالأدلة:\n• النبي ﷺ تأمّر في القتال، وهاجر، ولبس الدرع، وتداوى، وقال: «تداووا عباد الله».\n• الأعرابي ترك ناقته بلا عقل، قال له النبي ﷺ: «اعقلها وتوكل».\n• يعقوب عليه السلام أمر بنيه بدخول مصر من أبواب متفرقة (أخذ سبب) مع التوكل.\n\nفي الصحة النفسية: الدعاء والأذكار مع العلاج النفسي والأدوية إن لزم — هذا التوكل الحقيقي. الدعاء وحده بلا علاج قد يكون تواكلًا.","practical_steps":["بعد الدعاء، اسأل: «ما الأسباب التي قدّرها الله؟» وخذ بها","تداوى ولا تقل «الله سيشفي» بلا سبب","اعمل بجهد كامل، واترك النتيجة لله","اربط قلبك بالله في كل خطوة، لا في النتيجة فقط","اقبل ما قدّره الله بعد الجهد دون اعتراض"],"common_mistakes":["ترك الأسباب باسم التوكل (تواكل)","الاعتماد على الأسباب وحدها ونسيان الله","حصر التوكل في الدعاء دون العمل","الاعتراض على النتيجة بعد الجهد"],"when_to_seek_help":"في الأمور النفسية، الجمع بين العلاج المتخصص والدعاء قوة. لا تستبدل أحدهما بالآخر.","related_questions":["الصبر والاستسلام","كيف عالج الإسلام القلق","هل الاكتئاب ضعف إيمان"],"risk_level":"low","language":"ar","tags":["توكل","أسباب","إسلامية"]},{"id":"islamic-dua-for-sadness","question":"ما الأدعية المأثورة لتفريج الهم والحزن؟","alternative_questions":["أدعية للهم والحزن","دعاء تفريج الكرب","أذكار للحزن والقلق","ماذا كان يقول النبي عند الحزن"],"title":"أدعية تفريج الهم","category":"الصحة النفسية الإسلامية","subcategory":"أدعية وأذكار","keywords":["أدعية","هم","حزن","كرب","تفريج","أذكار","سنة","دعاء"],"short_answer":"من الأدعية المأثورة: دعاء ذي النون في بطن الحوت، ودعاء تفريج الهم. مع الأذكار الصباحية والمسائية حصن قلبي.","answer":"من الأدعية المأثورة الصحيحة لتفريج الهم والحزن:\n\n1) دعاء ذي النون (نبي الله يونس عليه السلام) — قال النبي ﷺ: «ما قالها مسلم في دعوة قط إلا استجيب له»:\n«لا إله إلا أنت سبحانك إني كنت من الظالمين».\n\n2) ما كان يقوله النبي ﷺ عند الكرب:\n«لا إله إلا الله العظيم الحليم، لا إله إلا الله رب العرش العظيم، لا إله إلا الله رب السماوات ورب الأرض ورب العرش الكريم».\n\n3) دعاء تفريج الهم والحزن:\n«اللهم إني عبدك، ابن عبدك، ابن أمتك، ناصيتي بيدك، ماضٍ فيّ حكمك، عدل فيّ قضاؤك، أسألك بكل اسم هو لك سمّيت به نفسك، أو أنزلته في كتابك، أو علّمته أحدًا من خلقك، أو استأثرت به في علم الغيب عندك، أن تجعل القرآن ربيع قلبي، ونور صدري، وجلاء حزني، وذهاب همي».\n\n4) الأذكار الصباحية والمسائية — حصن متين.\n5) «حسبنا الله ونعم الوكيل».\n\nتذكّر: الدعاء مع الأخذ بالأسباب (العلاج النفسي إن لزم) هو المنهج النبوي الكامل.","practical_steps":["داوم على أذكار الصباح والمساء بقلب حاضر","الجأ إلى الله بالدعاء المأثور عند الكرب","صلِ ركعتين واستفرغ همك في السجود","اجمع بين الدعاء وطلب العلاج النفسي","كثر من «لا حول ولا قوة إلا بالله»"],"common_mistakes":["ترك الأسباب والاكتفاء بالدعاء","الدعاء بلا حضور قلب","استخدام أدعية غير صحيحة أو ابتداعية","اليأس إن لم يستجب فورًا"],"when_to_seek_help":"الهم والحزن المستمر قد يكون مرضًا (اكتئاب) يحتاج علاجًا. اجمع بين الدعاء وطلب المختص — هذا التوكل.","related_questions":["كيف عالج الإسلام القلق","الصبر والاستسلام","هل الاكتئاب ضعف إيمان"],"risk_level":"low","language":"ar","tags":["أدعية","أذكار","هم"]},{"id":"islamic-gratitude-contentment","question":"كيف يبني الإسلام الرضا والقناعة؟","alternative_questions":["إزاي أرضى بما قسمه الله","القناعة في الإسلام إزاي","ليه دايماً مش راضي","الشكر يعمل إيه في النفس"],"title":"الرضا والقناعة","category":"الصحة النفسية الإسلامية","subcategory":"تزكية","keywords":["رضا","قناعة","شكر","زهد","تزكية","قسمة","إسلام","طمأنينة"],"short_answer":"الرضا ثمرة الشكر واليقين بأن ما قسمه الله خير. يُبنى بالنظر لمن دونك، شكر النعم، وعدم تعليق السعادة على ما ليس عندك.","answer":"الرضا ليس قبولًا سلبيًا، بل طمأنينة قلبية بما قدّر الله بعد الجهد. كيف يُبنى:\n\n1) الشكر — تأمل نعم الله عليك يوميًا (بصر، أهل، أمن، طعام). الشكر يولّد الرضا.\n\n2) النظر لمن دونك — قال النبي ﷺ: «انظروا إلى من هو أسفل منكم ولا تنظروا إلى من هو فوقكم، فهو أجدر أن لا تزدروا نعمة الله».\n\n3) اليقين بحكمة الله — ما اختاره الله لك خير مما تختار لنفسك وإن خفي السبب.\n\n4) عدم تعليق السعادة — «سأسعد إذا...» سجن. السعادة في القناعة لا في تحصيل.\n\n5) العمل ثم التسليم — اعمل بجهد، ثم ارضَ بالنتيجة.\n\nالرضا لا يعني ترك الطموح. بل العمل بجد ثم القبول. القناعة كنز لا يفنى، كما قال النبي ﷺ: «قد أفلح من أسلم، ورُزق كفافًا، وقنّعه الله بما آتاه».","practical_steps":["اكتب 3 نعم شكرًا لله يوميًا","انظر لمن هو أقل منك في النعم","اعمل بجهد ثم سلّم النتيجة لله","لا تربط سعادتك بما ليس عندك","كثر من «الحمد لله» بقلب حاضر"],"common_mistakes":["ربط الرضا بترك الطموح (ليس كذلك)","النظر لمن فوقك في النعم باستمرار","تأجيل الشكر «حتى يتحسن وضعي»","الشكوى المستمرة من القسمة"],"when_to_seek_help":"لو عدم الرضا يسبب حزنًا مستمرًا أو قلقًا شديدًا، فاطلب مختصًا — قد يكون قلقًا أو اكتئابًا يحتاج علاجًا مع التزكية.","related_questions":["الصبر والاستلام","كيف عالج الإسلام القلق","أدعية تفريج الهم"],"risk_level":"low","language":"ar","tags":["رضا","قناعة","شكر"]}];
